using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Utils;
using TowerDefense.Core;

namespace TowerDefense.Enemy
{
    [RequireComponent(typeof(EnemyMovement), typeof(EnemyHealth))]
    public class Enemy : MonoBehaviour
    {
        [Header("Settings")]
        [SerializeField] private EnemyData _enemyData;

        [Header("Health Bar")]
        [SerializeField] private Slider _healthSlider;
        [SerializeField] private Image _healthFillImage;
        [SerializeField] private Color _lowHealthColor = Color.red;
        [SerializeField] private Color _mediumHealthColor = Color.yellow;
        [SerializeField] private Color _highHealthColor = Color.green;
        [SerializeField] private float _healthBarOffsetY = 1.5f;

        private EnemyMovement _movement;
        private EnemyHealth _health;
        private Canvas _healthCanvas;

        public EnemyData Data => _enemyData;
        public EnemyMovement Movement => _movement;
        public EnemyHealth Health => _health;
        public bool IsDead => _health != null && _health.CurrentHealth <= 0;

        private int _birthWaveId = -1;  // 敌人归属的波次ID

        // 给 EnemySpawner 调用的
        public void SetBirthWaveId(int waveId)
        {
            _birthWaveId = waveId;
        }

        private void Awake()
        {
            _movement = GetComponent<EnemyMovement>();
            _health = GetComponent<EnemyHealth>();

            // 获取血条画布
            if (_healthSlider != null)
            {
                _healthCanvas = _healthSlider.GetComponentInParent<Canvas>();
                _healthSlider.value = 1f;
            }

            if (_enemyData != null)
            {
                Initialize(_enemyData);
            }
        }

        public void Initialize(EnemyData data)
        {
            _enemyData = data;

            if (_health != null)
            {
                _health.Initialize(data.stats.maxHealth, data.stats.goldReward);
                _health.OnHealthChanged += UpdateHealthBar;
                _health.OnDeath += OnDeath;
            }

            if (_movement != null)
            {
                _movement.SetSpeed(data.stats.moveSpeed);
            }

            // 初始化血条
            UpdateHealthBar(data.stats.maxHealth, data.stats.maxHealth);
        }

        public void StartMovement(PathCreator pathCreator)
        {
            if (_movement != null)
            {
                _movement.FollowPath(pathCreator);
            }
        }

        public void OnReachedEnd()
        {
            // 敌人走到终点也统计为波次敌人不再场
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            if (GameManager.Instance != null)
            {
                GameManager.Instance.TakeDamage(_enemyData.stats.lifeDamage);
            }
            EventBus.Publish(new EnemyReachEndEvent { Enemy = gameObject, Damage = _enemyData.stats.lifeDamage });
            Destroy(gameObject);
        }

        public void OnDeath()
        {
            // 波次统计-带上GameObject给HashSet去重
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            // 解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }

            // 隐藏血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = false;
            }

            if (GameManager.Instance != null)
            {
                GameManager.Instance.AddGold(_enemyData.stats.goldReward);
                GameManager.Instance.AddKill();
            }
            EventBus.Publish(new EnemyDeathEvent { Enemy = gameObject, Reward = _enemyData.stats.goldReward });
            Destroy(gameObject);
        }

        private void Update()
        {
            // 更新血条位置，始终在敌人头顶
            UpdateHealthBarPosition();
        }

        private void UpdateHealthBar(int currentHealth, int maxHealth)
        {
            if (_healthSlider == null) return;

            float healthPercent = (float)currentHealth / maxHealth;
            _healthSlider.value = healthPercent;

            // 根据血量改变颜色
            UpdateHealthBarColor(healthPercent);

            // 当血量低于最大值时显示血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = healthPercent < 1f;
            }
        }

        private void UpdateHealthBarColor(float healthPercent)
        {
            if (_healthFillImage == null) return;

            if (healthPercent <= 0.3f)
            {
                _healthFillImage.color = _lowHealthColor;
            }
            else if (healthPercent <= 0.6f)
            {
                _healthFillImage.color = _mediumHealthColor;
            }
            else
            {
                _healthFillImage.color = _highHealthColor;
            }
        }

        private void UpdateHealthBarPosition()
        {
            if (_healthSlider == null || _healthCanvas == null) return;

            // 将世界坐标转换为屏幕坐标
            Vector3 worldPosition = transform.position;
            worldPosition.y += _healthBarOffsetY;

            // 如果是世界空间画布，直接设置位置
            if (_healthCanvas.renderMode == RenderMode.WorldSpace)
            {
                _healthSlider.transform.position = worldPosition;
            }
            else
            {
                // 如果是屏幕空间画布，转换坐标
                Vector3 screenPosition = Camera.main.WorldToScreenPoint(worldPosition);
                _healthSlider.transform.position = screenPosition;
            }
        }

        private void OnDestroy()
        {
            // 确保解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }
        }

        public void TakeDamage(int damage)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage);
            }
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage, damageType);
            }
        }

        public void ApplySlow(float slowFactor, float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(slowFactor, duration);
            }
        }

        public void ApplyStun(float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(0f, duration);
            }
        }
    }
}

using UnityEngine;
using TowerDefense.Utils;

namespace TowerDefense.Enemy
{
    public class EnemyMovement : MonoBehaviour
    {
        [Header("Movement Settings")]
        [SerializeField] private float _speed = 2f;
        [SerializeField] private float _rotationSpeed = 5f;

        [Header("Rotation Settings")]
        [Tooltip("旋转模式：None=不旋转, FlipX=只左右翻转, Full=全方向旋转")]
        [SerializeField] private RotationMode _rotationMode = RotationMode.Full;

        public enum RotationMode
        {
            None,       
            FlipX,      
            Full        
        }

        private PathCreator _currentPath;
        private int _currentWaypointIndex;
        private Vector3[] _waypoints;
        private bool _isMoving = false;
        private float _currentSpeed = 0f;

        public bool IsMoving => _isMoving;
        public float CurrentSpeed => _currentSpeed;

        private void Update()
        {
            if (_isMoving && _waypoints != null && _waypoints.Length > 0)
            {
                MoveTowardsWaypoint();
            }
        }

        public void FollowPath(PathCreator pathCreator)
        {
            _currentPath = pathCreator;
            _waypoints = pathCreator.Waypoints.ToArray();
            _currentWaypointIndex = 0;
            _isMoving = true;

            if (_waypoints.Length > 0)
            {
                transform.position = _waypoints[0];
            }
        }

        /// <summary>
        /// Resume movement from current position without resetting to path start.
        /// Used when soldiers release blocked enemies.
        /// </summary>
        public void ResumeMovement()
        {
            if (_waypoints != null && _waypoints.Length > 0)
            {
                _isMoving = true;
            }
        }

        private void MoveTowardsWaypoint()
        {
            if (_currentWaypointIndex >= _waypoints.Length)
            {
                _isMoving = false;
                _currentSpeed = 0f;
                SendMessage("OnReachedEnd", SendMessageOptions.DontRequireReceiver);
                return;
            }

            Vector3 target = _waypoints[_currentWaypointIndex];
            target.z = transform.position.z;

            Vector3 direction = (target - transform.position).normalized;
            _currentSpeed = _speed;
            float step = _speed * Time.deltaTime;
            Vector3 newPosition = Vector3.MoveTowards(transform.position, target, step);
            transform.position = newPosition;

            // 根据旋转模式处理朝向
            if (direction.magnitude > 0.01f)
            {
                switch (_rotationMode)
                {
                    case RotationMode.Full:
                        float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg;
                        Quaternion targetRotation = Quaternion.AngleAxis(angle, Vector3.forward);
                        transform.rotation = Quaternion.Lerp(transform.rotation, targetRotation, _rotationSpeed * Time.deltaTime);
                        break;

                    case RotationMode.FlipX:
                        Vector3 localScale = transform.localScale;
                        if (direction.x > 0.01f)
                        {
                            localScale.x = Mathf.Abs(localScale.x);  
                        }
                        else if (direction.x < -0.01f)
                        {
                            localScale.x = -Mathf.Abs(localScale.x); 
                        }
                        transform.localScale = localScale;
                        break;

                    case RotationMode.None:
                    default:
                        break;
                }
            }

            // 检查是否到达当前路径点
            if (Vector3.Distance(transform.position, target) < 0.15f)
            {
                _currentWaypointIndex++;
            }
        }

        public void SetSpeed(float speed)
        {
            _speed = speed;
        }

        public float GetSpeed()
        {
            return _speed;
        }

        public void StopMovement()
        {
            _isMoving = false;
            _currentSpeed = 0f;
        }

        public float GetProgressPercent()
        {
            if (_waypoints == null || _waypoints.Length < 2) return 0f;

            float totalDistance = 0f;
            for (int i = 0; i < _waypoints.Length - 1; i++)
            {
                totalDistance += Vector3.Distance(_waypoints[i], _waypoints[i + 1]);
            }

            float currentDistance = 0f;
            for (int i = 0; i < _currentWaypointIndex; i++)
            {
                currentDistance += Vector3.Distance(_waypoints[i], _waypoints[i + 1]);
            }

            if (_currentWaypointIndex < _waypoints.Length - 1)
            {
                currentDistance += Vector3.Distance(transform.position, _waypoints[_currentWaypointIndex]);
            }

            return Mathf.Clamp01(currentDistance / totalDistance);
        }

        public void Slow(float slowFactor, float duration)
        {
            StartCoroutine(SlowCoroutine(slowFactor, duration));
        }

        private System.Collections.IEnumerator SlowCoroutine(float slowFactor, float duration)
        {
            float originalSpeed = _speed;
            _speed *= slowFactor;

            yield return new WaitForSeconds(duration);

            _speed = originalSpeed;
        }

        private void OnDrawGizmos()
        {
            if (_waypoints != null)
            {
                for (int i = _currentWaypointIndex; i < _waypoints.Length - 1; i++)
                {
                    Gizmos.color = Color.red;
                    Gizmos.DrawLine(_waypoints[i], _waypoints[i + 1]);
                }
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace TowerDefense.Enemy
{
    public class EnemyHealth : MonoBehaviour
    {
        [Header("Health Settings")]
        [SerializeField] private int _maxHealth = 100;
        [SerializeField] private int _goldReward = 10;

        [Header("UI Settings")]
        [SerializeField] private GameObject _healthBarPrefab;
        [SerializeField] private Vector3 _healthBarOffset = new Vector3(0, 1, 0);

        private int _currentHealth;
        private Slider _healthBarSlider;
        private Transform _healthBarTransform;

        public int CurrentHealth => _currentHealth;
        public int MaxHealth => _maxHealth;
        public float HealthPercentage => (float)_currentHealth / _maxHealth;

        public System.Action<int, int> OnHealthChanged;
        public System.Action OnDeath;

        private void Awake()
        {
            _currentHealth = _maxHealth;

            if (_healthBarPrefab != null)
            {
                CreateHealthBar();
            }
        }

        public void Initialize(int maxHealth, int goldReward)
        {
            _maxHealth = maxHealth;
            _currentHealth = maxHealth;
            _goldReward = goldReward;

            if (_healthBarSlider != null)
            {
                _healthBarSlider.maxValue = _maxHealth;
                _healthBarSlider.value = _currentHealth;
            }
        }

        private void CreateHealthBar()
        {
            Canvas canvas = FindObjectOfType<Canvas>();
            if (canvas == null) return;

            GameObject healthBarObj = Instantiate(_healthBarPrefab);
            healthBarObj.transform.SetParent(canvas.transform, false);

            _healthBarTransform = healthBarObj.transform;
            _healthBarSlider = healthBarObj.GetComponentInChildren<Slider>();

            if (_healthBarSlider != null)
            {
                _healthBarSlider.maxValue = _maxHealth;
                _healthBarSlider.value = _currentHealth;
            }
        }

        public void TakeDamage(int damage)
        {
            TakeDamage(damage, DamageType.Physical);
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            _currentHealth -= damage;
            _currentHealth = Mathf.Max(0, _currentHealth);

            // 触发血量变化事件
            OnHealthChanged?.Invoke(_currentHealth, _maxHealth);

            UpdateHealthBar();

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        private void UpdateHealthBar()
        {
            if (_healthBarTransform != null && _healthBarSlider != null)
            {
                _healthBarSlider.value = _currentHealth;

                Vector3 worldPos = Camera.main.WorldToScreenPoint(transform.position + _healthBarOffset);
                _healthBarTransform.position = worldPos;
            }
        }

        private void Die()
        {
            Destroy(_healthBarTransform?.gameObject);
            // 触发死亡事件
            OnDeath?.Invoke();
            SendMessage("OnDeath", SendMessageOptions.DontRequireReceiver);
        }

        private void OnDestroy()
        {
            Destroy(_healthBarTransform?.gameObject);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Enemy;
using TowerDefense.Core;

namespace TowerDefense.Wave
{
    public class WaveManager : MonoBehaviour
    {
        public static WaveManager Instance { get; private set; }

        [Header("Settings")]
        [SerializeField] private EnemySpawner _enemySpawner;
        [SerializeField] private float _waveDelay = 5f;
        [SerializeField] private int _totalWaves = 5;
        [SerializeField] private int _baseEnemyCount = 5;
        [SerializeField] private int _enemyIncreasePerWave = 2;

        [Header("Wave Data (Optional)")]
        [Tooltip("如果设置了这个数组，将使用这里的配置而不是动态生成")]
        [SerializeField] private WaveData[] _waveDatas;

        [Header("Enemy Data")]
        [Tooltip("所有可用的敌人数据（飞机、骷髅等）")]
        [SerializeField] private EnemyData[] _enemyDatas;

        private EnemyData _defaultEnemyData;

        [Header("UI")]
        [SerializeField] private Text _waveText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Text _waveAnnounceText;
        [SerializeField] private float _announceDuration = 2f;

        private int _currentWaveIndex = 0;
        private float _waveTimer = 0f;
        private bool _isWaveActive = false;
        private bool _isWaveTransition = false;

        public int CurrentWave => _currentWaveIndex;
        public int TotalWaves => _totalWaves;
        public bool IsWaveActive => _isWaveActive;

        private void Awake()
        {
            if (Instance == null)
            {
                Instance = this;
            }
            else
            {
                Destroy(gameObject);
            }
        }

        private void Start()
        {
            LoadEnemyData();
            UpdateWaveUI();

            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }

            EventBus.Subscribe<GameStartEvent>(OnGameStart);
        }

        private void LoadEnemyData()
        {
            // 如果在 Inspector 中设置了敌人数据数组，直接使用
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                Debug.Log($"已加载 {_enemyDatas.Length} 个敌人数据");
                foreach (var enemy in _enemyDatas)
                {
                    Debug.Log($"  - {enemy.enemyName}");
                }
                // 使用第一个作为默认
                _defaultEnemyData = _enemyDatas[0];
                return;
            }

            // 否则尝试从 Resources 加载
            _defaultEnemyData = Resources.Load<EnemyData>("Data/EnemyData");
            if (_defaultEnemyData == null)
            {
                Debug.LogError("Failed to load EnemyData from Resources/Data/EnemyData");
            }
        }

        private void OnDestroy()
        {
            EventBus.Unsubscribe<GameStartEvent>(OnGameStart);
        }

        private void OnGameStart(GameStartEvent e)
        {
            ForceStartWave();
        }

        private void Update()
        {
            if (_isWaveTransition && !_isWaveActive)
            {
                _waveTimer += Time.deltaTime;

                float remainingTime = _waveDelay - _waveTimer;

                if (remainingTime > 0)
                {
                    UpdateWaveCountdown((int)Mathf.CeilToInt(remainingTime));
                }

                if (remainingTime % 1f < 0.05f)
                {
                    Debug.Log($"倒计时更新: timer={_waveTimer:F1}/{_waveDelay}, 剩余={remainingTime:F1}s, transition={_isWaveTransition}, active={_isWaveActive}");
                }

                if (_waveTimer >= _waveDelay)
                {
                    Debug.Log($"✅ 倒计时结束, 准备开始下一波!");
                    _waveTimer = 0f;
                    HideWaveCountdown();
                    StartNextWave();
                }
            }

            UpdateEnemyCountDisplay();
        }

        private void UpdateWaveCountdown(int seconds)
        {
            if (_waveAnnounceText != null)
            {
                int nextWave = _currentWaveIndex + 1;
                _waveAnnounceText.text = $"第 {nextWave} 波 {seconds} 秒后出现！";
                _waveAnnounceText.gameObject.SetActive(true);
            }
        }

        private void HideWaveCountdown()
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private void UpdateEnemyCountDisplay()
        {
            if (_enemyCountText != null)
            {
                // 用 EnemySpawner 追踪的波次剩余敌人（出生总数 - 死亡数）
                _enemyCountText.text = $"剩余敌人:{TowerDefense.Enemy.EnemySpawner.RemainingEnemies}";
            }
        }

        public void StartNextWave()
        {
            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log("All waves completed!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
                return;
            }

            // 先增加波次索引
            _currentWaveIndex++;

            WaveData waveData = GetWaveData();
            if (waveData == null)
            {
                Debug.LogError("Failed to get wave data!");
                return;
            }

            _enemySpawner.StartWave(waveData);

            _isWaveActive = true;
            _isWaveTransition = false;

            if (GameManager.Instance != null)
            {
                GameManager.Instance.SetCurrentWave(_currentWaveIndex);
            }

            EventBus.Publish(new WaveStartEvent { WaveIndex = _currentWaveIndex });

            UpdateWaveUI();
            StartCoroutine(ShowWaveAnnouncement(_currentWaveIndex));
            Debug.Log($"Starting wave {_currentWaveIndex}");
        }

        private IEnumerator ShowWaveAnnouncement(int waveNumber)
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.text = $"第 {waveNumber} 波开始出怪！";
                _waveAnnounceText.gameObject.SetActive(true);

                Debug.Log($"📢 {_waveAnnounceText.text}");

                yield return new WaitForSeconds(_announceDuration);

                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private WaveData GetWaveData()
        {
            // 如果用户设置了 WaveData 数组，使用它
            if (_waveDatas != null && _waveDatas.Length > 0)
            {
                int index = _currentWaveIndex - 1;
                if (index >= 0 && index < _waveDatas.Length)
                {
                    Debug.Log($"使用配置的 WaveData: 波次 {_currentWaveIndex}");
                    return _waveDatas[index];
                }
            }

            // 否则动态生成
            if (_defaultEnemyData == null && (_enemyDatas == null || _enemyDatas.Length == 0))
            {
                Debug.LogError("No EnemyData available! Cannot create wave data.");
                return null;
            }

            Debug.Log($"动态生成 WaveData: 波次 {_currentWaveIndex}");
            return CreateWaveData();
        }

        private WaveData CreateWaveData()
        {
            WaveData waveData = ScriptableObject.CreateInstance<WaveData>();
            waveData.waveNumber = _currentWaveIndex;
            waveData.spawnInterval = Mathf.Max(0.5f, 1.5f - (_currentWaveIndex - 1) * 0.1f);
            waveData.enemies = new List<WaveData.WaveEnemy>();

            int totalEnemies = _baseEnemyCount + (_currentWaveIndex - 1) * _enemyIncreasePerWave;

            // 使用多个敌人数据
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                // 随机选择敌人
                for (int i = 0; i < _enemyDatas.Length; i++)
                {
                    int enemyCount = totalEnemies / _enemyDatas.Length;
                    if (i == 0)
                    {
                        enemyCount += totalEnemies % _enemyDatas.Length;
                    }

                    if (enemyCount > 0)
                    {
                        waveData.enemies.Add(new WaveData.WaveEnemy
                        {
                            enemyData = _enemyDatas[i],
                            count = enemyCount,
                            spawnDelay = 0,
                            spawnPoint = "MainPath"
                        });

                        Debug.Log($"波次 {_currentWaveIndex} 添加 {enemyCount} 个 {_enemyDatas[i].enemyName}");
                    }
                }
            }
            else
            {
                // 只有一个敌人数据时使用旧方法
                waveData.enemies.Add(new WaveData.WaveEnemy
                {
                    enemyData = _defaultEnemyData,
                    count = totalEnemies,
                    spawnDelay = 0,
                    spawnPoint = "MainPath"
                });
            }

            return waveData;
        }

        public void OnWaveComplete()
        {
            _isWaveActive = false;

            Debug.Log($"波次 {_currentWaveIndex}/{_totalWaves} 完成!");
            EventBus.Publish(new WaveEndEvent { WaveIndex = _currentWaveIndex });

            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log($"全部波次完成!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
            }
            else
            {
                _isWaveTransition = true;
                _waveTimer = 0f;
            }

            UpdateWaveUI();
        }

        public void StartWaveManually(int waveIndex)
        {
            if (waveIndex >= 0 && waveIndex < _totalWaves)
            {
                _currentWaveIndex = waveIndex;
                StartNextWave();
            }
        }

        public void SkipToNextWave()
        {
            if (!_isWaveActive && _currentWaveIndex < _totalWaves)
            {
                StartNextWave();
            }
        }

        public void ForceStartWave()
        {
            if (!_isWaveActive)
            {
                _isWaveTransition = false;
                _waveTimer = 0f;
                StartNextWave();
            }
        }

        private void UpdateWaveUI()
        {
            if (_waveText != null)
            {
                _waveText.text = $"波次:{_currentWaveIndex}/{_totalWaves}";
            }

            UpdateEnemyCountDisplay();
        }

        public void Reset()
        {
            _currentWaveIndex = 0;
            _waveTimer = 0f;
            _isWaveActive = false;
            _isWaveTransition = false;
            UpdateWaveUI();
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Hero
{
    public enum HeroState
    {
        Idle,
        Moving,
        Attacking,
        UsingSkill,
        Dead
    }

    public class Hero : MonoBehaviour
    {
        [Header("Data")]
        [SerializeField] private HeroData _heroData;

        [Header("Components")]
        [SerializeField] private Animator _animator;
        [SerializeField] private SpriteRenderer _spriteRenderer;
        [SerializeField] private Transform _healthBarAnchor;

        [Header("Movement")]
        [SerializeField] private float _moveSpeed = 3f;
        [SerializeField] private float _arrivalThreshold = 0.2f;

        private HeroState _currentState = HeroState.Idle;
        private HeroData.HeroStats _currentStats;
        private float _currentHealth;
        private int _currentLevel = 1;
        private float _currentExp = 0f;
        private float _expToNextLevel = 100f;

        private Enemy.Enemy _currentTarget;
        private Vector3 _targetPosition;
        private bool _isMoving = false;
        private float _attackCooldown = 0f;

        private Dictionary<string, float> _skillCooldowns = new Dictionary<string, float>();

        public HeroData Data => _heroData;
        public HeroState State => _currentState;
        public int CurrentLevel => _currentLevel;
        public float CurrentHealth => _currentHealth;
        public float HealthPercent => _currentHealth / _currentStats.maxHealth;
        public float CurrentExp => _currentExp;
        public float ExpPercent => _currentExp / _expToNextLevel;
        public bool IsDead => _currentState == HeroState.Dead;

        public System.Action<Hero> OnLevelUp;
        public System.Action<Hero> OnDeath;
        public System.Action<float> OnHealthChanged;
        public System.Action<float> OnExpChanged;
        public System.Action<string> OnSkillUsed;
        public System.Action<string> OnSkillReady;

        private void Awake()
        {
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
            if (_spriteRenderer == null) _spriteRenderer = GetComponentInChildren<SpriteRenderer>();
        }

        public void Initialize(HeroData data)
        {
            _heroData = data;
            _currentStats = data.baseStats;
            _currentHealth = _currentStats.maxHealth;
            _currentLevel = 1;
            _currentExp = 0f;
            _currentState = HeroState.Idle;

            foreach (var skill in _heroData.skills)
            {
                _skillCooldowns[skill.skillName] = 0f;
            }
        }

        private void Update()
        {
            if (_currentState == HeroState.Dead) return;

            UpdateCooldowns();
            UpdateMovement();
            UpdateAttack();
            UpdateHealthRegen();
        }

        private void UpdateCooldowns()
        {
            List<string> skills = new List<string>(_skillCooldowns.Keys);
            foreach (var skillName in skills)
            {
                if (_skillCooldowns[skillName] > 0)
                {
                    _skillCooldowns[skillName] -= Time.deltaTime;
                    if (_skillCooldowns[skillName] <= 0)
                    {
                        _skillCooldowns[skillName] = 0;
                        OnSkillReady?.Invoke(skillName);
                    }
                }
            }
        }

        private void UpdateMovement()
        {
            if (!_isMoving) return;

            Vector3 direction = (_targetPosition - transform.position).normalized;
            transform.position += direction * _moveSpeed * Time.deltaTime;

            if (_spriteRenderer != null)
            {
                _spriteRenderer.flipX = direction.x < 0;
            }

            float distance = Vector3.Distance(transform.position, _targetPosition);
            if (distance <= _arrivalThreshold)
            {
                _isMoving = false;
                _currentState = HeroState.Idle;

                if (_animator != null)
                {
                    _animator.SetBool("IsMoving", false);
                }
            }
        }

        private void UpdateAttack()
        {
            if (_currentState != HeroState.Idle) return;

            if (_currentTarget == null || _currentTarget.IsDead)
            {
                FindTarget();
            }

            if (_currentTarget != null && _attackCooldown <= 0)
            {
                Attack();
            }

            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        private void UpdateHealthRegen()
        {
            if (_currentStats.healthRegen > 0 && _currentHealth < _currentStats.maxHealth)
            {
                _currentHealth += _currentStats.healthRegen * Time.deltaTime;
                if (_currentHealth > _currentStats.maxHealth)
                {
                    _currentHealth = _currentStats.maxHealth;
                }
                OnHealthChanged?.Invoke(_currentHealth);
            }
        }

        public void MoveTo(Vector3 position)
        {
            _targetPosition = position;
            _isMoving = true;
            _currentState = HeroState.Moving;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", true);
            }
        }

        public void StopMoving()
        {
            _isMoving = false;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", false);
            }
        }

        private void FindTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            _currentTarget = spawner.GetClosestEnemy(transform.position, _currentStats.attackRange);
        }

        private void Attack()
        {
            if (_currentTarget == null) return;

            _currentState = HeroState.Attacking;
            _attackCooldown = 1f / _currentStats.attackSpeed;

            if (_animator != null)
            {
                _animator.SetTrigger("Attack");
            }

           // 在第211行和第257行添加转换
            _currentTarget.TakeDamage(Mathf.RoundToInt(_currentStats.attackDamage), DamageType.Physical);

            _currentState = HeroState.Idle;
        }

        public bool UseSkill(int skillIndex)
        {
            if (skillIndex < 0 || skillIndex >= _heroData.skills.Length) return false;

            HeroData.HeroSkill skill = _heroData.skills[skillIndex];

            if (_skillCooldowns[skill.skillName] > 0) return false;

            _skillCooldowns[skill.skillName] = skill.cooldown;
            _currentState = HeroState.UsingSkill;

            if (_animator != null)
            {
                _animator.SetTrigger("Skill");
            }

            ExecuteSkill(skill);

            OnSkillUsed?.Invoke(skill.skillName);
            EventBus.Publish(new SkillUsedEvent { SkillName = skill.skillName });

            _currentState = HeroState.Idle;
            return true;
        }

        private void ExecuteSkill(HeroData.HeroSkill skill)
        {
            if (skill.effectPrefab != null)
            {
                Instantiate(skill.effectPrefab, transform.position, Quaternion.identity);
            }

            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, skill.effectRadius);

            foreach (var enemy in enemiesInRange)
            {
                if (enemy != null && !enemy.IsDead)
                {
                    // 在第211行和第257行添加转换
enemy.TakeDamage(Mathf.RoundToInt(skill.effectValue), DamageType.Magic);
                }
            }
        }

        public void TakeDamage(float damage)
        {
            if (_currentState == HeroState.Dead) return;

            float actualDamage = damage * (1f - _currentStats.armor / 100f);
            _currentHealth -= actualDamage;

            OnHealthChanged?.Invoke(_currentHealth);

            if (_animator != null)
            {
                _animator.SetTrigger("Hit");
            }

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        public void Heal(float amount)
        {
            _currentHealth += amount;
            if (_currentHealth > _currentStats.maxHealth)
            {
                _currentHealth = _currentStats.maxHealth;
            }
            OnHealthChanged?.Invoke(_currentHealth);
        }

        public void AddExp(float exp)
        {
            _currentExp += exp;
            OnExpChanged?.Invoke(_currentExp);

            while (_currentExp >= _expToNextLevel)
            {
                LevelUp();
            }
        }

        private void LevelUp()
        {
            _currentExp -= _expToNextLevel;
            _currentLevel++;
            _expToNextLevel *= 1.5f;

            _currentStats.maxHealth *= 1.1f;
            _currentStats.attackDamage *= 1.1f;
            _currentHealth = _currentStats.maxHealth;

            OnLevelUp?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetTrigger("LevelUp");
            }
        }

        private void Die()
        {
            _currentState = HeroState.Dead;
            OnDeath?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetBool("IsDead", true);
            }
        }

        public void Revive()
        {
            _currentHealth = _currentStats.maxHealth;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsDead", false);
            }
        }

        public float GetSkillCooldown(string skillName)
        {
            return _skillCooldowns.TryGetValue(skillName, out float cd) ? cd : 0f;
        }

        public float GetSkillCooldownPercent(string skillName)
        {
            foreach (var skill in _heroData.skills)
            {
                if (skill.skillName == skillName)
                {
                    return GetSkillCooldown(skillName) / skill.cooldown;
                }
            }
            return 0f;
        }
    }
}

using UnityEngine;
using UnityEngine.EventSystems;
using TowerDefense.Data;

namespace TowerDefense.Hero
{
    public class HeroController : MonoBehaviour
    {
        [Header("Hero")]
        [SerializeField] private Hero _hero;
        [SerializeField] private HeroData _heroData;

        [Header("Movement Settings")]
        [SerializeField] private bool _useClickMovement = true;
        [SerializeField] private LayerMask _groundLayer;

        [Header("Skill Keys")]
        [SerializeField] private KeyCode _skill1Key = KeyCode.Q;
        [SerializeField] private KeyCode _skill2Key = KeyCode.W;
        [SerializeField] private KeyCode _skill3Key = KeyCode.E;

        private Camera _mainCamera;

        private void Awake()
        {
            _mainCamera = Camera.main;

            if (_hero == null)
            {
                _hero = GetComponent<Hero>();
            }
        }

        private void Start()
        {
            if (_hero != null && _heroData != null)
            {
                _hero.Initialize(_heroData);
            }
        }

        private void Update()
        {
            if (_hero == null || _hero.IsDead) return;

            HandleMovement();
            HandleSkills();
        }

        private void HandleMovement()
        {
            if (!_useClickMovement) return;

            if (Input.GetMouseButtonDown(1) && !EventSystem.current.IsPointerOverGameObject())
            {
                Ray ray = _mainCamera.ScreenPointToRay(Input.mousePosition);
                RaycastHit2D hit = Physics2D.Raycast(ray.origin, ray.direction, Mathf.Infinity, _groundLayer);

                if (hit.collider != null)
                {
                    _hero.MoveTo(hit.point);
                }
                else
                {
                    Vector3 worldPosition = _mainCamera.ScreenToWorldPoint(Input.mousePosition);
                    worldPosition.z = 0;
                    _hero.MoveTo(worldPosition);
                }
            }
        }

        private void HandleSkills()
        {
            if (_heroData == null || _heroData.skills == null) return;

            if (Input.GetKeyDown(_skill1Key) && _heroData.skills.Length > 0)
            {
                _hero.UseSkill(0);
            }
            else if (Input.GetKeyDown(_skill2Key) && _heroData.skills.Length > 1)
            {
                _hero.UseSkill(1);
            }
            else if (Input.GetKeyDown(_skill3Key) && _heroData.skills.Length > 2)
            {
                _hero.UseSkill(2);
            }
        }

        public void UseSkillByIndex(int index)
        {
            if (_hero != null)
            {
                _hero.UseSkill(index);
            }
        }

        public void SetHeroData(HeroData data)
        {
            _heroData = data;
            if (_hero != null)
            {
                _hero.Initialize(_heroData);
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Enemy;

namespace TowerDefense.Skill
{
    public enum SkillTargetType
    {
        Self,
        Enemy,
        Area,
        Direction
    }

    public abstract class SkillBase : ScriptableObject
    {
        [Header("Skill Info")]
        public string skillName;
        public string description;
        public Sprite icon;
        public int maxLevel = 5;

        [Header("Cooldown & Cost")]
        public float cooldown = 10f;
        public int manaCost = 0;
        public int goldCost = 0;

        [Header("Targeting")]
        public SkillTargetType targetType = SkillTargetType.Area;
        public float range = 5f;
        public float radius = 2f;

        [Header("Effects")]
        public GameObject effectPrefab;
        public AudioClip soundEffect;

        protected int _currentLevel = 1;

        public int CurrentLevel => _currentLevel;

        public virtual bool CanUse(GameObject user)
        {
            if (goldCost > 0 && !GameManager.Instance.HasEnoughGold(goldCost))
            {
                return false;
            }
            return true;
        }

        public virtual void Use(GameObject user, Vector3 targetPosition)
        {
            if (!CanUse(user)) return;

            if (goldCost > 0)
            {
                GameManager.Instance.SpendGold(goldCost);
            }

            Execute(user, targetPosition);
            PlayEffects(targetPosition);

            EventBus.Publish(new SkillUsedEvent { SkillName = skillName });
        }

        protected abstract void Execute(GameObject user, Vector3 targetPosition);

        protected virtual void PlayEffects(Vector3 position)
        {
            if (effectPrefab != null)
            {
                Instantiate(effectPrefab, position, Quaternion.identity);
            }

            if (soundEffect != null)
            {
                AudioSource.PlayClipAtPoint(soundEffect, position);
            }
        }

        public virtual void Upgrade()
        {
            if (_currentLevel < maxLevel)
            {
                _currentLevel++;
            }
        }

        protected List<Enemy.Enemy> GetEnemiesInRadius(Vector3 center, float radius)
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return new List<Enemy.Enemy>();

            return spawner.GetEnemiesInRange(center, radius);
        }
    }
}

