using UnityEngine;
using System.Collections;
using UnityEngine.UI;
using TowerDefense.Enemy;

/// <summary>
/// Controls the Lightning skill in 2D: shows range circle on activation,
/// follows mouse, releases lightning on click with screen flash and camera shake.
/// All positions and effects operate on the XY plane (Z=0).
/// </summary>
public class LightningSkillController : MonoBehaviour
{
    [Header("Skill Settings")]
    [SerializeField] private float _skillRange = 5f;
    [SerializeField] private int _damage = 50;
    [SerializeField] private int _boltCount = 6;
    [SerializeField] private float _boltInterval = 0.06f;
    [SerializeField] private float _boltHeight = 18f;
    [SerializeField] private float _cooldown = 30f;

    [Header("References")]
    [SerializeField] private GameObject _rangeIndicator;
    [SerializeField] private ParticleSystem _lightningImpactPrefab;
    [SerializeField] private GameObject _lightningBoltPrefab;
    [SerializeField] private Button _skillButton;
    [SerializeField] private Camera _mainCamera;

    [Header("Audio")]
    [SerializeField] private AudioClip _thunderClip;
    [SerializeField] private AudioSource _audioSource;

    [Header("Screen Flash")]
    [SerializeField] private float _flashDuration = 0.15f;
    [SerializeField] private Color _flashColor = new Color(0.4f, 0.6f, 1f, 0.6f);

    [Header("Cooldown Display")]
    [SerializeField] private Text _cooldownText;

    [Header("Camera Shake")]
    [SerializeField] private float _shakeIntensity = 0.4f;
    [SerializeField] private float _shakeDuration = 0.3f;

    [Header("Ground Ring")]
    [SerializeField] private float _ringExpandSpeed = 15f;
    [SerializeField] private float _ringMaxRadius = 8f;
    [SerializeField] private float _ringDuration = 0.8f;

    private bool _skillActive;
    private bool _onCooldown;
    private Vector3 _targetPos;
    private LineRenderer _rangeLR;

    private Vector3 _camOriginalPos;
    private float _shakeTimer;

    private Image _flashImage;
    private float _flashTimer;

    private void Start()
    {
        if (_mainCamera == null) _mainCamera = Camera.main;
        if (_rangeIndicator == null)
        {
            var ri = GameObject.Find("RangeIndicator");
            if (ri == null)
            {
                foreach (var t in Resources.FindObjectsOfTypeAll<Transform>())
                {
                    if (t.name == "RangeIndicator") { ri = t.gameObject; break; }
                }
            }
            if (ri != null) _rangeIndicator = ri;
        }
        if (_rangeIndicator != null)
        {
            _rangeIndicator.SetActive(false);
            _rangeLR = _rangeIndicator.GetComponent<LineRenderer>();
            if (_rangeLR != null) _rangeLR.useWorldSpace = false;
        }
        if (_skillButton == null)
        {
            var btnObj = GameObject.Find("SkillButton_Lightning");
            if (btnObj != null) _skillButton = btnObj.GetComponent<Button>();
        }
        if (_skillButton != null) _skillButton.onClick.AddListener(OnSkillButtonClicked);

        CreateFlashOverlay();
    }

    private void CreateFlashOverlay()
    {
        var canvas = FindObjectOfType<Canvas>();
        if (canvas == null) return;

        var flashObj = new GameObject("ScreenFlash");
        flashObj.transform.SetParent(canvas.transform, false);
        var flashRect = flashObj.AddComponent<RectTransform>();
        flashRect.anchorMin = Vector2.zero;
        flashRect.anchorMax = Vector2.one;
        flashRect.offsetMin = Vector2.zero;
        flashRect.offsetMax = Vector2.zero;

        _flashImage = flashObj.AddComponent<Image>();
        _flashImage.color = new Color(_flashColor.r, _flashColor.g, _flashColor.b, 0f);
        _flashImage.raycastTarget = false;
    }

    private void Update()
    {
        if (_skillActive)
        {
            UpdateRangeIndicator();

            if (Input.GetMouseButtonDown(0))
            {
                ReleaseSkill();
            }
            if (Input.GetMouseButtonDown(1))
            {
                CancelSkill();
            }
        }

        // 2D camera shake (XY only)
        if (_shakeTimer > 0f)
        {
            _shakeTimer -= Time.deltaTime;
            float intensity = _shakeIntensity * (_shakeTimer / _shakeDuration);
            Vector2 offset = Random.insideUnitCircle * intensity;
            _mainCamera.transform.position = _camOriginalPos + new Vector3(offset.x, offset.y, 0f);
        }

        // Screen flash
        if (_flashTimer > 0f)
        {
            _flashTimer -= Time.deltaTime;
            float alpha = (_flashTimer / _flashDuration) * _flashColor.a;
            _flashImage.color = new Color(_flashColor.r, _flashColor.g, _flashColor.b, alpha);
        }
    }

    private void OnSkillButtonClicked()
    {
        if (_onCooldown) return;
        _skillActive = true;
        if (_rangeIndicator != null) _rangeIndicator.SetActive(true);
    }

    private void UpdateRangeIndicator()
    {
        // 2D: convert mouse to world point on Z=0 plane
        // z must be distance from camera to XY plane, otherwise returns camera position
        Vector3 mouseScreen = Input.mousePosition;
        mouseScreen.z = Mathf.Abs(_mainCamera.transform.position.z);
        Vector3 mouseWorld = _mainCamera.ScreenToWorldPoint(mouseScreen);
        mouseWorld.z = 0f;
        _targetPos = mouseWorld;

        if (_rangeIndicator != null)
        {
            _rangeIndicator.transform.position = _targetPos;
        }

        // Pulse range indicator
        if (_rangeLR != null)
        {
            float pulse = 0.6f + 0.4f * Mathf.PingPong(Time.time * 3f, 1f);
            _rangeLR.startColor = new Color(0.3f, 0.6f, 1f, pulse);
            _rangeLR.endColor = new Color(0.3f, 0.6f, 1f, pulse);
        }
    }

    private void ReleaseSkill()
    {
        _skillActive = false;
        if (_rangeIndicator != null) _rangeIndicator.SetActive(false);

        _flashTimer = _flashDuration;
        _camOriginalPos = _mainCamera.transform.position;
        _shakeTimer = _shakeDuration;

        DealDamageToEnemies();
        StartCoroutine(SpawnLightningBolts());
        StartCoroutine(SpawnGroundRing());
        StartCoroutine(CooldownRoutine());
    }

    private void DealDamageToEnemies()
    {
        var hits = Physics2D.OverlapCircleAll(_targetPos, _skillRange);
        foreach (var hit in hits)
        {
            var enemy = hit.GetComponent<Enemy>();
            if (enemy != null && !enemy.IsDead)
            {
                enemy.TakeDamage(_damage);
            }
        }
    }

    private void CancelSkill()
    {
        _skillActive = false;
        if (_rangeIndicator != null) _rangeIndicator.SetActive(false);
    }

    private IEnumerator SpawnLightningBolts()
    {
        // Impact particle at target
        if (_lightningImpactPrefab != null)
        {
            var impact = Instantiate(_lightningImpactPrefab, _targetPos, Quaternion.identity);
            impact.Play(true);
            Destroy(impact.gameObject, impact.main.duration + 1.5f);
        }

        if (_thunderClip != null && _audioSource != null)
        {
            _audioSource.PlayOneShot(_thunderClip);
        }

        // Main bolt: origin is above the target on Y axis
        if (_lightningBoltPrefab != null)
        {
            Vector3 mainOrigin = new Vector3(_targetPos.x, _targetPos.y + _boltHeight, 0f);
            var boltObj = Instantiate(_lightningBoltPrefab);
            var bolt = boltObj.GetComponent<LightningBolt>();
            if (bolt != null) bolt.Fire(mainOrigin, _targetPos);
            else Destroy(boltObj);
        }

        yield return new WaitForSeconds(_boltInterval);

        // Surrounding bolts
        for (int i = 0; i < _boltCount - 1; i++)
        {
            // Random offset in 2D circle around target
            Vector2 offset2D = Random.insideUnitCircle * _skillRange * 0.7f;
            Vector3 boltTarget = new Vector3(_targetPos.x + offset2D.x, _targetPos.y + offset2D.y, 0f);
            Vector3 boltOrigin = new Vector3(boltTarget.x + Random.Range(-1f, 1f), boltTarget.y + _boltHeight + Random.Range(-3f, 3f), 0f);

            if (_lightningBoltPrefab != null)
            {
                var boltObj = Instantiate(_lightningBoltPrefab);
                var bolt = boltObj.GetComponent<LightningBolt>();
                if (bolt != null) bolt.Fire(boltOrigin, boltTarget);
                else Destroy(boltObj);
            }

            yield return new WaitForSeconds(_boltInterval);
        }
    }

    private IEnumerator SpawnGroundRing()
    {
        var ringObj = new GameObject("GroundRing");
        ringObj.transform.position = _targetPos;
        var lr = ringObj.AddComponent<LineRenderer>();
        var mat = new Material(Shader.Find("Mobile/Particles/Additive"));
        if (mat != null) lr.material = mat;
        lr.useWorldSpace = true;
        lr.startWidth = 0.3f;
        lr.endWidth = 0.1f;
        lr.loop = true;
        lr.sortingOrder = 1;

        int ringSegments = 48;
        lr.positionCount = ringSegments + 1;
        float elapsed = 0f;

        while (elapsed < _ringDuration)
        {
            elapsed += Time.deltaTime;
            float t = elapsed / _ringDuration;
            float radius = Mathf.Lerp(0.5f, _ringMaxRadius, t);
            float alpha = 1f - t;

            lr.startColor = new Color(0.4f, 0.7f, 1f, alpha * 0.8f);
            lr.endColor = new Color(0.3f, 0.5f, 1f, alpha * 0.2f);

            // 2D circle on XY plane
            for (int i = 0; i <= ringSegments; i++)
            {
                float angle = (float)i / ringSegments * Mathf.PI * 2f;
                float x = Mathf.Cos(angle) * radius;
                float y = Mathf.Sin(angle) * radius;
                lr.SetPosition(i, new Vector3(_targetPos.x + x, _targetPos.y + y, 0f));
            }

            yield return null;
        }

        Destroy(ringObj);
    }

    private IEnumerator CooldownRoutine()
    {
        _onCooldown = true;
        float remaining = _cooldown;
        while (remaining > 0f)
        {
            remaining -= Time.deltaTime;
            if (_cooldownText != null)
                _cooldownText.text = Mathf.CeilToInt(remaining).ToString() + "s";
            yield return null;
        }
        if (_cooldownText != null)
            _cooldownText.text = "";
        _onCooldown = false;
    }
}

using UnityEngine;
using System.Collections;
using System.Collections.Generic;

/// <summary>
/// Procedural 2D lightning bolt with branching forks using LineRenderers.
/// All positions on XY plane (Z=0). Branches spread horizontally.
/// </summary>
public class LightningBolt : MonoBehaviour
{
    [Header("Main Bolt")]
    [SerializeField] private int _segments = 12;
    [SerializeField] private float _jitter = 1.5f;
    [SerializeField] private float _duration = 0.45f;
    [SerializeField] private float _width = 0.5f;

    [Header("Branches")]
    [SerializeField] private int _branchCount = 3;
    [SerializeField] private int _branchSegments = 5;
    [SerializeField] private float _branchJitter = 0.8f;
    [SerializeField] private float _branchWidth = 0.2f;
    [SerializeField] private float _branchLength = 0.35f;

    [Header("Colors")]
    [SerializeField] private Color _coreColor = new Color(0.85f, 0.92f, 1f, 1f);
    [SerializeField] private Color _glowColor = new Color(0.4f, 0.6f, 1f, 0.6f);
    [SerializeField] private Color _tipColor = new Color(0.3f, 0.5f, 1f, 0.1f);

    private LineRenderer _mainLR;
    private List<LineRenderer> _branchLRs = new List<LineRenderer>();
    private float _timer;
    private Vector3 _origin;
    private Vector3 _target;

    public void Fire(Vector3 from, Vector3 to)
    {
        _origin = from;
        _target = to;

        // Main bolt
        _mainLR = CreateLineRenderer("MainBolt", _width, _width * 0.25f, _coreColor, _tipColor);
        GeneratePath2D(_mainLR, from, to, _segments, _jitter);

        // Branches
        for (int i = 0; i < _branchCount; i++)
        {
            float t = Random.Range(0.2f, 0.7f);
            Vector3 branchRoot = Vector3.Lerp(from, to, t);
            // Perpendicular in 2D: rotate direction 90 degrees
            Vector2 dir2D = (to - from);
            Vector2 perp2D = new Vector2(-dir2D.y, dir2D.x).normalized;
            branchRoot += (Vector3)(perp2D * Random.Range(-_jitter, _jitter) * 0.5f);

            // Branch end: spread sideways and slightly toward target direction
            Vector3 branchEnd = branchRoot + (Vector3)(perp2D * Random.Range(-1f, 1f) + new Vector2(dir2D.x * 0.2f, dir2D.y * 0.1f).normalized) * Vector3.Distance(from, to) * _branchLength;

            var branchLR = CreateLineRenderer("Branch_" + i, _branchWidth, _branchWidth * 0.2f, _glowColor, _tipColor);
            GeneratePath2D(branchLR, branchRoot, branchEnd, _branchSegments, _branchJitter);
            _branchLRs.Add(branchLR);
        }

        _timer = _duration;
        StartCoroutine(AnimateBolt());
    }

    private LineRenderer CreateLineRenderer(string name, float startWidth, float endWidth, Color startColor, Color endColor)
    {
        var obj = new GameObject(name);
        obj.transform.SetParent(transform);
        var lr = obj.AddComponent<LineRenderer>();
        var mat = new Material(Shader.Find("Mobile/Particles/Additive"));
        if (mat == null) mat = new Material(Shader.Find("Unlit/Color"));
        lr.material = mat;
        lr.startWidth = startWidth;
        lr.endWidth = endWidth;
        lr.startColor = startColor;
        lr.endColor = endColor;
        lr.useWorldSpace = true;
        lr.sortingOrder = 10; // Render on top of sprites
        lr.positionCount = 0;
        return lr;
    }

    private void GeneratePath2D(LineRenderer lr, Vector3 from, Vector3 to, int segments, float jitter)
    {
        lr.positionCount = segments + 1;
        // 2D perpendicular: swap (dx,dy) -> (-dy, dx)
        Vector2 dir = to - from;
        Vector2 perp = new Vector2(-dir.y, dir.x).normalized;
        if (perp == Vector2.zero) perp = Vector2.right;

        lr.SetPosition(0, from);
        for (int i = 1; i < segments; i++)
        {
            float t = (float)i / segments;
            Vector3 pos = Vector3.Lerp(from, to, t);
            pos += (Vector3)(perp * Random.Range(-jitter, jitter));
            pos.z = 0f; // Stay on Z=0
            lr.SetPosition(i, pos);
        }
        lr.SetPosition(segments, to);
    }

    private IEnumerator AnimateBolt()
    {
        while (_timer > 0f)
        {
            _timer -= Time.deltaTime;
            float alpha = Mathf.Clamp01(_timer / _duration);

            // Main bolt flicker
            _mainLR.startColor = new Color(_coreColor.r, _coreColor.g, _coreColor.b, alpha);
            _mainLR.endColor = new Color(_tipColor.r, _tipColor.g, _tipColor.b, alpha * 0.3f);

            // Re-jitter for flicker effect
            GeneratePath2D(_mainLR, _origin, _target, _segments, _jitter * alpha);

            // Branches fade faster
            foreach (var branch in _branchLRs)
            {
                branch.startColor = new Color(_glowColor.r, _glowColor.g, _glowColor.b, alpha * 0.6f);
                branch.endColor = new Color(_tipColor.r, _tipColor.g, _tipColor.b, alpha * 0.1f);
            }

            yield return null;
        }
        Destroy(gameObject);
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Hero
{
    public enum HeroState
    {
        Idle,
        Moving,
        Attacking,
        UsingSkill,
        Dead
    }

    public class Hero : MonoBehaviour
    {
        [Header("Data")]
        [SerializeField] private HeroData _heroData;

        [Header("Components")]
        [SerializeField] private Animator _animator;
        [SerializeField] private SpriteRenderer _spriteRenderer;
        [SerializeField] private Transform _healthBarAnchor;

        [Header("Movement")]
        [SerializeField] private float _moveSpeed = 3f;
        [SerializeField] private float _arrivalThreshold = 0.2f;

        private HeroState _currentState = HeroState.Idle;
        private HeroData.HeroStats _currentStats;
        private float _currentHealth;
        private int _currentLevel = 1;
        private float _currentExp = 0f;
        private float _expToNextLevel = 100f;

        private Enemy.Enemy _currentTarget;
        private Vector3 _targetPosition;
        private bool _isMoving = false;
        private float _attackCooldown = 0f;

        private Dictionary<string, float> _skillCooldowns = new Dictionary<string, float>();

        public HeroData Data => _heroData;
        public HeroState State => _currentState;
        public int CurrentLevel => _currentLevel;
        public float CurrentHealth => _currentHealth;
        public float HealthPercent => _currentHealth / _currentStats.maxHealth;
        public float CurrentExp => _currentExp;
        public float ExpPercent => _currentExp / _expToNextLevel;
        public bool IsDead => _currentState == HeroState.Dead;

        public System.Action<Hero> OnLevelUp;
        public System.Action<Hero> OnDeath;
        public System.Action<float> OnHealthChanged;
        public System.Action<float> OnExpChanged;
        public System.Action<string> OnSkillUsed;
        public System.Action<string> OnSkillReady;

        private void Awake()
        {
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
            if (_spriteRenderer == null) _spriteRenderer = GetComponentInChildren<SpriteRenderer>();
        }

        public void Initialize(HeroData data)
        {
            _heroData = data;
            _currentStats = data.baseStats;
            _currentHealth = _currentStats.maxHealth;
            _currentLevel = 1;
            _currentExp = 0f;
            _currentState = HeroState.Idle;

            foreach (var skill in _heroData.skills)
            {
                _skillCooldowns[skill.skillName] = 0f;
            }
        }

        private void Update()
        {
            if (_currentState == HeroState.Dead) return;

            UpdateCooldowns();
            UpdateMovement();
            UpdateAttack();
            UpdateHealthRegen();
        }

        private void UpdateCooldowns()
        {
            List<string> skills = new List<string>(_skillCooldowns.Keys);
            foreach (var skillName in skills)
            {
                if (_skillCooldowns[skillName] > 0)
                {
                    _skillCooldowns[skillName] -= Time.deltaTime;
                    if (_skillCooldowns[skillName] <= 0)
                    {
                        _skillCooldowns[skillName] = 0;
                        OnSkillReady?.Invoke(skillName);
                    }
                }
            }
        }

        private void UpdateMovement()
        {
            if (!_isMoving) return;

            Vector3 direction = (_targetPosition - transform.position).normalized;
            transform.position += direction * _moveSpeed * Time.deltaTime;

            if (_spriteRenderer != null)
            {
                _spriteRenderer.flipX = direction.x < 0;
            }

            float distance = Vector3.Distance(transform.position, _targetPosition);
            if (distance <= _arrivalThreshold)
            {
                _isMoving = false;
                _currentState = HeroState.Idle;

                if (_animator != null)
                {
                    _animator.SetBool("IsMoving", false);
                }
            }
        }

        private void UpdateAttack()
        {
            if (_currentState != HeroState.Idle) return;

            if (_currentTarget == null || _currentTarget.IsDead)
            {
                FindTarget();
            }

            if (_currentTarget != null && _attackCooldown <= 0)
            {
                Attack();
            }

            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        private void UpdateHealthRegen()
        {
            if (_currentStats.healthRegen > 0 && _currentHealth < _currentStats.maxHealth)
            {
                _currentHealth += _currentStats.healthRegen * Time.deltaTime;
                if (_currentHealth > _currentStats.maxHealth)
                {
                    _currentHealth = _currentStats.maxHealth;
                }
                OnHealthChanged?.Invoke(_currentHealth);
            }
        }

        public void MoveTo(Vector3 position)
        {
            _targetPosition = position;
            _isMoving = true;
            _currentState = HeroState.Moving;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", true);
            }
        }

        public void StopMoving()
        {
            _isMoving = false;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", false);
            }
        }

        private void FindTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            _currentTarget = spawner.GetClosestEnemy(transform.position, _currentStats.attackRange);
        }

        private void Attack()
        {
            if (_currentTarget == null) return;

            _currentState = HeroState.Attacking;
            _attackCooldown = 1f / _currentStats.attackSpeed;

            if (_animator != null)
            {
                _animator.SetTrigger("Attack");
            }

           // 在第211行和第257行添加转换
            _currentTarget.TakeDamage(Mathf.RoundToInt(_currentStats.attackDamage), DamageType.Physical);

            _currentState = HeroState.Idle;
        }

        public bool UseSkill(int skillIndex)
        {
            if (skillIndex < 0 || skillIndex >= _heroData.skills.Length) return false;

            HeroData.HeroSkill skill = _heroData.skills[skillIndex];

            if (_skillCooldowns[skill.skillName] > 0) return false;

            _skillCooldowns[skill.skillName] = skill.cooldown;
            _currentState = HeroState.UsingSkill;

            if (_animator != null)
            {
                _animator.SetTrigger("Skill");
            }

            ExecuteSkill(skill);

            OnSkillUsed?.Invoke(skill.skillName);
            EventBus.Publish(new SkillUsedEvent { SkillName = skill.skillName });

            _currentState = HeroState.Idle;
            return true;
        }

        private void ExecuteSkill(HeroData.HeroSkill skill)
        {
            if (skill.effectPrefab != null)
            {
                Instantiate(skill.effectPrefab, transform.position, Quaternion.identity);
            }

            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, skill.effectRadius);

            foreach (var enemy in enemiesInRange)
            {
                if (enemy != null && !enemy.IsDead)
                {
                    // 在第211行和第257行添加转换
enemy.TakeDamage(Mathf.RoundToInt(skill.effectValue), DamageType.Magic);
                }
            }
        }

        public void TakeDamage(float damage)
        {
            if (_currentState == HeroState.Dead) return;

            float actualDamage = damage * (1f - _currentStats.armor / 100f);
            _currentHealth -= actualDamage;

            OnHealthChanged?.Invoke(_currentHealth);

            if (_animator != null)
            {
                _animator.SetTrigger("Hit");
            }

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        public void Heal(float amount)
        {
            _currentHealth += amount;
            if (_currentHealth > _currentStats.maxHealth)
            {
                _currentHealth = _currentStats.maxHealth;
            }
            OnHealthChanged?.Invoke(_currentHealth);
        }

        public void AddExp(float exp)
        {
            _currentExp += exp;
            OnExpChanged?.Invoke(_currentExp);

            while (_currentExp >= _expToNextLevel)
            {
                LevelUp();
            }
        }

        private void LevelUp()
        {
            _currentExp -= _expToNextLevel;
            _currentLevel++;
            _expToNextLevel *= 1.5f;

            _currentStats.maxHealth *= 1.1f;
            _currentStats.attackDamage *= 1.1f;
            _currentHealth = _currentStats.maxHealth;

            OnLevelUp?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetTrigger("LevelUp");
            }
        }

        private void Die()
        {
            _currentState = HeroState.Dead;
            OnDeath?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetBool("IsDead", true);
            }
        }

        public void Revive()
        {
            _currentHealth = _currentStats.maxHealth;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsDead", false);
            }
        }

        public float GetSkillCooldown(string skillName)
        {
            return _skillCooldowns.TryGetValue(skillName, out float cd) ? cd : 0f;
        }

        public float GetSkillCooldownPercent(string skillName)
        {
            foreach (var skill in _heroData.skills)
            {
                if (skill.skillName == skillName)
                {
                    return GetSkillCooldown(skillName) / skill.cooldown;
                }
            }
            return 0f;
        }
    }
}

using UnityEngine;
using UnityEngine.EventSystems;
using TowerDefense.Data;

namespace TowerDefense.Hero
{
    public class HeroController : MonoBehaviour
    {
        [Header("Hero")]
        [SerializeField] private Hero _hero;
        [SerializeField] private HeroData _heroData;

        [Header("Movement Settings")]
        [SerializeField] private bool _useClickMovement = true;
        [SerializeField] private LayerMask _groundLayer;

        [Header("Skill Keys")]
        [SerializeField] private KeyCode _skill1Key = KeyCode.Q;
        [SerializeField] private KeyCode _skill2Key = KeyCode.W;
        [SerializeField] private KeyCode _skill3Key = KeyCode.E;

        private Camera _mainCamera;

        private void Awake()
        {
            _mainCamera = Camera.main;

            if (_hero == null)
            {
                _hero = GetComponent<Hero>();
            }
        }

        private void Start()
        {
            if (_hero != null && _heroData != null)
            {
                _hero.Initialize(_heroData);
            }
        }

        private void Update()
        {
            if (_hero == null || _hero.IsDead) return;

            HandleMovement();
            HandleSkills();
        }

        private void HandleMovement()
        {
            if (!_useClickMovement) return;

            if (Input.GetMouseButtonDown(1) && !EventSystem.current.IsPointerOverGameObject())
            {
                Ray ray = _mainCamera.ScreenPointToRay(Input.mousePosition);
                RaycastHit2D hit = Physics2D.Raycast(ray.origin, ray.direction, Mathf.Infinity, _groundLayer);

                if (hit.collider != null)
                {
                    _hero.MoveTo(hit.point);
                }
                else
                {
                    Vector3 worldPosition = _mainCamera.ScreenToWorldPoint(Input.mousePosition);
                    worldPosition.z = 0;
                    _hero.MoveTo(worldPosition);
                }
            }
        }

        private void HandleSkills()
        {
            if (_heroData == null || _heroData.skills == null) return;

            if (Input.GetKeyDown(_skill1Key) && _heroData.skills.Length > 0)
            {
                _hero.UseSkill(0);
            }
            else if (Input.GetKeyDown(_skill2Key) && _heroData.skills.Length > 1)
            {
                _hero.UseSkill(1);
            }
            else if (Input.GetKeyDown(_skill3Key) && _heroData.skills.Length > 2)
            {
                _hero.UseSkill(2);
            }
        }

        public void UseSkillByIndex(int index)
        {
            if (_hero != null)
            {
                _hero.UseSkill(index);
            }
        }

        public void SetHeroData(HeroData data)
        {
            _heroData = data;
            if (_hero != null)
            {
                _hero.Initialize(_heroData);
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class GameUI : MonoBehaviour
    {
        [Header("Top Bar")]
        [SerializeField] private Image _goldIcon;
        [SerializeField] private Text _goldText;
        [SerializeField] private Image _lifeIcon;
        [SerializeField] private Text _lifeText;
        [SerializeField] private Image _waveIcon;
        [SerializeField] private Text _waveText;

        [Header("Wave Info")]
        [SerializeField] private GameObject _waveInfoPanel;
        [SerializeField] private Text _waveTimerText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Button _startWaveButton;

        [Header("Tower Selection")]
        [SerializeField] private GameObject _towerSelectPanel;
        [SerializeField] private Transform _towerButtonContainer;
        [SerializeField] private GameObject _towerButtonPrefab;

        [Header("Tower Info")]
        [SerializeField] private GameObject _towerInfoPanel;
        [SerializeField] private Text _towerNameText;
        [SerializeField] private Text _towerLevelText;
        [SerializeField] private Text _towerDamageText;
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _sellButton;
        [SerializeField] private Text _sellValueText;

        [Header("Game Controls")]
        [SerializeField] private Button _pauseButton;
        [SerializeField] private Button _speedButton;
        [SerializeField] private GameObject _pauseMenu;
        [SerializeField] private GameObject _gameOverPanel;
        [SerializeField] private GameObject _victoryPanel;

        [Header("Settings")]
        [SerializeField] private Slider _volumeSlider;
        [SerializeField] private Toggle _soundToggle;

        private Tower.TowerSlot _selectedSlot;
        private Tower.Tower _selectedTower;

        private void Start()
        {
            InitializeUI();
            SubscribeToEvents();
        }

        private void InitializeUI()
        {
            if (_pauseMenu != null) _pauseMenu.SetActive(false);
            if (_gameOverPanel != null) _gameOverPanel.SetActive(false);
            if (_victoryPanel != null) _victoryPanel.SetActive(false);
            if (_towerInfoPanel != null) _towerInfoPanel.SetActive(false);
            if (_towerSelectPanel != null) _towerSelectPanel.SetActive(false);

            UpdateGoldDisplay(GameManager.Instance.CurrentGold);
            UpdateLifeDisplay(GameManager.Instance.CurrentLife);
            UpdateWaveDisplay(GameManager.Instance.CurrentWave);

            if (_startWaveButton != null)
            {
                _startWaveButton.onClick.AddListener(OnStartWaveClicked);
            }
            if (_pauseButton != null)
            {
                _pauseButton.onClick.AddListener(OnPauseClicked);
            }
            if (_speedButton != null)
            {
                _speedButton.onClick.AddListener(OnSpeedClicked);
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            }
            if (_sellButton != null)
            {
                _sellButton.onClick.AddListener(OnSellClicked);
            }
        }

        private void SubscribeToEvents()
        {
            GameManager.Instance.OnGoldChanged += UpdateGoldDisplay;
            GameManager.Instance.OnLifeChanged += UpdateLifeDisplay;
            GameManager.Instance.OnWaveChanged += UpdateWaveDisplay;
            GameManager.Instance.OnStateChanged += OnGameStateChanged;

            EventBus.Subscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Subscribe<LifeChangedEvent>(OnLifeChanged);
        }

        private void OnDestroy()
        {
            if (GameManager.Instance != null)
            {
                GameManager.Instance.OnGoldChanged -= UpdateGoldDisplay;
                GameManager.Instance.OnLifeChanged -= UpdateLifeDisplay;
                GameManager.Instance.OnWaveChanged -= UpdateWaveDisplay;
                GameManager.Instance.OnStateChanged -= OnGameStateChanged;
            }

            EventBus.Unsubscribe<GoldChangedEvent>(OnGoldChanged);
            EventBus.Unsubscribe<LifeChangedEvent>(OnLifeChanged);
        }

        #region Display Updates

        private void UpdateGoldDisplay(int gold)
        {
            if (_goldText != null)
            {
                _goldText.text = gold.ToString();
            }

            if (_goldIcon != null)
            {
                _goldIcon.enabled = true;
            }
        }

        private void UpdateLifeDisplay(int life)
        {
            if (_lifeText != null)
            {
                _lifeText.text = life.ToString();
            }

            if (_lifeIcon != null)
            {
                _lifeIcon.enabled = true;
            }
        }

        private void UpdateWaveDisplay(int wave)
        {
            if (_waveText != null)
            {
                _waveText.text = $"{wave}/{GameManager.Instance.TotalWaves}";
            }

            if (_waveIcon != null)
            {
                _waveIcon.enabled = true;
            }
        }

        private void OnGoldChanged(GoldChangedEvent e)
        {
            UpdateGoldDisplay(e.CurrentGold);
        }

        private void OnLifeChanged(LifeChangedEvent e)
        {
            UpdateLifeDisplay(e.CurrentLife);
        }

        #endregion

        #region Tower Selection

        public void ShowTowerSelectPanel(Tower.TowerSlot slot)
        {
            _selectedSlot = slot;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(true);
            }
        }

        public void HideTowerSelectPanel()
        {
            _selectedSlot = null;
            if (_towerSelectPanel != null)
            {
                _towerSelectPanel.SetActive(false);
            }
        }

        public void SelectTower(Data.TowerData towerData)
        {
            if (_selectedSlot != null)
            {
                _selectedSlot.PlaceTower(towerData);
                HideTowerSelectPanel();
            }
        }

        #endregion

        #region Tower Info

        public void ShowTowerInfo(Tower.Tower tower)
        {
            _selectedTower = tower;

            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(true);
            }

            UpdateTowerInfo();
        }

        public void HideTowerInfo()
        {
            _selectedTower = null;
            if (_towerInfoPanel != null)
            {
                _towerInfoPanel.SetActive(false);
            }
        }

        private void UpdateTowerInfo()
        {
            if (_selectedTower == null) return;

            if (_towerNameText != null)
            {
                _towerNameText.text = _selectedTower.Data.towerName;
            }
            if (_towerLevelText != null)
            {
                _towerLevelText.text = $"Level: {_selectedTower.CurrentLevel}";
            }
            if (_towerDamageText != null)
            {
                _towerDamageText.text = $"Damage: {_selectedTower.CurrentStats.damage}";
            }
            if (_upgradeCostText != null)
            {
                int cost = _selectedTower.GetUpgradeCost();
                _upgradeCostText.text = cost > 0 ? cost.ToString() : "MAX";
            }
            if (_sellValueText != null)
            {
                _sellValueText.text = _selectedTower.GetSellValue().ToString();
            }
            if (_upgradeButton != null)
            {
                _upgradeButton.interactable = !_selectedTower.IsMaxLevel;
            }
        }

        #endregion

        #region Button Handlers

        private void OnStartWaveClicked()
        {
            Wave.WaveManager waveManager = FindObjectOfType<Wave.WaveManager>();
            if (waveManager != null)
            {
                waveManager.ForceStartWave();
            }

            if (_startWaveButton != null)
            {
                _startWaveButton.gameObject.SetActive(false);
            }
        }

        private void OnPauseClicked()
        {
            GameManager.Instance.TogglePause();

            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(GameManager.Instance.CurrentState == GameState.Paused);
            }
        }

        private void OnSpeedClicked()
        {
            float currentSpeed = GameManager.Instance.GameSpeed;
            float newSpeed = currentSpeed >= 3f ? 1f : currentSpeed + 1f;

            if (_speedButton != null)
            {
                Text textComponent = _speedButton.GetComponentInChildren<Text>();
                if (textComponent != null)
                {
                    textComponent.text = $"{newSpeed}x";
                }
            }
        }

        private void OnUpgradeClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Upgrade();
                UpdateTowerInfo();
            }
        }

        private void OnSellClicked()
        {
            if (_selectedTower != null)
            {
                _selectedTower.Sell();
                HideTowerInfo();
            }
        }

        #endregion

        #region Game State

        private void OnGameStateChanged(GameState state)
        {
            switch (state)
            {
                case GameState.Paused:
                    ShowPauseMenu();
                    break;
                case GameState.Playing:
                    HidePauseMenu();
                    break;
                case GameState.GameOver:
                    ShowGameOver();
                    break;
                case GameState.Victory:
                    ShowVictory();
                    break;
            }
        }

        private void ShowPauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(true);
            }
        }

        private void HidePauseMenu()
        {
            if (_pauseMenu != null)
            {
                _pauseMenu.SetActive(false);
            }
        }

        private void ShowGameOver()
        {
            if (_gameOverPanel != null)
            {
                _gameOverPanel.SetActive(true);
            }
        }

        private void ShowVictory()
        {
            if (_victoryPanel != null)
            {
                _victoryPanel.SetActive(true);
            }
        }

        #endregion

        #region Wave Timer

        public void UpdateWaveTimer(float time)
        {
            if (_waveTimerText != null)
            {
                if (time > 0)
                {
                    _waveTimerText.text = $"Next Wave: {Mathf.CeilToInt(time)}s";
                }
                else
                {
                    _waveTimerText.text = "Wave In Progress";
                }
            }
        }

        public void UpdateEnemyCount(int count)
        {
            if (_enemyCountText != null)
            {
                _enemyCountText.text = $"Enemies: {count}";
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using System.Collections.Generic;
using TowerDefense.Data;
