namespace TowerDefense.UI
{
    public class ShopPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _shopPanel;
        [SerializeField] private Button _closeButton;
        [SerializeField] private Image _dimOverlay;  // 半透明遮罩

        [Header("Currency Display")]
        [SerializeField] private Text _goldAmountText;
        [SerializeField] private Text _diamondAmountText;

        [Header("Tabs")]
        [SerializeField] private Button _tabResource;
        [SerializeField] private Button _tabHero;
        [SerializeField] private Button _tabTower;
        [SerializeField] private Button _tabSpecial;
        [SerializeField] private GameObject _tabIndicator;  // 滑动指示器
        [SerializeField] private Color _tabActiveColor = new Color(1f, 0.85f, 0.3f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.6f, 0.6f, 0.6f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _shopItemPrefab;
        [Header("Confirm Dialog")]
        [SerializeField] private GameObject _confirmDialog;
        [SerializeField] private Text _confirmTitleText;
        [SerializeField] private Text _confirmDescText;
        [SerializeField] private Text _confirmPriceText;
        [SerializeField] private Button _confirmBuyButton;
        [SerializeField] private Button _confirmCancelButton;

        [Header("Feedback")]
        [SerializeField] private GameObject _feedbackPanel;
        [SerializeField] private Text _feedbackText;
        [SerializeField] private float _feedbackDuration = 1.5f;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/ShopItems";

        private ShopData _shopData;
        private ShopCategory _currentCategory;
        private ShopItemData _pendingBuyItem;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<ShopCategory, Button> _tabButtons = new Dictionary<ShopCategory, Button>();
        private Dictionary<ShopCategory, Vector3> _tabPositions = new Dictionary<ShopCategory, Vector3>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;
        private Coroutine _feedbackCoroutine;

        private void Awake()
        {
            _tabButtons[ShopCategory.Resource] = _tabResource;
            _tabButtons[ShopCategory.Hero] = _tabHero;
            _tabButtons[ShopCategory.Tower] = _tabTower;
            _tabButtons[ShopCategory.Special] = _tabSpecial;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(CloseShop);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                    // 记录每个Tab的位置用于指示器滑动
                    _tabPositions[cat] = kvp.Value.transform.localPosition;
                }
            }

            // 确认弹窗按钮
            if (_confirmBuyButton != null)
                _confirmBuyButton.onClick.AddListener(OnConfirmBuy);
            if (_confirmCancelButton != null)
                _confirmCancelButton.onClick.AddListener(OnCancelBuy);

            _torchRoot = GameObject.Find("火把");

            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadShopData();
        }

        private void Start()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);
            if (_feedbackPanel != null)
                _feedbackPanel.SetActive(false);
        }

        private void LoadShopData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _shopData = JsonUtility.FromJson<ShopData>(jsonFile.text);
                Debug.Log($"[ShopPanel] Loaded {_shopData.items.Length} items from JSON");
            }
            else
            {
                Debug.LogError($"[ShopPanel] Failed to load JSON: Resources/{_jsonPath}");
                _shopData = new ShopData { items = new ShopItemData[0] };
            }
        }

        public void OpenShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(true);

            // 半透明遮罩
            if (_dimOverlay != null)
            {
                _dimOverlay.gameObject.SetActive(true);
                _dimOverlay.color = new Color(0, 0, 0, 0.6f);
            }

            if (_torchRoot != null)
                _torchRoot.SetActive(false);

            if (_clouds != null)
                _clouds.IsPaused = true;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            LoadShopData();
            UpdateCurrencyDisplay();
            SwitchTab(ShopCategory.Resource);
        }

        public void CloseShop()
        {
            if (_shopPanel != null)
                _shopPanel.SetActive(false);

            if (_dimOverlay != null)
                _dimOverlay.gameObject.SetActive(false);

            if (_torchRoot != null)
                _torchRoot.SetActive(true);

            if (_clouds != null)
                _clouds.IsPaused = false;

            if (_snowParticles != null)
            {
                var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (renderer != null)
                    renderer.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void UpdateCurrencyDisplay()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                if (_goldAmountText != null)
                    _goldAmountText.text = wallet.Gold.ToString();
                if (_diamondAmountText != null)
                    _diamondAmountText.text = wallet.Diamond.ToString();
            }
        }

        private void SwitchTab(ShopCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            MoveTabIndicator(category);
            RefreshItemList();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory ? _tabActiveColor : new Color(0.8f, 0.8f, 0.8f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void MoveTabIndicator(ShopCategory category)
        {
            if (_tabIndicator == null || !_tabPositions.ContainsKey(category)) return;
            StartCoroutine(AnimateTabIndicator(_tabPositions[category]));
        }

        private IEnumerator AnimateTabIndicator(Vector3 targetPos)
        {
            Vector3 startPos = _tabIndicator.transform.localPosition;
            float duration = 0.2f;
            float elapsed = 0f;

            while (elapsed < duration)
            {
                elapsed += Time.deltaTime;
                float t = elapsed / duration;
                // ease-out
                t = 1f - (1f - t) * (1f - t);
                _tabIndicator.transform.localPosition = Vector3.Lerp(startPos, targetPos, t);
                yield return null;
            }

            _tabIndicator.transform.localPosition = targetPos;
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) Destroy(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _shopItemPrefab == null)
            {
                Debug.LogWarning("[ShopPanel] Item container or prefab is null");
                return;
            }

            foreach (var itemData in _shopData.items)
            {
                if (itemData.category != _currentCategory) continue;

                GameObject itemObj = Instantiate(_shopItemPrefab, _itemContainer);
                _spawnedItems.Add(itemObj);

                var shopItemUI = itemObj.GetComponent<ShopItemUI>();
                if (shopItemUI != null)
                {
                    shopItemUI.Setup(itemData, this);
                }
            }
        }

        /// <summary>
        /// 点击购买时，先弹出确认框
        /// </summary>
        public void OnBuyClicked(ShopItemData itemData)
        {
            if (itemData.isLimited && itemData.purchasedCount >= itemData.limitCount)
            {
                ShowFeedback("已达购买上限!");
                return;
            }

            _pendingBuyItem = itemData;
            ShowConfirmDialog(itemData);
        }

        private void ShowConfirmDialog(ShopItemData itemData)
        {
            if (_confirmDialog == null)
            {
                // 没有确认弹窗则直接购买
                ExecuteBuy(itemData);
                return;
            }

            if (_confirmTitleText != null)
                _confirmTitleText.text = $"购买 {itemData.name}?";

            if (_confirmDescText != null)
            {
                string rewardText = ShopItemUI.BuildRewardText(itemData);
                _confirmDescText.text = string.IsNullOrEmpty(rewardText) ? itemData.description : $"获得: {rewardText}";
            }

            if (_confirmPriceText != null)
            {
                int price = itemData.discount > 0
                    ? itemData.price * (100 - itemData.discount) / 100
                    : itemData.price;

                if (itemData.currencyType == CurrencyType.Free)
                {
                    _confirmPriceText.text = "免费领取";
                    _confirmPriceText.color = Color.green;
                }
                else
                {
                    string symbol = GetCurrencySymbol(itemData.currencyType);
                    _confirmPriceText.text = $"花费: {symbol} {price}";
                    _confirmPriceText.color = Color.white;
                }
            }

            _confirmDialog.SetActive(true);
        }

        private void OnConfirmBuy()
        {
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);

            if (_pendingBuyItem != null)
            {
                ExecuteBuy(_pendingBuyItem);
                _pendingBuyItem = null;
            }
        }

        private void OnCancelBuy()
        {
            if (_confirmDialog != null)
                _confirmDialog.SetActive(false);
            _pendingBuyItem = null;
        }

        private void ExecuteBuy(ShopItemData itemData)
        {
            int price = itemData.discount > 0
                ? itemData.price * (100 - itemData.discount) / 100
                : itemData.price;

            var wallet = PlayerWallet.Instance;
            if (wallet == null)
            {
                Debug.LogWarning("[ShopPanel] PlayerWallet not found");
                return;
            }

            bool success = itemData.currencyType switch
            {
                CurrencyType.Gold => wallet.SpendGold(price),
                CurrencyType.Diamond => wallet.SpendDiamond(price),
                CurrencyType.Free => true,
                _ => false
            };

            if (!success)
            {
                string curName = itemData.currencyType switch
                {
                    CurrencyType.Gold => "金币不足",
                    CurrencyType.Diamond => "钻石不足",
                    _ => "无法购买"
                };
                ShowFeedback(curName);
                return;
            }

            Debug.Log($"[ShopPanel] 购买成功: {itemData.name}, 花费: {price}");

            // 发放奖励
            if (itemData.rewardGold > 0)
                wallet.AddGold(itemData.rewardGold);
            if (itemData.rewardDiamond > 0)
                wallet.AddDiamond(itemData.rewardDiamond);
            if (itemData.rewardStamina > 0)
                wallet.AddStamina(itemData.rewardStamina);

            itemData.purchasedCount++;

            ShowFeedback($"购买成功! {itemData.name}");
            UpdateCurrencyDisplay();
            RefreshItemList();
        }

        private void ShowFeedback(string message)
        {
            if (_feedbackPanel == null || _feedbackText == null) return;

            if (_feedbackCoroutine != null)
                StopCoroutine(_feedbackCoroutine);

            _feedbackCoroutine = StartCoroutine(ShowFeedbackCoroutine(message));
        }

        private IEnumerator ShowFeedbackCoroutine(string message)
        {
            _feedbackPanel.SetActive(true);
            _feedbackText.text = message;

            // 淡入
            var canvasGroup = _feedbackPanel.GetComponent<CanvasGroup>();
            if (canvasGroup != null)
            {
                canvasGroup.alpha = 0f;
                float fadeIn = 0.2f;
                float t = 0f;
                while (t < fadeIn)
                {
                    t += Time.deltaTime;
                    canvasGroup.alpha = Mathf.Lerp(0f, 1f, t / fadeIn);
                    yield return null;
                }
                canvasGroup.alpha = 1f;

                // 停留
                yield return new WaitForSeconds(_feedbackDuration);

                // 淡出
                float fadeOut = 0.3f;
                t = 0f;
                while (t < fadeOut)
                {
                    t += Time.deltaTime;
                    canvasGroup.alpha = Mathf.Lerp(1f, 0f, t / fadeOut);
                    yield return null;
                }
                canvasGroup.alpha = 0f;
            }
            else
            {
                yield return new WaitForSeconds(_feedbackDuration);
            }

            _feedbackPanel.SetActive(false);
            _feedbackCoroutine = null;
        }

        public static string GetCategoryName(ShopCategory category)
        {
            return category switch
            {
                ShopCategory.Resource => "资源",
                ShopCategory.Hero => "英雄",
                ShopCategory.Tower => "防御塔",
                ShopCategory.Special => "特惠",
                _ => "未知"
            };
        }

        public static string GetCurrencySymbol(CurrencyType type)
        {
            return type switch
            {
                CurrencyType.Gold => "🪙",
                CurrencyType.Diamond => "💎",
                CurrencyType.Free => "🎁",
                _ => ""
            };
        }
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace TowerDefense.UI
{
    public class SettingsPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _settingsPanel;

        [Header("Buttons")]
        [SerializeField] private Button _settingsButton;
        [SerializeField] private Button _restartButton;
        [SerializeField] private Button _mainMenuButton;
        [SerializeField] private Button _quitButton;

        [Header("Settings")]
        [SerializeField] private Toggle _bgMusicToggle;
        [SerializeField] private Toggle _soundEffectsToggle;
        [SerializeField] private Slider _volumeSlider;
        [SerializeField] private Dropdown _languageDropdown;

        private bool _isPanelOpen = false;
        private bool _wasPausedBefore = false;

        private void Awake()
        {
            // 初始隐藏设置面板
            if (_settingsPanel != null)
            {
                _settingsPanel.SetActive(false);
            }

            // 绑定按钮事件
            if (_settingsButton != null)
            {
                _settingsButton.onClick.AddListener(ToggleSettingsPanel);
            }

            if (_restartButton != null)
            {
                _restartButton.onClick.AddListener(OnRestartClicked);
            }

            if (_mainMenuButton != null)
            {
                _mainMenuButton.onClick.AddListener(OnMainMenuClicked);
            }

            if (_quitButton != null)
            {
                _quitButton.onClick.AddListener(OnQuitClicked);
            }

            // 绑定设置选项事件
            if (_bgMusicToggle != null)
            {
                _bgMusicToggle.onValueChanged.AddListener(OnBgMusicChanged);
            }

            if (_soundEffectsToggle != null)
            {
                _soundEffectsToggle.onValueChanged.AddListener(OnSoundEffectsChanged);
            }

            if (_volumeSlider != null)
            {
                _volumeSlider.onValueChanged.AddListener(OnVolumeChanged);
            }

            if (_languageDropdown != null)
            {
                _languageDropdown.onValueChanged.AddListener(OnLanguageChanged);
            }

            // 加载保存的设置
            LoadSettings();
        }

        private void LoadSettings()
        {
            // 从 PlayerPrefs 加载设置
            if (_bgMusicToggle != null)
            {
                _bgMusicToggle.isOn = PlayerPrefs.GetInt("BgMusicEnabled", 1) == 1;
            }

            if (_soundEffectsToggle != null)
            {
                _soundEffectsToggle.isOn = PlayerPrefs.GetInt("SoundEffectsEnabled", 1) == 1;
            }

            if (_volumeSlider != null)
            {
                _volumeSlider.value = PlayerPrefs.GetFloat("Volume", 0.7f);
            }

            if (_languageDropdown != null)
            {
                _languageDropdown.value = PlayerPrefs.GetInt("Language", 0);
            }
        }

        private void SaveSettings()
        {
            // 保存设置到 PlayerPrefs
            if (_bgMusicToggle != null)
            {
                PlayerPrefs.SetInt("BgMusicEnabled", _bgMusicToggle.isOn ? 1 : 0);
            }

            if (_soundEffectsToggle != null)
            {
                PlayerPrefs.SetInt("SoundEffectsEnabled", _soundEffectsToggle.isOn ? 1 : 0);
            }

            if (_volumeSlider != null)
            {
                PlayerPrefs.SetFloat("Volume", _volumeSlider.value);
            }

            if (_languageDropdown != null)
            {
                PlayerPrefs.SetInt("Language", _languageDropdown.value);
            }

            PlayerPrefs.Save();
        }

        public void ToggleSettingsPanel()
        {
            _isPanelOpen = !_isPanelOpen;

            if (_settingsPanel != null)
            {
                _settingsPanel.SetActive(_isPanelOpen);
            }

            // 打开时暂停游戏，关闭时恢复
            if (_isPanelOpen)
            {
                _wasPausedBefore = Core.GameManager.Instance.CurrentState == Core.GameState.Paused;

                if (!_wasPausedBefore)
                {
                    Core.GameManager.Instance.PauseGame();
                    Debug.Log("设置界面打开，游戏已暂停");
                }
            }
            else
            {
                if (!_wasPausedBefore)
                {
                    Core.GameManager.Instance.ResumeGame();
                    Debug.Log("设置界面关闭，游戏已恢复");
                }

                // 保存设置
                SaveSettings();
            }
        }

        private void OnBgMusicChanged(bool enabled)
        {
            Debug.Log($"背景音乐: {(enabled ? "开启" : "关闭")}");
            // 这里可以添加实际的音乐控制逻辑
            // AudioManager.Instance.SetBgMusicEnabled(enabled);
        }

        private void OnSoundEffectsChanged(bool enabled)
        {
            Debug.Log($"音效: {(enabled ? "开启" : "关闭")}");
            // 这里可以添加实际的音效控制逻辑
            // AudioManager.Instance.SetSoundEffectsEnabled(enabled);
        }

        private void OnVolumeChanged(float value)
        {
            Debug.Log($"音量: {value * 100:F0}%");
            // 这里可以添加实际的音量控制逻辑
            // AudioManager.Instance.SetVolume(value);
        }

        private void OnLanguageChanged(int index)
        {
            string language = _languageDropdown.options[index].text;
            Debug.Log($"语言切换为: {language}");
            // 这里可以添加实际的语言切换逻辑
        }

        private void OnRestartClicked()
        {
            Debug.Log("重新开始游戏");
            Core.GameManager.Instance.RestartGame();
        }

        private void OnMainMenuClicked()
        {
            Debug.Log("返回主菜单");
            // 恢复游戏状态
            if (Core.GameManager.Instance.CurrentState == Core.GameState.Paused)
            {
                Core.GameManager.Instance.ResumeGame();
            }

            // 加载主菜单场景
            UnityEngine.SceneManagement.SceneManager.LoadScene("MainMenu");
        }

        private void OnQuitClicked()
        {
            Debug.Log("退出游戏");
#if UNITY_EDITOR
            UnityEditor.EditorApplication.isPlaying = false;
#else
            Application.Quit();
#endif
        }

        private void OnDestroy()
        {
            // 清理事件绑定
            if (_settingsButton != null)
            {
                _settingsButton.onClick.RemoveListener(ToggleSettingsPanel);
            }

            if (_restartButton != null)
            {
                _restartButton.onClick.RemoveListener(OnRestartClicked);
            }

            if (_mainMenuButton != null)
            {
                _mainMenuButton.onClick.RemoveListener(OnMainMenuClicked);
            }

            if (_quitButton != null)
            {
                _quitButton.onClick.RemoveListener(OnQuitClicked);
            }
        }
    }
}

using System.IO;
using UnityEngine;
using TowerDefense.Core;

namespace TowerDefense.Save
{
    public class SaveSystem : Singleton<SaveSystem>
    {
        private const string SAVE_FILE = "savedata.json";
        private const string SAVE_FOLDER = "Save";

        private GameSaveData _currentSave;
        private string SavePath => Path.Combine(Application.persistentDataPath, SAVE_FOLDER, SAVE_FILE);

        public GameSaveData CurrentSave => _currentSave;

        /// <summary>是否在模块模式下运行</summary>
        private bool _isModuleMode;

        protected override void Awake()
        {
            base.Awake();

            _isModuleMode = ModuleModeDetector.IsModuleMode;

            if (_isModuleMode)
            {
                // 模块模式下使用共享 SaveSystem 的模块存档
                LoadFromSharedSaveSystem();
            }
            else
            {
                LoadGame();
            }
        }

        /// <summary>
        /// 从共享 SaveSystem 加载塔防模块存档数据。
        /// </summary>
        private void LoadFromSharedSaveSystem()
        {
            var sharedSave = Sttop5.Shared.Save.SaveSystem.Instance;
            if (sharedSave != null)
            {
                string moduleData = sharedSave.LoadModuleData("towerdefense");
                if (!string.IsNullOrEmpty(moduleData))
                {
                    try
                    {
                        // 尝试从模块存档数据中提取塔防原生存档
                        var wrapper = JsonUtility.FromJson<TDModuleSaveWrapper>(moduleData);
                        if (wrapper != null && !string.IsNullOrEmpty(wrapper.tdSaveJson))
                        {
                            _currentSave = JsonUtility.FromJson<GameSaveData>(wrapper.tdSaveJson);
                        }
                        else
                        {
                            _currentSave = new GameSaveData();
                        }
                        Debug.Log("[SaveSystem] 从共享存档加载塔防模块数据");
                    }
                    catch (System.Exception e)
                    {
                        Debug.LogError($"[SaveSystem] 加载共享模块存档失败: {e.Message}");
                        _currentSave = new GameSaveData();
                    }
                }
                else
                {
                    _currentSave = new GameSaveData();
                    Debug.Log("[SaveSystem] 无塔防模块存档，创建新数据");
                }
            }
            else
            {
                LoadGame();
                Debug.LogWarning("[SaveSystem] 共享 SaveSystem 不可用，使用独立存档");
            }
        }

        /// <summary>
        /// 模块存档数据包装器，用于从共享 SaveSystem 的模块存档中提取塔防原生存档。
        /// </summary>
        [System.Serializable]
        private class TDModuleSaveWrapper
        {
            public string tdSaveJson;
        }

        public void SaveGame()
        {
            if (_isModuleMode)
            {
                SaveToSharedSaveSystem();
                return;
            }

            string directory = Path.GetDirectoryName(SavePath);
            if (!Directory.Exists(directory))
            {
                Directory.CreateDirectory(directory);
            }

            string json = JsonUtility.ToJson(_currentSave, true);
            File.WriteAllText(SavePath, json);

            Debug.Log($"[SaveSystem] Game saved to {SavePath}");
        }

        /// <summary>
        /// 保存到共享 SaveSystem 的模块存档。
        /// </summary>
        private void SaveToSharedSaveSystem()
        {
            var sharedSave = Sttop5.Shared.Save.SaveSystem.Instance;
            if (sharedSave != null)
            {
                string tdJson = _currentSave != null ? JsonUtility.ToJson(_currentSave) : "";
                sharedSave.SaveModuleData("towerdefense", tdJson, 1);
                Debug.Log("[SaveSystem] 塔防模块存档已保存到共享 SaveSystem");
            }
        }

        public void LoadGame()
        {
            if (File.Exists(SavePath))
            {
                string json = File.ReadAllText(SavePath);
                _currentSave = JsonUtility.FromJson<GameSaveData>(json);
                Debug.Log("[SaveSystem] Game loaded successfully");
            }
            else
            {
                _currentSave = new GameSaveData();
                Debug.Log("[SaveSystem] No save file found, creating new save data");
            }
        }

        public void DeleteSave()
        {
            if (_isModuleMode)
            {
                var sharedSave = Sttop5.Shared.Save.SaveSystem.Instance;
                if (sharedSave != null)
                {
                    sharedSave.DeleteModuleData("towerdefense");
                    _currentSave = new GameSaveData();
                    Debug.Log("[SaveSystem] Module save data deleted");
                }
                return;
            }

            if (File.Exists(SavePath))
            {
                File.Delete(SavePath);
                _currentSave = new GameSaveData();
                Debug.Log("[SaveSystem] Save file deleted");
            }
        }

        public void SaveLevelProgress(int levelIndex, int stars, int score, float time)
        {
            if (levelIndex < 0) return;

            while (_currentSave.levels.Count <= levelIndex)
            {
                _currentSave.levels.Add(new GameSaveData.LevelSaveData
                {
                    levelIndex = _currentSave.levels.Count,
                    isUnlocked = false,
                    starsEarned = 0,
                    highScore = 0,
                    bestTime = float.MaxValue
                });
            }

            var levelData = _currentSave.levels[levelIndex];
            levelData.isUnlocked = true;
            levelData.starsEarned = Mathf.Max(levelData.starsEarned, stars);
            levelData.highScore = Mathf.Max(levelData.highScore, score);
            levelData.bestTime = Mathf.Min(levelData.bestTime, time);

            _currentSave.levels[levelIndex] = levelData;

            if (levelIndex + 1 < _currentSave.levels.Count)
            {
                var nextLevel = _currentSave.levels[levelIndex + 1];
                nextLevel.isUnlocked = true;
                _currentSave.levels[levelIndex + 1] = nextLevel;
            }

            SaveGame();
        }

        public GameSaveData.LevelSaveData GetLevelData(int levelIndex)
        {
            if (levelIndex >= 0 && levelIndex < _currentSave.levels.Count)
            {
                return _currentSave.levels[levelIndex];
            }
            return new GameSaveData.LevelSaveData { levelIndex = levelIndex, isUnlocked = levelIndex == 0 };
        }

        public void SaveHeroProgress(string heroName, int level, float experience)
        {
            var heroData = _currentSave.heroes.Find(h => h.heroName == heroName);
            if (heroData == null)
            {
                heroData = new GameSaveData.HeroSaveData { heroName = heroName, isUnlocked = true };
                _currentSave.heroes.Add(heroData);
            }

            heroData.level = level;
            heroData.experience = experience;

            SaveGame();
        }

        public GameSaveData.HeroSaveData GetHeroData(string heroName)
        {
            return _currentSave.heroes.Find(h => h.heroName == heroName);
        }

        public void UpdatePlayerStats(int gold, int kills, int waves, float playTime)
        {
            _currentSave.player.totalGold += gold;
            _currentSave.player.totalKills += kills;
            _currentSave.player.totalWavesCompleted += waves;
            _currentSave.player.totalPlayTime += playTime;
            _currentSave.player.totalGamesPlayed++;

            SaveGame();
        }

        public void SaveSettings(float musicVolume, float sfxVolume, bool fullscreen, int quality)
        {
            _currentSave.settings.musicVolume = musicVolume;
            _currentSave.settings.sfxVolume = sfxVolume;
            _currentSave.settings.isFullscreen = fullscreen;
            _currentSave.settings.qualityLevel = quality;

            SaveGame();
        }

        public void LoadSettings()
        {
            AudioListener.volume = _currentSave.settings.sfxVolume;
            Screen.fullScreen = _currentSave.settings.isFullscreen;
            QualitySettings.SetQualityLevel(_currentSave.settings.qualityLevel);
        }

        public int CalculateTotalStars()
        {
            int total = 0;
            foreach (var level in _currentSave.levels)
            {
                total += level.starsEarned;
            }
            _currentSave.totalStars = total;
            return total;
        }
    }
}

