using UnityEngine;
using TowerDefense.Core;

namespace TowerDefense.Data
{
    public class PlayerWallet : Singleton<PlayerWallet>
    {
        [Header("Initial Values")]
        [SerializeField] private int _initialGold = 1000;
        [SerializeField] private int _initialDiamond = 100;
        [SerializeField] private int _initialStamina = 60;

        /// <summary>塔防金币与家园金币的兑换比率：100 塔防金币 = 1 家园金币</summary>
        public const int EXCHANGE_RATE = 100;

        private int _gold;
        private int _diamond;
        private int _stamina;

        /// <summary>是否代理钻石/体力到共享 PlayerProfile（金币始终独立管理）</summary>
        private bool _isProxyMode;

        /// <summary>金币始终独立管理（不代理到 PlayerProfile）</summary>
        public int Gold => _gold;
        /// <summary>钻石在模块模式下代理到 PlayerProfile</summary>
        public int Diamond => _isProxyMode ? GetProxyDiamond() : _diamond;
        /// <summary>体力在模块模式下代理到 PlayerProfile</summary>
        public int Stamina => _isProxyMode ? GetProxyStamina() : _stamina;

        /// <summary>是否可以与家园金币兑换（需要 PlayerProfile 可用）</summary>
        public bool CanExchange => _profile != null;

        public event System.Action<int> OnGoldChanged;
        public event System.Action<int> OnDiamondChanged;
        public event System.Action<int> OnStaminaChanged;

        private Sttop5.Shared.Player.PlayerProfile _profile;

        private const string WALLET_SAVE_KEY = "towerdefense_wallet";

        [System.Serializable]
        private class WalletSaveData
        {
            public int gold;
        }

        protected override void Awake()
        {
            base.Awake();

            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "TDGameScene" || ModuleModeDetector.IsModuleMode)
            {
                EnableProxyMode();
            }
            else
            {
                _gold = _initialGold;
                _diamond = _initialDiamond;
                _stamina = _initialStamina;
            }
        }

        /// <summary>
        /// 启用代理模式，将钻石/体力操作转发到共享 PlayerProfile，金币独立管理。
        /// </summary>
        public void EnableProxyMode()
        {
            _profile = Sttop5.Shared.Player.PlayerProfile.Instance;
            if (_profile != null)
            {
                _isProxyMode = true;
                // 钻石和体力代理到 PlayerProfile
                _diamond = _profile.Diamond;
                _stamina = _profile.Stamina;

                _profile.OnDiamondChanged += OnProxyDiamondChanged;
                _profile.OnStaminaChanged += OnProxyStaminaChanged;

                // 金币独立管理，从存档加载
                LoadWalletData();

                Debug.Log($"[PlayerWallet] 代理模式已启用，金币独立管理，当前金币: {_gold}");
            }
            else
            {
                _gold = _initialGold;
                _diamond = _initialDiamond;
                _stamina = _initialStamina;
                Debug.LogWarning("[PlayerWallet] PlayerProfile 不可用，使用独立模式");
            }
        }

        /// <summary>
        /// 禁用代理模式，断开与 PlayerProfile 的连接。
        /// </summary>
        public void DisableProxyMode()
        {
            if (_profile != null)
            {
                _profile.OnDiamondChanged -= OnProxyDiamondChanged;
                _profile.OnStaminaChanged -= OnProxyStaminaChanged;
            }
            _isProxyMode = false;
            _profile = null;
        }

        #region Proxy Helpers

        private int GetProxyDiamond() => _profile != null ? _profile.Diamond : _diamond;
        private int GetProxyStamina() => _profile != null ? _profile.Stamina : _stamina;

        private void OnProxyDiamondChanged(int diamond)
        {
            _diamond = diamond;
            OnDiamondChanged?.Invoke(diamond);
        }

        private void OnProxyStaminaChanged(int stamina)
        {
            _stamina = stamina;
            OnStaminaChanged?.Invoke(stamina);
        }

        #endregion

        #region Gold (独立管理)

        public bool HasEnoughGold(int amount) => _gold >= amount;

        public void AddGold(int amount)
        {
            if (amount <= 0) return;
            _gold += amount;
            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;
            _gold -= amount;
            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = -amount });
            return true;
        }

        /// <summary>
        /// 将塔防金币兑换为家园金币（100:1）。
        /// </summary>
        /// <param name="tdGoldAmount">要兑换的塔防金币数量，必须为 EXCHANGE_RATE 的倍数</param>
        /// <returns>是否兑换成功</returns>
        public bool ConvertGoldToHome(int tdGoldAmount)
        {
            if (!CanExchange) return false;
            if (tdGoldAmount <= 0 || tdGoldAmount % EXCHANGE_RATE != 0) return false;
            if (_gold < tdGoldAmount) return false;

            int homeGold = tdGoldAmount / EXCHANGE_RATE;
            _gold -= tdGoldAmount;
            _profile.AddGold(homeGold, "towerdefense_exchange");

            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = -tdGoldAmount });
            Debug.Log($"[PlayerWallet] 兑换: {tdGoldAmount} 塔防金币 → {homeGold} 家园金币");
            return true;
        }

        /// <summary>
        /// 将家园金币兑换为塔防金币（1:100）。
        /// </summary>
        /// <param name="homeGoldAmount">要兑换的家园金币数量</param>
        /// <returns>是否兑换成功</returns>
        public bool ConvertGoldFromHome(int homeGoldAmount)
        {
            if (!CanExchange) return false;
            if (homeGoldAmount <= 0) return false;
            if (!_profile.HasEnoughGold(homeGoldAmount)) return false;

            if (!_profile.SpendGold(homeGoldAmount, "towerdefense_exchange")) return false;

            int tdGold = homeGoldAmount * EXCHANGE_RATE;
            _gold += tdGold;

            OnGoldChanged?.Invoke(_gold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _gold, Change = tdGold });
            Debug.Log($"[PlayerWallet] 兑换: {homeGoldAmount} 家园金币 → {tdGold} 塔防金币");
            return true;
        }

        #endregion

        #region Diamond (代理/独立)

        public bool HasEnoughDiamond(int amount) => Diamond >= amount;

        public void AddDiamond(int amount)
        {
            if (amount <= 0) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddDiamond(amount, "towerdefense");
                return;
            }

            _diamond += amount;
            OnDiamondChanged?.Invoke(_diamond);
        }

        public bool SpendDiamond(int amount)
        {
            if (!HasEnoughDiamond(amount)) return false;

            if (_isProxyMode && _profile != null)
            {
                return _profile.SpendDiamond(amount, "towerdefense");
            }

            _diamond -= amount;
            OnDiamondChanged?.Invoke(_diamond);
            return true;
        }

        #endregion

        #region Stamina (代理/独立)

        public bool HasEnoughStamina(int amount) => Stamina >= amount;

        public void AddStamina(int amount)
        {
            if (amount <= 0) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddStamina(amount);
                return;
            }

            _stamina += amount;
            OnStaminaChanged?.Invoke(_stamina);
        }

        public bool SpendStamina(int amount)
        {
            if (Stamina < amount) return false;

            if (_isProxyMode && _profile != null)
            {
                return _profile.SpendStamina(amount);
            }

            _stamina -= amount;
            OnStaminaChanged?.Invoke(_stamina);
            return true;
        }

        #endregion

        #region Persistence

        private void SaveWalletData()
        {
            var sharedSave = Sttop5.Shared.Save.SaveSystem.Instance;
            if (sharedSave == null) return;

            var data = new WalletSaveData { gold = _gold };
            sharedSave.SaveModuleData(WALLET_SAVE_KEY, JsonUtility.ToJson(data), 1);
        }

        private void LoadWalletData()
        {
            var sharedSave = Sttop5.Shared.Save.SaveSystem.Instance;
            if (sharedSave == null)
            {
                _gold = _initialGold;
                return;
            }

            string json = sharedSave.LoadModuleData(WALLET_SAVE_KEY);
            if (!string.IsNullOrEmpty(json))
            {
                try
                {
                    var data = JsonUtility.FromJson<WalletSaveData>(json);
                    if (data != null)
                    {
                        _gold = data.gold;
                        Debug.Log($"[PlayerWallet] 从存档加载金币: {_gold}");
                        return;
                    }
                }
                catch (System.Exception e)
                {
                    Debug.LogError($"[PlayerWallet] 加载金币存档失败: {e.Message}");
                }
            }
            _gold = _initialGold;
            Debug.Log($"[PlayerWallet] 使用初始金币: {_gold}");
        }

        #endregion

        private new void OnDestroy()
        {
            SaveWalletData();
            DisableProxyMode();
        }

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveWalletData();
        }

        private void OnApplicationQuit()
        {
            SaveWalletData();
        }
    }
}

using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Save;

namespace TowerDefense.Data
{
    public class PlayerLevelSystem : Singleton<PlayerLevelSystem>
    {
        [Header("等级配置")]
        [SerializeField] private int _maxLevel = 99;
        [SerializeField] private int _baseExp = 100;
        [SerializeField] private int _expIncrement = 50;

        private int _level = 1;
        private int _currentExp = 0;

        /// <summary>是否代理到共享 PlayerProfile</summary>
        private bool _isProxyMode;

        private Sttop5.Shared.Player.PlayerProfile _profile;

        public int Level => _isProxyMode ? GetProxyLevel() : _level;
        public int CurrentExp => _isProxyMode ? GetProxyExp() : _currentExp;
        public int MaxLevel => _maxLevel;
        public int ExpToNextLevel => _isProxyMode ? GetProxyExpToNext() : GetExpRequiredForLevel(_level);
        public float ExpProgress => Level >= _maxLevel ? 1f : (float)CurrentExp / ExpToNextLevel;
        public bool IsMaxLevel => Level >= _maxLevel;

        public event System.Action<int> OnLevelChanged;
        public event System.Action<int, int> OnExpChanged;

        private bool _loadedFromSave = false;

        protected override void Awake()
        {
            base.Awake();
        }

        private void Start()
        {
            // 检测模块模式（通过场景名或全局标志判断）
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "TDGameScene" || ModuleModeDetector.IsModuleMode)
            {
                EnableProxyMode();
            }
            else
            {
                LoadFromSave();
            }
        }

        /// <summary>
        /// 启用代理模式，将等级/经验操作转发到共享 PlayerProfile。
        /// </summary>
        public void EnableProxyMode()
        {
            _profile = Sttop5.Shared.Player.PlayerProfile.Instance;
            if (_profile != null)
            {
                _isProxyMode = true;
                _level = _profile.Level;
                _currentExp = _profile.CurrentExp;

                _profile.OnLevelChanged += OnProxyLevelChanged;
                _profile.OnExpChanged += OnProxyExpChanged;

                Debug.Log($"[PlayerLevelSystem] 代理模式已启用: Lv.{_level}");
            }
            else
            {
                LoadFromSave();
                Debug.LogWarning("[PlayerLevelSystem] PlayerProfile 不可用，使用独立模式");
            }
        }

        /// <summary>
        /// 禁用代理模式。
        /// </summary>
        public void DisableProxyMode()
        {
            if (_profile != null)
            {
                _profile.OnLevelChanged -= OnProxyLevelChanged;
                _profile.OnExpChanged -= OnProxyExpChanged;
            }
            _isProxyMode = false;
            _profile = null;
        }

        #region Proxy Helpers

        private int GetProxyLevel() => _profile != null ? _profile.Level : _level;
        private int GetProxyExp() => _profile != null ? _profile.CurrentExp : _currentExp;
        private int GetProxyExpToNext() => _profile != null ? _profile.ExpToNextLevel : GetExpRequiredForLevel(_level);

        private void OnProxyLevelChanged(int level)
        {
            _level = level;
            OnLevelChanged?.Invoke(level);
        }

        private void OnProxyExpChanged(int currentExp, int expToNext)
        {
            _currentExp = currentExp;
            OnExpChanged?.Invoke(currentExp, expToNext);
            EventBus.Publish(new ExpChangedEvent { Level = _level, CurrentExp = currentExp, ExpToNext = expToNext });
        }

        #endregion

        public int GetExpRequiredForLevel(int level)
        {
            if (level >= _maxLevel) return int.MaxValue;
            return _baseExp + (level - 1) * _expIncrement;
        }

        public void AddExp(int amount)
        {
            if (amount <= 0 || IsMaxLevel) return;

            if (_isProxyMode && _profile != null)
            {
                _profile.AddExp(amount);
                return;
            }

            if (!_loadedFromSave)
            {
                LoadFromSave();
            }

            int oldLevel = _level;
            _currentExp += amount;

            while (_currentExp >= ExpToNextLevel && !IsMaxLevel)
            {
                _currentExp -= ExpToNextLevel;
                _level++;
            }

            if (IsMaxLevel)
                _currentExp = 0;

            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
            EventBus.Publish(new ExpChangedEvent { Level = _level, CurrentExp = _currentExp, ExpToNext = ExpToNextLevel });

            if (_level != oldLevel)
            {
                OnLevelChanged?.Invoke(_level);
                EventBus.Publish(new LevelUpEvent { NewLevel = _level, OldLevel = oldLevel });
                Debug.Log($"[PlayerLevelSystem] 升级! Lv.{oldLevel} → Lv.{_level}");
            }
        }

        public void SetLevelData(int level, int exp)
        {
            _level = Mathf.Clamp(level, 1, _maxLevel);
            _currentExp = IsMaxLevel ? 0 : Mathf.Clamp(exp, 0, ExpToNextLevel);
            OnLevelChanged?.Invoke(_level);
            OnExpChanged?.Invoke(_currentExp, ExpToNextLevel);
        }

        private void LoadFromSave()
        {
            var save = SaveSystem.Instance;
            if (save != null && save.CurrentSave != null)
            {
                var player = save.CurrentSave.player;
                SetLevelData(player.playerLevel, player.playerExp);
                _loadedFromSave = true;
                Debug.Log($"[PlayerLevelSystem] 从存档加载: Lv.{_level}, Exp={_currentExp}");
            }
            else
            {
                Debug.LogWarning("[PlayerLevelSystem] SaveSystem 未就绪，将在首次 AddExp 时重试加载");
            }
        }

        public void PersistToSave()
        {
            if (_isProxyMode)
            {
                // 代理模式下由 PlayerProfile 自己持久化
                _profile?.PersistToSave();
                return;
            }

            var save = SaveSystem.Instance;
            if (save != null && save.CurrentSave != null)
            {
                save.CurrentSave.player.playerLevel = _level;
                save.CurrentSave.player.playerExp = _currentExp;
                save.SaveGame();
            }
        }

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) PersistToSave();
        }

        private void OnApplicationQuit()
        {
            PersistToSave();
        }

        private void OnDisable()
        {
            PersistToSave();
        }

        private new void OnDestroy()
        {
            DisableProxyMode();
        }
    }
}

using UnityEngine;
using UnityEngine.Tilemaps;
using System.Collections.Generic;

namespace TowerDefense.Map
{
    public class MapGenerator : MonoBehaviour
    {
        [Header("Tilemaps")]
        [SerializeField] private Tilemap groundMap;
        [SerializeField] private Tilemap pathMap;
        [SerializeField] private Tilemap buildSlotMap;
        [SerializeField] private Tilemap decorationMap;

        [Header("Prefabs")]
        [SerializeField] private GameObject towerSlotPrefab;

        [Header("Map Settings")]
        [SerializeField] private Vector3 mapSize = new Vector3(20, 15, 0);

        private List<Tower.TowerSlot> towerSlots = new List<Tower.TowerSlot>();

        public void InitializeMap()
        {
            GenerateTowerSlots();
            InitializePaths();
        }

        private void GenerateTowerSlots()
        {
            if (buildSlotMap == null || towerSlotPrefab == null) return;

            towerSlots.Clear();

            BoundsInt bounds = buildSlotMap.cellBounds;
            TileBase[] allTiles = buildSlotMap.GetTilesBlock(bounds);

            for (int x = bounds.xMin; x < bounds.xMax; x++)
            {
                for (int y = bounds.yMin; y < bounds.yMax; y++)
                {
                    Vector3Int cellPosition = new Vector3Int(x, y, 0);
                    TileBase tile = buildSlotMap.GetTile(cellPosition);

                    if (tile != null)
                    {
                        Vector3 worldPosition = buildSlotMap.CellToWorld(cellPosition);
                        worldPosition += new Vector3(0.5f, 0.5f, 0);

                        GameObject slotObj = Instantiate(towerSlotPrefab, worldPosition, Quaternion.identity);
                        slotObj.name = $"TowerSlot_{x}_{y}";

                        Tower.TowerSlot slot = slotObj.GetComponent<Tower.TowerSlot>();
                        if (slot != null)
                        {
                            towerSlots.Add(slot);
                        }
                    }
                }
            }

            Debug.Log($"Generated {towerSlots.Count} tower slots");
        }

        private void InitializePaths()
        {
            if (pathMap == null) return;

            List<Vector3> waypoints = new List<Vector3>();

            BoundsInt bounds = pathMap.cellBounds;
            TileBase[] allTiles = pathMap.GetTilesBlock(bounds);

            for (int x = bounds.xMin; x < bounds.xMax; x++)
            {
                for (int y = bounds.yMin; y < bounds.yMax; y++)
                {
                    Vector3Int cellPosition = new Vector3Int(x, y, 0);
                    TileBase tile = pathMap.GetTile(cellPosition);

                    if (tile != null)
                    {
                        Vector3 worldPosition = pathMap.CellToWorld(cellPosition);
                        worldPosition += new Vector3(0.5f, 0.5f, 0);
                        waypoints.Add(worldPosition);
                    }
                }
            }

            Debug.Log($"Found {waypoints.Count} path points");
        }

        public List<Tower.TowerSlot> GetTowerSlots()
        {
            return towerSlots;
        }

        public void ClearMap()
        {
            foreach (var slot in towerSlots)
            {
                if (slot != null && slot.CurrentTower != null)
                {
                    slot.SellTower();
                }
            }

            towerSlots.Clear();
        }

        private void OnDrawGizmos()
        {
            if (buildSlotMap != null)
            {
                Gizmos.color = Color.green;
                BoundsInt bounds = buildSlotMap.cellBounds;
                Gizmos.DrawWireCube(bounds.center, bounds.size);
            }

            if (pathMap != null)
            {
                Gizmos.color = Color.red;
                BoundsInt bounds = pathMap.cellBounds;
                Gizmos.DrawWireCube(bounds.center, bounds.size);
            }
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using UnityEngine;
using UnityEngine.Tilemaps;
using TowerDefense.Data;
using TowerDefense.Utils;

namespace TowerDefense.Map
{
    public class LevelBuilder : MonoBehaviour
    {
        [Header("Tilemaps")]
        [SerializeField] private Tilemap groundMap;
        [SerializeField] private Tilemap pathMap;
        [SerializeField] private Tilemap buildSlotMap;
        [SerializeField] private Tilemap decorationMap;

        [Header("Tile Assets")]
        [SerializeField] private TileBase grassTile;
        [SerializeField] private TileBase pathTile;
        [SerializeField] private TileBase buildSlotTile;
        [SerializeField] private TileBase decoStoneTile;
        [SerializeField] private TileBase decoGrassTile1;
        [SerializeField] private TileBase decoGrassTile2;
        [SerializeField] private TileBase decoGrassTile3;

        [Header("Path Tiles (Auto-selected)")]
        [SerializeField] private TileBase pathHorizontalTop;
        [SerializeField] private TileBase pathHorizontalBottom;
        [SerializeField] private TileBase pathVerticalLeft;
        [SerializeField] private TileBase pathVerticalRight;
        [SerializeField] private TileBase pathCornerTopRight;
        [SerializeField] private TileBase pathCornerTopLeft;
        [SerializeField] private TileBase pathCornerBottomRight;
        [SerializeField] private TileBase pathCornerBottomLeft;

        [Header("Prefabs")]
        [SerializeField] private GameObject towerSlotPrefab;

        private List<Tower.TowerSlot> _towerSlots = new List<Tower.TowerSlot>();
        private Vector3Int _startCell;
        private Vector3Int _endCell;

        /// <summary>各分支的路径格子集合（'1'→index 0, '2'→index 1...）</summary>
        private List<HashSet<Vector3Int>> _branchCells = new List<HashSet<Vector3Int>>();

        public List<Tower.TowerSlot> TowerSlots => _towerSlots;
        public Vector3Int StartCell => _startCell;
        public Vector3Int EndCell => _endCell;

        // 判断字符是否为路径类格子（P/S/E/1/2/3...）
        private static bool IsPathChar(char c)
        {
            return c == 'P' || c == 'S' || c == 'E' || (c >= '1' && c <= '9');
        }

        // 判断字符是否为分支路径（1/2/3...）
        private static bool IsBranchChar(char c)
        {
            return c >= '1' && c <= '9';
        }

        // 获取分支索引（'1'→0, '2'→1, ...）
        private static int BranchIndex(char c)
        {
            return c - '1';
        }

        public void BuildLevel(LevelData levelData)
        {
            if (levelData?.mapRows == null || levelData.mapRows.Length == 0)
            {
                Debug.LogError("LevelData has no map rows!");
                return;
            }

            ClearAll();

            int height = levelData.mapRows.Length;
            int width = levelData.mapRows[0].Length;

            var pathCells = new HashSet<Vector3Int>();
            var buildCells = new HashSet<Vector3Int>();
            var decoCells = new HashSet<Vector3Int>();
            _branchCells = new List<HashSet<Vector3Int>>();

            // First pass: collect all cell positions
            for (int row = 0; row < height; row++)
            {
                string line = levelData.mapRows[row];
                for (int col = 0; col < Mathf.Min(line.Length, width); col++)
                {
                    char c = line[col];
                    var cell = new Vector3Int(col, height - 1 - row, 0);

                    if (IsPathChar(c))
                    {
                        pathCells.Add(cell);
                        if (c == 'S') _startCell = cell;
                        if (c == 'E') _endCell = cell;

                        // 记录分支格子
                        if (IsBranchChar(c))
                        {
                            int idx = BranchIndex(c);
                            while (_branchCells.Count <= idx)
                                _branchCells.Add(new HashSet<Vector3Int>());
                            _branchCells[idx].Add(cell);
                        }
                    }
                    else if (c == 'B') buildCells.Add(cell);
                    else if (c == 'D') decoCells.Add(cell);
                }
            }

            // Second pass: paint tiles
            for (int row = 0; row < height; row++)
            {
                string line = levelData.mapRows[row];
                for (int col = 0; col < Mathf.Min(line.Length, width); col++)
                {
                    char c = line[col];
                    var cell = new Vector3Int(col, height - 1 - row, 0);

                    if (c != '.') groundMap.SetTile(cell, grassTile);

                    if (IsPathChar(c))
                        pathMap.SetTile(cell, SelectPathTile(cell, pathCells));
                    else if (c == 'B')
                        buildSlotMap.SetTile(cell, buildSlotTile);
                    else if (c == 'D')
                        decorationMap.SetTile(cell, PickRandomDeco());
                }
            }

            GenerateTowerSlots();
            UpdatePathCreators();

            int branchCount = _branchCells.Count;
            Debug.Log($"Level '{levelData.levelName}' built: {width}x{height}, " +
                      $"path={pathCells.Count}, build={buildCells.Count}, deco={decoCells.Count}, branches={branchCount}");
        }

        // ─── PathCreator 管理 ─────────────────────────────────

        private const string PATH_CREATOR_PARENT = "路径";

        /// <summary>
        /// 根据分支数量，更新场景中的 PathCreator。
        /// 复用已有的 PathCreator（不销毁），只更新路径点。
        /// 如果 PathCreator 已有手动设置的路径点，则不覆盖。
        /// </summary>
        private void UpdatePathCreators()
        {
            var existing = FindObjectsOfType<PathCreator>().ToList();

            if (_branchCells.Count == 0)
            {
                // 无分支：单路径
                var waypoints = GetPathWaypoints(null);
                EnsurePathCreator(existing, 0, "路径", waypoints);
            }
            else
            {
                // 有分支：每个分支一条路径
                for (int i = 0; i < _branchCells.Count; i++)
                {
                    var waypoints = GetPathWaypoints(_branchCells[i]);
                    string name = _branchCells.Count == 1 ? "路径" : $"路径_{i + 1}路";
                    EnsurePathCreator(existing, i, name, waypoints);
                }
            }

            // 清理多余 PathCreator（只删自动创建的，不删用户手动的）
            var allAfter = FindObjectsOfType<PathCreator>();
            int expected = _branchCells.Count > 0 ? _branchCells.Count : 1;
            if (allAfter.Length > expected + 1) // +1 容差
            {
                for (int i = expected; i < allAfter.Length; i++)
                {
                    if (allAfter[i] != null)
                    {
                        Debug.Log($"[LevelBuilder] 清理多余 PathCreator: {allAfter[i].gameObject.name}");
                        Destroy(allAfter[i].gameObject);
                    }
                }
            }
        }

        /// <summary>
        /// 确保指定索引的 PathCreator 存在并更新路径点。
        /// 复用已有对象，不销毁重建（保持引用不断裂）。
        /// </summary>
        private void EnsurePathCreator(List<PathCreator> existing, int index, string objectName, List<Vector3> waypoints)
        {
            // 按名字或索引找已有的 PathCreator
            PathCreator pc = null;

            // 先按名字找
            foreach (var e in existing)
            {
                if (e != null && (e.gameObject.name == objectName || e.gameObject.name == "路径"))
                {
                    pc = e;
                    break;
                }
            }

            // 按索引找
            if (pc == null && index < existing.Count)
                pc = existing[index];

            // 都没有，创建新的
            if (pc == null)
            {
                var parent = FindOrCreatePathParent();
                var go = new GameObject(objectName);
                go.transform.SetParent(parent.transform, false);
                pc = go.AddComponent<PathCreator>();
            }

            // 更新路径点：如果自动追踪到了有效路径就覆盖，否则保留已有数据
            if (waypoints.Count > 0)
            {
                pc.ClearPath();
                foreach (var wp in waypoints)
                    pc.AddWaypoint(wp);
                Debug.Log($"[LevelBuilder] PathCreator '{pc.gameObject.name}' 已更新: {waypoints.Count} 个路径点");
            }
            else if (pc.WaypointCount == 0)
            {
                Debug.LogWarning($"[LevelBuilder] PathCreator '{pc.gameObject.name}' 无自动路径点，也无手动路径点！");
            }
            else
            {
                Debug.Log($"[LevelBuilder] PathCreator '{pc.gameObject.name}' 自动追踪失败，保留现有 {pc.WaypointCount} 个路径点");
            }
        }

        private GameObject FindOrCreatePathParent()
        {
            var parent = GameObject.Find(PATH_CREATOR_PARENT);
            if (parent == null) parent = GameObject.Find("路径");
            if (parent == null) parent = new GameObject(PATH_CREATOR_PARENT);
            return parent;
        }

        // ─── 路径追踪 ──────────────────────────────────────────

        /// <summary>
        /// 从 Tilemap 追踪路径拐点。
        /// branchCells 为 null 时，走所有路径格（P+S+E+所有分支）；
        /// 不为 null 时，走共享路径格（P+S+E）+ 指定分支格。
        /// </summary>
        public List<Vector3> GetPathWaypoints(HashSet<Vector3Int> branchCells)
        {
            var waypoints = new List<Vector3>();
            if (pathMap == null) return waypoints;

            // 收集所有路径格
            var allPathCells = new HashSet<Vector3Int>();
            BoundsInt bounds = pathMap.cellBounds;
            for (int x = bounds.xMin; x < bounds.xMax; x++)
            for (int y = bounds.yMin; y < bounds.yMax; y++)
            {
                var c = new Vector3Int(x, y, 0);
                if (pathMap.GetTile(c) != null) allPathCells.Add(c);
            }

            if (allPathCells.Count == 0) return waypoints;

            // 构建当前分支可走的格子集合
            HashSet<Vector3Int> walkable;
            if (branchCells == null || branchCells.Count == 0)
            {
                walkable = allPathCells;
            }
            else
            {
                // 共享格（P/S/E）+ 当前分支格
                walkable = new HashSet<Vector3Int>();
                // 找出共享格：属于所有分支都不独占的格子
                var allBranchCells = new HashSet<Vector3Int>();
                foreach (var bc in _branchCells)
                    allBranchCells.UnionWith(bc);

                foreach (var cell in allPathCells)
                {
                    if (!allBranchCells.Contains(cell) || branchCells.Contains(cell))
                        walkable.Add(cell);
                }
            }

            Vector3Int start = _startCell;
            Vector3Int end = _endCell;

            if (!walkable.Contains(start) || !walkable.Contains(end)) return waypoints;

            // BFS
            var prev = new Dictionary<Vector3Int, Vector3Int>();
            var queue = new Queue<Vector3Int>();
            var visited = new HashSet<Vector3Int>();
            queue.Enqueue(start);
            visited.Add(start);
            prev[start] = start;

            while (queue.Count > 0)
            {
                var cur = queue.Dequeue();
                if (cur == end) break;
                foreach (var dir in new[] { Vector3Int.right, Vector3Int.up, Vector3Int.left, Vector3Int.down })
                {
                    var nb = cur + dir;
                    if (walkable.Contains(nb) && !visited.Contains(nb))
                    {
                        visited.Add(nb);
                        prev[nb] = cur;
                        queue.Enqueue(nb);
                    }
                }
            }

            if (!prev.ContainsKey(end)) return waypoints;

            var path = new List<Vector3Int>();
            var node = end;
            while (node != start) { path.Add(node); node = prev[node]; }
            path.Add(start);
            path.Reverse();

            // 简化：只保留拐点
            var simplified = new List<Vector3Int> { path[0] };
            for (int i = 1; i < path.Count - 1; i++)
            {
                if (path[i] - path[i - 1] != path[i + 1] - path[i])
                    simplified.Add(path[i]);
            }
            simplified.Add(path[path.Count - 1]);

            foreach (var cell in simplified)
                waypoints.Add(pathMap.CellToWorld(cell) + new Vector3(0.5f, 0.5f, 0));

            return waypoints;
        }

        // ─── Tile 选择 ──────────────────────────────────────────

        private TileBase SelectPathTile(Vector3Int cell, HashSet<Vector3Int> pathCells)
        {
            bool up = pathCells.Contains(cell + Vector3Int.up);
            bool down = pathCells.Contains(cell + Vector3Int.down);
            bool left = pathCells.Contains(cell + Vector3Int.left);
            bool right = pathCells.Contains(cell + Vector3Int.right);

            bool upLeft = pathCells.Contains(cell + Vector3Int.up + Vector3Int.left);
            bool upRight = pathCells.Contains(cell + Vector3Int.up + Vector3Int.right);
            bool downLeft = pathCells.Contains(cell + Vector3Int.down + Vector3Int.left);
            bool downRight = pathCells.Contains(cell + Vector3Int.down + Vector3Int.right);

            bool upIsParallel = up && upLeft && upRight;
            bool downIsParallel = down && downLeft && downRight;
            bool leftIsParallel = left && upLeft && downLeft;
            bool rightIsParallel = right && upRight && downRight;

            if (left && right)
            {
                if (upIsParallel) return pathHorizontalBottom;
                if (downIsParallel) return pathHorizontalTop;
                if (up && !down) return pathHorizontalBottom;
                if (down && !up) return pathHorizontalTop;
                if (!downRight && upLeft) return pathCornerBottomRight;
                if (!downLeft && upRight) return pathCornerBottomLeft;
                if (!upRight && downLeft) return pathCornerTopRight;
                if (!upLeft && downRight) return pathCornerTopLeft;
                return up ? pathHorizontalBottom : pathHorizontalTop;
            }

            if (up && down)
            {
                if (rightIsParallel) return pathVerticalLeft;
                if (leftIsParallel) return pathVerticalRight;
                if (right && !left) return pathVerticalLeft;
                if (left && !right) return pathVerticalRight;
                if (!downRight && upLeft) return pathCornerBottomRight;
                if (!downLeft && upRight) return pathCornerBottomLeft;
                if (!upRight && downLeft) return pathCornerTopRight;
                if (!upLeft && downRight) return pathCornerTopLeft;
                return right ? pathVerticalLeft : pathVerticalRight;
            }

            if (up && right && !down && !left) return pathCornerBottomLeft;
            if (up && left && !down && !right) return pathCornerBottomRight;
            if (down && right && !up && !left) return pathCornerTopLeft;
            if (down && left && !up && !right) return pathCornerTopRight;

            if (left || right) return up ? pathHorizontalBottom : pathHorizontalTop;
            if (up || down) return right ? pathVerticalLeft : pathVerticalRight;

            return pathTile;
        }

        private TileBase PickRandomDeco()
        {
            float r = Random.value;
            if (r < 0.4f) return decoGrassTile1;
            if (r < 0.7f) return decoGrassTile2;
            if (r < 0.9f) return decoGrassTile3;
            return decoStoneTile;
        }

        // ─── 建造槽 ──────────────────────────────────────────

        private void GenerateTowerSlots()
        {
            if (buildSlotMap == null || towerSlotPrefab == null) return;

            _towerSlots.Clear();

            Transform buildSlotsParent = null;
            var existingParent = GameObject.Find("建造槽");
            if (existingParent == null) existingParent = GameObject.Find("BuildSlots");
            if (existingParent != null)
            {
                for (int i = existingParent.transform.childCount - 1; i >= 0; i--)
                    DestroyImmediate(existingParent.transform.GetChild(i).gameObject);
                buildSlotsParent = existingParent.transform;
            }

            BoundsInt bounds = buildSlotMap.cellBounds;
            for (int x = bounds.xMin; x < bounds.xMax; x++)
            {
                for (int y = bounds.yMin; y < bounds.yMax; y++)
                {
                    Vector3Int cellPosition = new Vector3Int(x, y, 0);
                    if (buildSlotMap.GetTile(cellPosition) == null) continue;

                    Vector3 worldPosition = buildSlotMap.CellToWorld(cellPosition) + new Vector3(0.5f, 0.5f, 0);
                    GameObject slotObj = Instantiate(towerSlotPrefab, worldPosition, Quaternion.identity);
                    slotObj.name = $"TowerSlot_{x}_{y}";
                    if (buildSlotsParent != null) slotObj.transform.SetParent(buildSlotsParent, true);

                    Tower.TowerSlot slot = slotObj.GetComponent<Tower.TowerSlot>();
                    if (slot != null) _towerSlots.Add(slot);
                }
            }
            Debug.Log($"Generated {_towerSlots.Count} tower slots");
        }

        // ─── 清理 ──────────────────────────────────────────

        public void ClearAll()
        {
            // 清除场景中所有已放置的塔
            foreach (var tower in FindObjectsOfType<Tower.Tower>())
            {
                if (tower != null) Destroy(tower.gameObject);
            }

            foreach (var slot in _towerSlots) { if (slot != null) Destroy(slot.gameObject); }
            _towerSlots.Clear();

            var buildSlotsObj = GameObject.Find("建造槽");
            if (buildSlotsObj == null) buildSlotsObj = GameObject.Find("BuildSlots");
            if (buildSlotsObj != null)
            {
                for (int i = buildSlotsObj.transform.childCount - 1; i >= 0; i--)
                    DestroyImmediate(buildSlotsObj.transform.GetChild(i).gameObject);
            }

            groundMap?.ClearAllTiles();
            pathMap?.ClearAllTiles();
            buildSlotMap?.ClearAllTiles();
            decorationMap?.ClearAllTiles();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace TowerDefense.Core
{
    public static class EventBus
    {
        private static readonly Dictionary<Type, Delegate> _events = new Dictionary<Type, Delegate>();

        public static void Subscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Combine(_events[eventType], callback);
            }
            else
            {
                _events[eventType] = callback;
            }
        }

        public static void Unsubscribe<T>(Action<T> callback) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                _events[eventType] = Delegate.Remove(_events[eventType], callback);
            }
        }

        public static void Publish<T>(T eventData) where T : struct
        {
            Type eventType = typeof(T);
            if (_events.ContainsKey(eventType))
            {
                (_events[eventType] as Action<T>)?.Invoke(eventData);
            }
        }

        public static void Clear()
        {
            _events.Clear();
        }
    }

    #region Event Data Structures

    public struct GameStartEvent { }
    public struct GamePauseEvent { public bool IsPaused; }
    public struct GameOverEvent { public bool IsVictory; }
    public struct WaveStartEvent { public int WaveIndex; }
    public struct WaveEndEvent { public int WaveIndex; }
    public struct EnemySpawnEvent { public GameObject Enemy; }
    public struct EnemyDeathEvent { public GameObject Enemy; public int Reward; }
    public struct EnemyReachEndEvent { public GameObject Enemy; public int Damage; }
    public struct TowerPlacedEvent { public GameObject Tower; public int Cost; }
    public struct TowerUpgradedEvent { public GameObject Tower; public int Level; }
    public struct TowerSoldEvent { public GameObject Tower; public int Refund; }
    public struct GoldChangedEvent { public int CurrentGold; public int Change; }
    public struct LifeChangedEvent { public int CurrentLife; public int Change; }
    public struct SkillUsedEvent { public string SkillName; }
    public struct ExpChangedEvent { public int Level; public int CurrentExp; public int ExpToNext; }
    public struct LevelUpEvent { public int OldLevel; public int NewLevel; }
    public struct TreeChoppedEvent { public Vector3 TreePosition; public int WoodAmount; public int GoldAmount; }

    #endregion
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections.Generic;
using System.Linq;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class AchievementPanel : MonoBehaviour
    {
        [Header("Panel")]
        [SerializeField] private GameObject _panel;
        [SerializeField] private Button _closeButton;

        [Header("Header")]
        [SerializeField] private Text _titleText;
        [SerializeField] private Text _totalCountText;
        [SerializeField] private Slider _totalProgressSlider;
        [SerializeField] private Text _totalPercentText;

        [Header("Milestones")]
        [SerializeField] private Transform _milestoneContainer;
        [SerializeField] private GameObject _milestonePrefab;

        [Header("Tabs")]
        [SerializeField] private Button _tabAll;
        [SerializeField] private Button _tabGrowth;
        [SerializeField] private Button _tabBattle;
        [SerializeField] private Button _tabCollection;
        [SerializeField] private Button _tabExploration;
        [SerializeField] private Button _tabFun;
        [SerializeField] private Color _tabActiveColor = new Color(0.45f, 0.75f, 0.3f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.95f, 0.93f, 0.85f, 1f);

        [Header("Content")]
        [SerializeField] private Transform _itemContainer;
        [SerializeField] private GameObject _achievementItemPrefab;

        [Header("Claim All")]
        [SerializeField] private Button _claimAllButton;

        [Header("Data")]
        [SerializeField] private string _jsonPath = "Data/Achievements";

        private AchievementData _data;
        private bool _isOpen;
        private AchievementCategory _currentCategory = AchievementCategory.All;
        private List<GameObject> _spawnedItems = new List<GameObject>();
        private Dictionary<AchievementCategory, Button> _tabButtons = new Dictionary<AchievementCategory, Button>();
        private GameObject _torchRoot;
        private MovingClouds _clouds;
        private ParticleSystem _snowParticles;
        private int _snowOriginalSortOrder;

        private void Awake()
        {
            _tabButtons[AchievementCategory.All] = _tabAll;
            _tabButtons[AchievementCategory.Growth] = _tabGrowth;
            _tabButtons[AchievementCategory.Battle] = _tabBattle;
            _tabButtons[AchievementCategory.Collection] = _tabCollection;
            _tabButtons[AchievementCategory.Exploration] = _tabExploration;
            _tabButtons[AchievementCategory.Fun] = _tabFun;

            if (_closeButton != null)
                _closeButton.onClick.AddListener(ClosePanel);

            if (_claimAllButton != null)
                _claimAllButton.onClick.AddListener(ClaimAll);

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var cat = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(cat));
                }
            }

            _torchRoot = GameObject.Find("火把");
            GameObject bgObj = GameObject.Find("背景");
            if (bgObj != null)
            {
                _clouds = bgObj.GetComponent<MovingClouds>();
                _snowParticles = bgObj.GetComponentInChildren<ParticleSystem>();
                if (_snowParticles != null)
                {
                    var renderer = _snowParticles.GetComponent<ParticleSystemRenderer>();
                    if (renderer != null)
                        _snowOriginalSortOrder = renderer.sortingOrder;
                }
            }

            LoadData();
        }

        private void Start()
        {
            // 首次启动时隐藏面板，但避免在 OpenPanel 调用后误关
            if (_panel != null && !_isOpen)
                _panel.SetActive(false);
        }

        private void LoadData()
        {
            var jsonFile = Resources.Load<TextAsset>(_jsonPath);
            if (jsonFile != null)
            {
                _data = JsonUtility.FromJson<AchievementData>(jsonFile.text);
                Debug.Log($"[AchievementPanel] Loaded {_data.items.Length} achievements");
            }
            else
            {
                Debug.LogError($"[AchievementPanel] Failed to load: Resources/{_jsonPath}");
                _data = new AchievementData { items = new AchievementItemData[0] };
            }
        }

        public void OpenPanel()
        {
            _isOpen = true;
            if (_panel != null)
                _panel.SetActive(true);

            if (_torchRoot != null) _torchRoot.SetActive(false);
            if (_clouds != null) _clouds.IsPaused = true;
            if (_snowParticles != null)
            {
                var r = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (r != null) r.sortingOrder = -10;
                _snowParticles.Pause(true);
            }

            LoadData();
            UpdateHeader();
            SwitchTab(AchievementCategory.All);
        }

        public void ClosePanel()
        {
            _isOpen = false;
            if (_panel != null)
                _panel.SetActive(false);

            if (_torchRoot != null) _torchRoot.SetActive(true);
            if (_clouds != null) _clouds.IsPaused = false;
            if (_snowParticles != null)
            {
                var r = _snowParticles.GetComponent<ParticleSystemRenderer>();
                if (r != null) r.sortingOrder = _snowOriginalSortOrder;
                _snowParticles.Play(true);
            }
        }

        private void SwitchTab(AchievementCategory category)
        {
            _currentCategory = category;
            UpdateTabVisuals();
            RefreshItemList();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var colors = kvp.Value.colors;
                colors.normalColor = kvp.Key == _currentCategory ? _tabActiveColor : _tabInactiveColor;
                colors.selectedColor = colors.normalColor;
                colors.highlightedColor = kvp.Key == _currentCategory
                    ? _tabActiveColor
                    : new Color(0.85f, 0.83f, 0.75f, 1f);
                kvp.Value.colors = colors;
            }
        }

        private void UpdateHeader()
        {
            if (_data == null) return;

            int total = _data.items.Length;
            int completed = _data.items.Count(i => i.status == AchievementStatus.Claimed);
            float pct = total > 0 ? (float)completed / total : 0f;

            if (_totalCountText != null)
                _totalCountText.text = $"{completed}/{total}";

            if (_totalProgressSlider != null)
            {
                _totalProgressSlider.maxValue = total;
                _totalProgressSlider.value = completed;
            }

            if (_totalPercentText != null)
                _totalPercentText.text = $"{(int)(pct * 100)}%";

            // 一键领取按钮
            if (_claimAllButton != null)
            {
                bool hasClaimable = _data.items.Any(i => i.status == AchievementStatus.Claimable);
                _claimAllButton.interactable = hasClaimable;
            }
        }

        private void RefreshItemList()
        {
            foreach (var item in _spawnedItems)
            {
                if (item != null) DestroyImmediate(item);
            }
            _spawnedItems.Clear();

            if (_itemContainer == null || _achievementItemPrefab == null) return;

            var items = _data.items
                .Where(i => _currentCategory == AchievementCategory.All || i.category == _currentCategory)
                .OrderBy(i => (int)i.status)
                .ThenBy(i => i.sortIndex);

            foreach (var itemData in items)
            {
                GameObject itemObj = Instantiate(_achievementItemPrefab, _itemContainer);
                itemObj.SetActive(true);
                _spawnedItems.Add(itemObj);

                var ui = itemObj.GetComponent<AchievementItemUI>();
                if (ui != null)
                    ui.Setup(itemData, this);
            }
        }

        public void OnClaimClicked(AchievementItemData itemData)
        {
            if (itemData.status != AchievementStatus.Claimable) return;

            var wallet = PlayerWallet.Instance;
            if (wallet == null) return;

            GrantRewards(itemData.rewards);

            itemData.status = AchievementStatus.Claimed;
            Debug.Log($"[AchievementPanel] 领取: {itemData.name}");

            UpdateHeader();
            RefreshItemList();
        }

        private void ClaimAll()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet == null) return;

            var claimable = _data.items.Where(i => i.status == AchievementStatus.Claimable).ToList();
            if (claimable.Count == 0) return;

            foreach (var item in claimable)
            {
                GrantRewards(item.rewards);
                item.status = AchievementStatus.Claimed;
            }

            Debug.Log($"[AchievementPanel] 一键领取 {claimable.Count} 个成就");
            UpdateHeader();
            RefreshItemList();
        }

        private void GrantRewards(AchievementReward[] rewards)
        {
            if (rewards == null) return;
            var wallet = PlayerWallet.Instance;
            foreach (var r in rewards)
            {
                switch (r.rewardType)
                {
                    case RewardType.Gold: wallet?.AddGold(r.amount); break;
                    case RewardType.Diamond: wallet?.AddDiamond(r.amount); break;
                    case RewardType.Stamina: wallet?.AddStamina(r.amount); break;
                    case RewardType.Exp: PlayerLevelSystem.Instance?.AddExp(r.amount); break;
                }
            }
        }

        public void UpdateAchievementProgress(int id, int currentCount)
        {
            if (_data == null) return;
            var item = _data.items.FirstOrDefault(i => i.id == id);
            if (item == null) return;

            item.currentCount = currentCount;
            if (item.currentCount >= item.targetCount && item.status == AchievementStatus.InProgress)
            {
                item.status = AchievementStatus.Claimable;
                Debug.Log($"[AchievementPanel] 成就可领取: {item.name}");
            }
        }

        public static string GetCategoryName(AchievementCategory cat)
        {
            return cat switch
            {
                AchievementCategory.All => "全部",
                AchievementCategory.Growth => "成长",
                AchievementCategory.Battle => "战斗",
                AchievementCategory.Collection => "收集",
                AchievementCategory.Exploration => "探索",
                AchievementCategory.Fun => "趣味",
                _ => "未知"
            };
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Enemy;

namespace TowerDefense.Skill
{
    public enum SkillTargetType
    {
        Self,
        Enemy,
        Area,
        Direction
    }

    public abstract class SkillBase : ScriptableObject
    {
        [Header("Skill Info")]
        public string skillName;
        public string description;
        public Sprite icon;
        public int maxLevel = 5;

        [Header("Cooldown & Cost")]
        public float cooldown = 10f;
        public int manaCost = 0;
        public int goldCost = 0;

        [Header("Targeting")]
        public SkillTargetType targetType = SkillTargetType.Area;
        public float range = 5f;
        public float radius = 2f;

        [Header("Effects")]
        public GameObject effectPrefab;
        public AudioClip soundEffect;

        protected int _currentLevel = 1;

        public int CurrentLevel => _currentLevel;

        public virtual bool CanUse(GameObject user)
        {
            if (goldCost > 0 && !GameManager.Instance.HasEnoughGold(goldCost))
            {
                return false;
            }
            return true;
        }

        public virtual void Use(GameObject user, Vector3 targetPosition)
        {
            if (!CanUse(user)) return;

            if (goldCost > 0)
            {
                GameManager.Instance.SpendGold(goldCost);
            }

            Execute(user, targetPosition);
            PlayEffects(targetPosition);

            EventBus.Publish(new SkillUsedEvent { SkillName = skillName });
        }

        protected abstract void Execute(GameObject user, Vector3 targetPosition);

        protected virtual void PlayEffects(Vector3 position)
        {
            if (effectPrefab != null)
            {
                Instantiate(effectPrefab, position, Quaternion.identity);
            }

            if (soundEffect != null)
            {
                AudioSource.PlayClipAtPoint(soundEffect, position);
            }
        }

        public virtual void Upgrade()
        {
            if (_currentLevel < maxLevel)
            {
                _currentLevel++;
            }
        }

        protected List<Enemy.Enemy> GetEnemiesInRadius(Vector3 center, float radius)
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return new List<Enemy.Enemy>();

            return spawner.GetEnemiesInRange(center, radius);
        }
    }
}

using UnityEngine;
using TowerDefense.Enemy;

namespace TowerDefense.Skill
{
    [CreateAssetMenu(fileName = "MeteorSkill", menuName = "TowerDefense/Skills/Meteor")]
    public class MeteorSkill : SkillBase
    {
        [Header("Meteor Settings")]
        public float baseDamage = 100f;
        public float damagePerLevel = 20f;
        public float stunDuration = 1f;
        public int meteorCount = 3;

        protected override void Execute(GameObject user, Vector3 targetPosition)
        {
            float totalDamage = baseDamage + (damagePerLevel * (_currentLevel - 1));

            var enemies = GetEnemiesInRadius(targetPosition, radius);

            foreach (var enemy in enemies)
            {
                if (enemy != null && !enemy.IsDead)
                {
                    // 在第25行修复
                   enemy.TakeDamage(Mathf.RoundToInt(totalDamage), DamageType.Explosion);

                    if (stunDuration > 0)
                    {
                        enemy.ApplyStun(stunDuration);
                    }
                }
            }
        }
    }
}

using UnityEngine;
using TowerDefense.Enemy;

namespace TowerDefense.Skill
{
    [CreateAssetMenu(fileName = "FreezeSkill", menuName = "TowerDefense/Skills/Freeze")]
    public class FreezeSkill : SkillBase
    {
        [Header("Freeze Settings")]
        public float slowAmount = 0.5f;
        public float baseDuration = 3f;
        public float durationPerLevel = 0.5f;

        protected override void Execute(GameObject user, Vector3 targetPosition)
        {
            float duration = baseDuration + (durationPerLevel * (_currentLevel - 1));

            var enemies = GetEnemiesInRadius(targetPosition, radius);

            foreach (var enemy in enemies)
