        Claimed     // 已领取
    }

    [System.Serializable]
    public class AchievementReward
    {
        public RewardType rewardType;
        public int amount;
    }

    [System.Serializable]
    public class AchievementItemData
    {
        public int id;
        public string name;
        public string description;
        public AchievementCategory category;
        public string iconColorHex;        // 图标背景色 (#RRGGBB)
        public string iconSymbol;          // 图标符号 (emoji 或文字)
        public int targetCount;            // 目标数量
        public int currentCount;           // 当前进度
        public AchievementStatus status;
        public AchievementReward[] rewards;
        public int sortIndex;              // 排序权重
    }

    [System.Serializable]
    public class AchievementData
    {
        public AchievementItemData[] items;
        public int[] milestoneThresholds;  // 里程碑节点 (如 [5, 10, 20, 32])
        public AchievementReward[] milestoneRewards; // 里程碑奖励
    }
}

using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Map;

namespace TowerDefense.Core
{
    public enum GameState
    {
        Menu,
        Playing,
        Paused,
        GameOver,
        Victory
    }

    public class GameManager : Singleton<GameManager>
    {
        [Header("Level Config")]
        [SerializeField] private LevelData[] _levels;
        [SerializeField] private LevelBuilder _levelBuilder;

        [Header("Game Settings")]
        [SerializeField] private int _initialGold = 500;
        [SerializeField] private int _initialLife = 20;
        [SerializeField] private float _gameSpeed = 1f;

        [Header("Debug")]
        [SerializeField] private bool _debugMode = false;
        [Tooltip("直接从第 N 关开始（0=第一关, 1=第二关...）。优化调试用，上线前改回 0")]
        [SerializeField] private int _debugStartLevel = 0;

        private LevelData _currentLevelData;
        private int _currentLevelIndex = -1;

        private GameState _currentState = GameState.Menu;
        private int _currentGold;
        private int _currentLife;
        private int _currentWave = 0;
        private int _totalWaves = 0;
        private int _enemiesKilled = 0;
        private float _gameTime = 0f;

        /// <summary>是否以模块模式运行</summary>
        private bool _isModuleMode;

        public GameState CurrentState => _currentState;
        public int CurrentGold => _currentGold;
        public int CurrentLife => _currentLife;
        public int CurrentWave => _currentWave;
        public int TotalWaves => _totalWaves;
        public int EnemiesKilled => _enemiesKilled;
        public float GameTime => _gameTime;
        public float GameSpeed => _gameSpeed;
        public bool IsPlaying => _currentState == GameState.Playing;
        public bool IsModuleMode => _isModuleMode;

        public System.Action<GameState> OnStateChanged;
        public System.Action<int> OnGoldChanged;
        public System.Action<int> OnLifeChanged;
        public System.Action<int> OnWaveChanged;

        protected override void Awake()
        {
            // 检测模块模式：通过场景名或全局标志判断
            _isModuleMode = ModuleModeDetector.IsModuleMode;

            if (_isModuleMode)
            {
                // 模块模式下不使用 DontDestroyOnLoad
                // 单例实例存在但不跨场景持久化
                // 使用 base.Instance 静态属性检测重复实例
                var existingInstance = FindObjectOfType<GameManager>();
                if (existingInstance != null && existingInstance != this)
                {
                    Destroy(gameObject);
                    return;
                }
                // 不调用 base.Awake()，避免 DontDestroyOnLoad
            }
            else
            {
                base.Awake();
            }

            InitializeGame();
        }

        public LevelData CurrentLevelData => _currentLevelData;
        public LevelData[] Levels => _levels;
        public int CurrentLevelIndex => _currentLevelIndex;

        private void Start()
        {
            string sceneName = UnityEngine.SceneManagement.SceneManager.GetActiveScene().name;
            if (sceneName == "GameScene" || sceneName == "TDGameScene")
            {
                int startLevel = Mathf.Clamp(_debugStartLevel, 0, _levels != null ? _levels.Length - 1 : 0);
                LoadLevel(startLevel);
            }
        }

        public void LoadLevel(int levelIndex)
        {
            if (_levels == null || levelIndex < 0 || levelIndex >= _levels.Length)
            {
                Debug.LogError($"Invalid level index: {levelIndex}");
                return;
            }

            _currentLevelIndex = levelIndex;
            _currentLevelData = _levels[levelIndex];
            _initialGold = _currentLevelData.initialGold;
            _initialLife = _currentLevelData.initialLife;
            InitializeGame();

            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = 0 });
            OnLifeChanged?.Invoke(_currentLife);

            if (_levelBuilder != null)
            {
                _levelBuilder.BuildLevel(_currentLevelData);
            }

            StartGame(_currentLevelData.waves.Count > 0 ? _currentLevelData.waves.Count : _currentLevelData.waveCount);
        }

        private void InitializeGame()
        {
            _currentGold = _initialGold;
            _currentLife = _initialLife;
            _currentState = GameState.Menu;
            _currentWave = 0;
            _enemiesKilled = 0;
            _gameTime = 0f;

            if (Wave.WaveManager.Instance != null)
            {
                Wave.WaveManager.Instance.Reset();
            }
        }

        private void Update()
        {
            if (_currentState == GameState.Playing)
            {
                _gameTime += Time.deltaTime * _gameSpeed;
            }

            if (_debugMode)
            {
                HandleDebugInput();
            }
        }

        public void StartGame(int totalWaves)
        {
            _totalWaves = totalWaves;
            _currentState = GameState.Playing;
            _gameTime = 0f;
            Time.timeScale = _gameSpeed;
            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameStartEvent());
        }

        public void PauseGame()
        {
            if (_currentState == GameState.Playing)
            {
                _currentState = GameState.Paused;
                Time.timeScale = 0f;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = true });
            }
        }

        public void ResumeGame()
        {
            if (_currentState == GameState.Paused)
            {
                _currentState = GameState.Playing;
                Time.timeScale = _gameSpeed;
                OnStateChanged?.Invoke(_currentState);
                EventBus.Publish(new GamePauseEvent { IsPaused = false });
            }
        }

        public void TogglePause()
        {
            if (_currentState == GameState.Playing)
            {
                PauseGame();
            }
            else if (_currentState == GameState.Paused)
            {
                ResumeGame();
            }
        }

        public void GameOver(bool isVictory)
        {
            _currentState = isVictory ? GameState.Victory : GameState.GameOver;
            Time.timeScale = 0f;

            // 持久化玩家等级数据
            Data.PlayerLevelSystem.Instance?.PersistToSave();

            OnStateChanged?.Invoke(_currentState);
            EventBus.Publish(new GameOverEvent { IsVictory = isVictory });

            if (isVictory)
            {
                Data.PlayerLevelSystem.Instance?.AddExp(50 + _currentWave * 10);

                // Add gold reward to PlayerWallet (TD-specific gold)
                var wallet = Data.PlayerWallet.Instance;
                if (wallet != null)
                {
                    int goldReward = _currentWave * 20;
                    wallet.AddGold(goldReward);
                }
            }
            Data.PlayerLevelSystem.Instance?.PersistToSave();

            // 模块模式下发布 MiniGameCompletedEvent
            if (_isModuleMode)
            {
                Sttop5.Shared.Core.GlobalEventBus.Publish(new Sttop5.Shared.Core.MiniGameCompletedEvent
                {
                    ModuleId = "towerdefense",
                    IsVictory = isVictory,
                    StarsEarned = isVictory ? CalculateStars() : 0,
                    GoldReward = isVictory ? _currentWave * 20 : 0,
                    ExpReward = isVictory ? 50 + _currentWave * 10 : 0
                });
            }
        }

        private int CalculateStars()
        {
            float lifeRatio = (float)_currentLife / _initialLife;
            if (lifeRatio >= 0.7f) return 3;
            if (lifeRatio >= 0.4f) return 2;
            return 1;
        }

        public void OnVictory()
        {
            GameOver(true);
        }

        public void RestartGame()
        {
            InitializeGame();
            Time.timeScale = 1f;

            if (_isModuleMode)
            {
                // 模块模式下重载 TDGameScene
                var sceneLoader = Sttop5.Shared.Core.SceneLoader.Instance;
                if (sceneLoader != null)
                {
                    sceneLoader.UnloadScene("TDGameScene", () =>
                    {
                        sceneLoader.LoadSceneAdditive("TDGameScene");
                    });
                }
                else
                {
                    UnityEngine.SceneManagement.SceneManager.LoadScene(
                        UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
                    );
                }
            }
            else
            {
                UnityEngine.SceneManagement.SceneManager.LoadScene(
                    UnityEngine.SceneManagement.SceneManager.GetActiveScene().name
                );
            }
        }

        /// <summary>
        /// 返回家园（模块模式下使用）。
        /// </summary>
        public void ReturnToHome()
        {
            if (_isModuleMode)
            {
                Time.timeScale = 1f;
                Sttop5.Shared.Core.ModuleManager.Instance.DeactivateCurrentModule();
            }
            else
            {
                UnityEngine.SceneManagement.SceneManager.LoadScene("MainMenu");
            }
        }

        #region Gold Management

        public bool HasEnoughGold(int amount)
        {
            return _currentGold >= amount;
        }

        public void AddGold(int amount)
        {
            if (amount <= 0) return;
            _currentGold += amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = amount });
        }

        public bool SpendGold(int amount)
        {
            if (!HasEnoughGold(amount)) return false;
            _currentGold -= amount;
            OnGoldChanged?.Invoke(_currentGold);
            EventBus.Publish(new GoldChangedEvent { CurrentGold = _currentGold, Change = -amount });
            return true;
        }

        #endregion

        #region Life Management

        public void TakeDamage(int damage)
        {
            _currentLife -= damage;
            if (_currentLife < 0) _currentLife = 0;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = -damage });

            if (_currentLife <= 0)
            {
                GameOver(false);
            }
        }

        public void Heal(int amount)
        {
            _currentLife += amount;
            OnLifeChanged?.Invoke(_currentLife);
            EventBus.Publish(new LifeChangedEvent { CurrentLife = _currentLife, Change = amount });
        }

        #endregion

        #region Wave Management

        public void SetCurrentWave(int wave)
        {
            _currentWave = wave;
            OnWaveChanged?.Invoke(_currentWave);
        }

        public void IncrementWave()
        {
            _currentWave++;
            OnWaveChanged?.Invoke(_currentWave);
        }

        #endregion

        #region Statistics

        public void AddKill()
        {
            _enemiesKilled++;
            Data.PlayerLevelSystem.Instance?.AddExp(5);
        }

        #endregion

        #region Debug

        private void HandleDebugInput()
        {
            if (Input.GetKeyDown(KeyCode.F1))
            {
                AddGold(100);
                Debug.Log($"[Debug] Added 100 gold. Current: {_currentGold}");
            }
            if (Input.GetKeyDown(KeyCode.F2))
            {
                _currentLife = _initialLife;
                OnLifeChanged?.Invoke(_currentLife);
                Debug.Log($"[Debug] Life restored to {_currentLife}");
            }
            if (Input.GetKeyDown(KeyCode.F3))
            {
                _gameSpeed = _gameSpeed >= 3f ? 1f : _gameSpeed + 0.5f;
                if (_currentState == GameState.Playing)
                {
                    Time.timeScale = _gameSpeed;
                }
                Debug.Log($"[Debug] Game speed: {_gameSpeed}x");
            }
        }

        #endregion
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public enum TowerState
    {
        Idle,
        Targeting,
        Attacking,
        Upgrading,
        Selling
    }

    public class Tower : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] protected TowerData _towerData;
        [SerializeField] protected TowerAttack _attack;
        [SerializeField] protected Animator _animator;
        [SerializeField] protected Transform _rotatePart;
        [SerializeField] protected SpriteRenderer _spriteRenderer;

        [Header("Visual")]
        [SerializeField] protected GameObject _rangeIndicator;
        [SerializeField] protected Color _rangeColor = new Color(0, 1, 0, 0.3f);
        [Tooltip("Rotation offset in degrees. Default -90 assumes sprite faces UP. Change to 0 if sprite faces RIGHT.")]
        [SerializeField] protected float _rotationOffset = -90f;

        protected int _currentLevel = 1;
        protected TowerState _currentState = TowerState.Idle;
        protected TowerData.TowerStats _currentStats;
        protected Enemy.Enemy _currentTarget;
        protected TowerSlot _slot;

        public TowerData Data => _towerData;
        public int CurrentLevel => _currentLevel;
        public TowerState State => _currentState;
        public Enemy.Enemy CurrentTarget => _currentTarget;
        public TowerData.TowerStats CurrentStats => _currentStats;
        public TowerSlot Slot => _slot;
        public bool IsMaxLevel => _currentLevel >= _towerData.levels.Length;

        public System.Action<Tower> OnUpgrade;
        public System.Action<Tower> OnSell;
        public System.Action<Enemy.Enemy> OnTargetAcquired;
        public System.Action OnTargetLost;

        protected virtual void Awake()
        {
            if (_attack == null) _attack = GetComponent<TowerAttack>();
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
        }

        public virtual void Initialize(TowerData data, TowerSlot slot)
        {
            _towerData = data;
            _slot = slot;
            _currentLevel = 1;
            _currentStats = data.levels[0];
            _currentState = TowerState.Idle;

            if (_attack != null)
            {
                _attack.Initialize(this);
            }

            UpdateRangeIndicator();
        }

        protected virtual void Update()
        {
            if (_currentState == TowerState.Upgrading || _currentState == TowerState.Selling)
                return;

            FindTarget();

            if (_currentTarget != null)
            {
                RotateTowardsTarget();
                Attack();
            }
        }

        protected virtual void FindTarget()
        {
            float actualAttackRange = _attack != null ? _attack.GetEffectiveAttackRange() : _currentStats.attackRange;

            if (_currentTarget != null && !_currentTarget.IsDead)
            {
                float distance = Vector3.Distance(transform.position, _currentTarget.transform.position);
                if (distance <= actualAttackRange)
                {
                    return;
                }
            }

            _currentTarget = FindBestTarget();

            if (_currentTarget != null)
            {
                _currentState = TowerState.Targeting;
                OnTargetAcquired?.Invoke(_currentTarget);
            }
            else
            {
                _currentState = TowerState.Idle;
                OnTargetLost?.Invoke();
            }
        }

        protected virtual Enemy.Enemy FindBestTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null)
            {
                Debug.LogError("EnemySpawner not found!");
                return null;
            }

            float actualAttackRange = _attack != null ? _attack.GetEffectiveAttackRange() : _currentStats.attackRange;
            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, actualAttackRange);

            if (enemiesInRange.Count == 0) return null;

            Enemy.Enemy bestTarget = null;
            float bestPriority = float.MinValue;

            foreach (var enemy in enemiesInRange)
            {
                if (enemy == null || enemy.IsDead) continue;

                float priority = CalculateTargetPriority(enemy);
                if (priority > bestPriority)
                {
                    bestPriority = priority;
                    bestTarget = enemy;
                }
            }

            return bestTarget;
        }

        protected virtual float CalculateTargetPriority(Enemy.Enemy enemy)
        {
            EnemyMovement movement = enemy.GetComponent<EnemyMovement>();
            if (movement != null)
            {
                return movement.GetProgressPercent();
            }
            return 0f;
        }

        protected virtual void RotateTowardsTarget()
        {
            if (_currentTarget == null) return;
            if (_towerData != null && (_towerData.towerType == TowerType.Barracks || _towerData.towerType == TowerType.Mage)) return;

            Transform rotateTransform = GetRotateTransform();
            if (rotateTransform == null) return;

            Vector3 direction = _currentTarget.transform.position - rotateTransform.position;
            float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg + _rotationOffset;
            Quaternion targetRotation = Quaternion.AngleAxis(angle, Vector3.forward);
            rotateTransform.rotation = Quaternion.Slerp(rotateTransform.rotation, targetRotation, 10f * Time.deltaTime);
        }

        /// <summary>
        /// Returns the transform that should rotate towards the target.
        /// Uses _rotatePart if it has a visual (renderer in children), 
        /// otherwise falls back to the sprite renderer's transform.
        /// </summary>
        protected Transform GetRotateTransform()
        {
            if (_rotatePart != null)
            {
                if (_rotatePart.GetComponent<Renderer>() != null || _rotatePart.GetComponentInChildren<Renderer>() != null)
                    return _rotatePart;
            }

            if (_spriteRenderer != null)
                return _spriteRenderer.transform;

            var sr = GetComponent<SpriteRenderer>();
            if (sr != null)
                return sr.transform;

            return _rotatePart;
        }

        protected virtual void Attack()
        {
            if (_attack == null) return;

            if (_attack.CanAttack())
            {
                _currentState = TowerState.Attacking;
                _attack.Attack(_currentTarget);
            }
        }

        public virtual bool Upgrade()
        {
            if (IsMaxLevel) return false;

            TowerData.TowerStats nextLevelStats = _towerData.levels[_currentLevel];
            if (!GameManager.Instance.SpendGold(nextLevelStats.upgradeCost)) return false;

            _currentLevel++;
            _currentStats = nextLevelStats;

            if (_animator != null)
            {
                _animator.SetTrigger("Upgrade");
            }

            UpdateRangeIndicator();
            OnUpgrade?.Invoke(this);
            EventBus.Publish(new TowerUpgradedEvent { Tower = gameObject, Level = _currentLevel });

            return true;
        }

        public virtual void Sell()
        {
            Debug.Log($"📤 Tower.Sell() called for {gameObject.name}");
            Debug.Log($"   sellValue: {_currentStats.sellValue}");
            Debug.Log($"   _slot: {_slot != null}");

            int sellValue = _currentStats.sellValue;
            GameManager.Instance.AddGold(sellValue);
            Debug.Log($"   ✅ Added {sellValue} gold");

            OnSell?.Invoke(this);
            EventBus.Publish(new TowerSoldEvent { Tower = gameObject, Refund = sellValue });

            if (_slot != null)
            {
                _slot.RemoveTower();
                Debug.Log($"   ✅ Called _slot.RemoveTower()");
            }

            Destroy(gameObject);
            Debug.Log($"   ✅ Tower destroyed");
        }

        public int GetUpgradeCost()
        {
            if (IsMaxLevel) return 0;
            return _towerData.levels[_currentLevel].upgradeCost;
        }

        public int GetSellValue()
        {
            return _currentStats.sellValue;
        }

        public void ShowRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(true);
            }
        }

        public void HideRange()
        {
            if (_rangeIndicator != null)
            {
                _rangeIndicator.SetActive(false);
            }
        }

        protected void UpdateRangeIndicator()
        {
            if (_rangeIndicator != null)
            {
                float scale = _currentStats.attackRange * 2f;
                _rangeIndicator.transform.localScale = new Vector3(scale, scale, 1f);
            }
        }

        private void OnDrawGizmosSelected()
        {
            if (_towerData != null && _currentStats.attackRange > 0)
            {
                Gizmos.color = _rangeColor;
                Gizmos.DrawWireSphere(transform.position, _currentStats.attackRange);
            }
        }
    }
}

using System.Collections;
using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public class TowerAttack : MonoBehaviour
    {
        [Header("Attack Settings")]
        [SerializeField] private Transform _firePoint;
        [SerializeField] private bool _autoFire = true;

        protected Transform FirePoint => _firePoint;

        protected Tower _tower;
        protected float _attackCooldown = 0f;
        protected bool _canAttack = true;

        public bool CanAttackValue => _canAttack && _attackCooldown <= 0f;

        public virtual void Initialize(Tower tower)
        {
            _tower = tower;
            _attackCooldown = 0f;
        }

        protected virtual void Update()
        {
            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        public virtual bool CanAttack()
        {
            return _attackCooldown <= 0f && _tower.CurrentTarget != null;
        }

        /// <summary>
        /// Returns the effective attack range for targeting purposes.
        /// Projectile towers use their stats range; barracks use soldier engage range.
        /// </summary>
        public virtual float GetEffectiveAttackRange()
        {
            return _tower != null ? _tower.CurrentStats.attackRange : 0f;
        }

        public virtual void Attack(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;

            TowerData.TowerStats stats = _tower.CurrentStats;

            switch (_tower.Data.towerType)
            {
                case TowerType.Archer:
                    FireProjectile(target);
                    break;
                case TowerType.Mage:
                    FireMagicAttack(target);
                    break;
                case TowerType.Barracks:
                    SpawnSoldiers(target);
                    break;
                case TowerType.Artillery:
                    FireExplosive(target);
                    break;
                case TowerType.Sword:
                    FirePierceProjectile(target);
                    break;
            }

            // Barracks don't use cooldown - soldiers continuously auto-assign
            if (_tower.Data.towerType != TowerType.Barracks)
            {
                _attackCooldown = 1f / stats.attackSpeed;
            }

            if (_tower.GetComponent<Animator>() != null)
            {
                _tower.GetComponent<Animator>().SetTrigger("Attack");
            }
        }

        protected virtual void FireProjectile(Enemy.Enemy target)
        {
            Debug.Log($"FireProjectile called");
            Debug.Log($"Projectile prefab: " + _tower.Data.projectilePrefab);
            Debug.Log($"FirePoint: " + _firePoint);

            if (_tower.Data.projectilePrefab == null || _firePoint == null)
            {
                if (_tower.Data.projectilePrefab == null)
                {
                    Debug.LogError("Projectile prefab is null!");
                }
                return;
            }

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, _tower.CurrentStats.damage, DamageType.Physical);
            }
        }

        protected virtual void FireMagicAttack(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, _tower.CurrentStats.damage, DamageType.Magic);
            }
        }

        protected virtual void FireExplosive(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(
                    target,
                    _tower.CurrentStats.damage,
                    DamageType.Explosion,
                    _tower.CurrentStats.splashRadius,
                    0,
                    _tower.CurrentStats.maxSplashTargets
                );
            }
        }

        protected virtual void SpawnSoldiers(Enemy.Enemy target)
        {
        }

        protected virtual void FirePierceProjectile(Enemy.Enemy target)
        {
            if (_tower.Data.projectilePrefab == null || _firePoint == null) return;

            TowerData.TowerStats stats = _tower.CurrentStats;

            int pierceCount = stats.pierceCount;
            if (pierceCount <= 0)
            {
                int towerLevel = _tower.CurrentLevel;
                pierceCount = towerLevel switch
                {
                    1 => 3,
                    2 => 5,
                    3 => 7,
                    _ => 3
                };
            }

            GameObject projectileObj = Instantiate(
                _tower.Data.projectilePrefab,
                _firePoint.position,
                Quaternion.identity
            );

            Projectile projectile = projectileObj.GetComponent<Projectile>();
            if (projectile != null)
            {
                projectile.Initialize(target, stats.damage, DamageType.Physical, 0f, pierceCount);
            }
        }

        public void SetFirePoint(Transform firePoint)
        {
            _firePoint = firePoint;
        }
    }
}

using System.Collections;
using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;
using TowerDefense.Utils;

namespace TowerDefense.Tower
{
    public class BarracksAttack : TowerAttack
    {
        [Header("Barracks Settings")]
        [SerializeField] private SoldierData _soldierData;
        [SerializeField] private float _spawnRadius = 0.5f;

        [Header("Rally Point")]
        [SerializeField] private Transform _rallyPoint;
        [SerializeField] private float _rallyPointRange = 3f;
        [SerializeField] private GameObject _rallyPointMarker;
        [SerializeField] private bool _rallyPointDraggable = true;

        private List<Soldier> _soldiers = new List<Soldier>();
        private int _maxSoldiers = 3;
        private bool _soldiersSpawned = false;

        public List<Soldier> Soldiers => _soldiers;
        public Transform RallyPoint => _rallyPoint;
        public float RallyPointRange => _rallyPointRange;

        public int AliveSoldierCount
        {
            get
            {
                int count = 0;
                foreach (var s in _soldiers)
                    if (s != null && s.IsAlive) count++;
                return count;
            }
        }

        public override void Initialize(Tower tower)
        {
            base.Initialize(tower);

            // Determine max soldiers from tower data
            if (_tower.Data != null && _tower.Data.soldierCountPerLevel != null
                && _tower.Data.soldierCountPerLevel.Length > 0)
            {
                int levelIndex = Mathf.Clamp(_tower.CurrentLevel - 1, 0, _tower.Data.soldierCountPerLevel.Length - 1);
                _maxSoldiers = _tower.Data.soldierCountPerLevel[levelIndex];
            }
            else
            {
                _maxSoldiers = _tower.CurrentLevel switch
                {
                    1 => 3,
                    2 => 5,
                    3 => 7,
                    _ => 3
                };
            }

            if (_soldierData == null && _tower.Data != null)
                _soldierData = _tower.Data.soldierData;

            SetupRallyPoint();
        }

        /// <summary>
        /// Setup the rally point. If not assigned, find the closest point on the enemy path.
        /// In Kingdom Rush, soldiers stand at the rally point and engage enemies from there.
        /// </summary>
        private void SetupRallyPoint()
        {
            // Create rally point object if not assigned
            if (_rallyPoint == null)
            {
                var rallyObj = new GameObject("RallyPoint");
                rallyObj.transform.SetParent(transform);
                rallyObj.transform.position = FindDefaultRallyPosition();
                _rallyPoint = rallyObj.transform;
            }

            // Create visual marker
            if (_rallyPointMarker == null)
            {
                _rallyPointMarker = CreateRallyPointMarker();
            }

            _rallyPointMarker.transform.SetParent(_rallyPoint);
            _rallyPointMarker.transform.localPosition = Vector3.zero;
            _rallyPointMarker.SetActive(true);
        }

        /// <summary>
        /// Find the default rally position: closest point on the enemy path to the tower.
        /// This is the Kingdom Rush behavior — soldiers rally near the path, not at the tower.
        /// </summary>
        private Vector3 FindDefaultRallyPosition()
        {
            var pathCreator = FindObjectOfType<PathCreator>();
            if (pathCreator != null && pathCreator.WaypointCount > 0)
            {
                Vector3 closestPoint = Vector3.zero;
                float closestDist = float.MaxValue;

                // Check interpolated path points for closest to tower
                var smoothPath = pathCreator.GetSmoothPath(20);
                foreach (var pathPoint in smoothPath)
                {
                    float dist = Vector3.Distance(transform.position, pathPoint);
                    if (dist < closestDist)
                    {
                        closestDist = dist;
                        closestPoint = pathPoint;
                    }
                }

                // Offset slightly off-path so soldiers aren't standing ON the path
                Vector3 awayFromPath = (transform.position - closestPoint).normalized;
                if (awayFromPath == Vector3.zero) awayFromPath = Vector3.up;
                closestPoint += awayFromPath * 0.8f;

                return closestPoint;
            }

            // Fallback: just offset from tower towards path center
            return transform.position + Vector3.right * _rallyPointRange * 0.7f;
        }

        private GameObject CreateRallyPointMarker()
        {
            var marker = new GameObject("RallyPointMarker");
            var sr = marker.AddComponent<SpriteRenderer>();
            sr.sprite = CreateCircleSprite();
            sr.color = new Color(1f, 0.8f, 0f, 0.4f);
            sr.sortingOrder = -1;
            marker.transform.localScale = new Vector3(_rallyPointRange * 2f, _rallyPointRange * 2f, 1f);
            return marker;
        }

        private Sprite CreateCircleSprite()
        {
            int size = 64;
            var tex = new Texture2D(size, size);
            var center = new Vector2(size / 2f, size / 2f);
            float radius = size / 2f - 2f;

            for (int y = 0; y < size; y++)
            {
                for (int x = 0; x < size; x++)
                {
                    float dist = Vector2.Distance(new Vector2(x, y), center);
                    if (dist > radius - 1f && dist < radius + 1f)
                        tex.SetPixel(x, y, Color.white);
                    else
                        tex.SetPixel(x, y, Color.clear);
                }
            }
            tex.Apply();
            return Sprite.Create(tex, new Rect(0, 0, size, size), new Vector2(0.5f, 0.5f));
        }

        /// <summary>
        /// Move rally point to a new position (called by drag handler).
        /// Clamped within tower's attack range.
        /// </summary>
        public void MoveRallyPoint(Vector3 newPosition)
        {
            // Clamp to within attack range of tower
            float maxDist = GetEffectiveAttackRange();
            Vector3 dir = newPosition - transform.position;
            if (dir.magnitude > maxDist)
            {
                newPosition = transform.position + dir.normalized * maxDist;
            }

            _rallyPoint.position = newPosition;

            // Move idle soldiers to new rally point
            foreach (var soldier in _soldiers)
            {
                if (soldier != null && soldier.IsAlive && soldier.State == SoldierState.Idle)
                {
                    soldier.SetRallyPoint(_rallyPoint);
                }
            }
        }

        protected override void Update()
        {
            base.Update();
            AutoAssignTargets();
        }

        public override void Attack(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;

            if (!_soldiersSpawned)
            {
                SpawnAllSoldiers();
                _soldiersSpawned = true;
            }

            AssignTarget(target);
        }

        protected override void SpawnSoldiers(Enemy.Enemy target)
        {
            if (_soldierData == null || _soldierData.soldierPrefab == null)
            {
                Debug.LogWarning("BarracksAttack: SoldierData or prefab is null!");
                return;
            }

            if (!_soldiersSpawned)
            {
                SpawnAllSoldiers();
                _soldiersSpawned = true;
            }

            AssignTarget(target);
        }

        private void SpawnAllSoldiers()
        {
            ClearDeadSoldiers();

            int toSpawn = _maxSoldiers - _soldiers.Count;
            Vector3 basePos = _rallyPoint != null ? _rallyPoint.position : transform.position;

            for (int i = 0; i < toSpawn; i++)
            {
                float angle = (2f * Mathf.PI * i) / _maxSoldiers;
                Vector3 offset = new Vector3(
                    Mathf.Cos(angle) * _spawnRadius,
                    Mathf.Sin(angle) * _spawnRadius,
                    0f
                );
                Vector3 spawnPos = basePos + offset;

                GameObject soldierObj = Instantiate(_soldierData.soldierPrefab, spawnPos, Quaternion.identity);
                // Don't parent under tower — non-uniform parent scale breaks child positioning

                Soldier soldier = soldierObj.GetComponent<Soldier>();
                if (soldier == null)
                {
                    soldier = soldierObj.AddComponent<Soldier>();
                }

                soldier.Initialize(_soldierData, _rallyPoint);
                soldier.OnSoldierDeath += OnSoldierDeath;
                _soldiers.Add(soldier);
            }

            Debug.Log($"Barracks spawned {toSpawn} soldiers at rally point (total: {_soldiers.Count})");
        }

        private void AssignTarget(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;

            foreach (var soldier in _soldiers)
            {
                if (soldier != null && soldier.IsAlive && soldier.State == SoldierState.Idle)
                {
                    soldier.EngageTarget(target);
                }
            }
        }

        /// <summary>
        /// Auto-assign idle soldiers to enemies within rally point range.
        /// In Kingdom Rush, soldiers detect enemies from their rally point, not the tower.
        /// </summary>
        private void AutoAssignTargets()
        {
            if (_tower == null) return;

            List<Soldier> idleSoldiers = new List<Soldier>();
            foreach (var s in _soldiers)
            {
                if (s != null && s.IsAlive && s.State == SoldierState.Idle)
                    idleSoldiers.Add(s);
            }

            if (idleSoldiers.Count == 0) return;

            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            // Search from rally point, not tower position
            Vector3 searchOrigin = _rallyPoint != null ? _rallyPoint.position : transform.position;
            float searchRange = _soldierData != null ? _soldierData.engageRange : 3f;
            var enemiesInRange = spawner.GetEnemiesInRange(searchOrigin, searchRange);

            foreach (var soldier in idleSoldiers)
            {
                Enemy.Enemy bestTarget = null;
                float bestDist = float.MaxValue;

                foreach (var enemy in enemiesInRange)
                {
                    if (enemy == null || enemy.IsDead) continue;

                    float dist = Vector3.Distance(soldier.transform.position, enemy.transform.position);
                    if (dist < bestDist)
                    {
                        bestDist = dist;
                        bestTarget = enemy;
                    }
                }

                if (bestTarget != null)
                {
                    soldier.EngageTarget(bestTarget);
                }
            }
        }

        private void OnSoldierDeath(Soldier soldier)
        {
            soldier.OnSoldierDeath -= OnSoldierDeath;
            StartCoroutine(RespawnSoldierAfterDelay(soldier, _soldierData.respawnTime));
        }

        private IEnumerator RespawnSoldierAfterDelay(Soldier soldier, float delay)
        {
            yield return new WaitForSeconds(delay);

            if (soldier != null && _tower != null)
            {
                Vector3 basePos = _rallyPoint != null ? _rallyPoint.position : transform.position;
                float angle = Random.Range(0f, 2f * Mathf.PI);
                Vector3 offset = new Vector3(
                    Mathf.Cos(angle) * _spawnRadius,
                    Mathf.Sin(angle) * _spawnRadius,
                    0f
                );
                soldier.Respawn(basePos + offset);
                soldier.SetRallyPoint(_rallyPoint);
                soldier.OnSoldierDeath += OnSoldierDeath;
                Debug.Log("Barracks soldier respawned at rally point");
            }
        }

        private void ClearDeadSoldiers()
        {
            for (int i = _soldiers.Count - 1; i >= 0; i--)
            {
                if (_soldiers[i] == null)
                {
                    _soldiers.RemoveAt(i);
                }
            }
        }

        public override bool CanAttack()
        {
            return !_soldiersSpawned || AliveSoldierCount > 0;
        }

        public override float GetEffectiveAttackRange()
        {
            return _soldierData != null ? _soldierData.engageRange : 3f;
        }

        private void OnDestroy()
        {
            foreach (var soldier in _soldiers)
            {
                if (soldier != null)
                {
                    soldier.OnSoldierDeath -= OnSoldierDeath;
                    Destroy(soldier.gameObject);
                }
            }
            _soldiers.Clear();
        }

        private void OnDrawGizmosSelected()
        {
            // Draw rally point range
            if (_rallyPoint != null)
            {
                Gizmos.color = new Color(1f, 0.8f, 0f, 0.3f);
                Gizmos.DrawWireSphere(_rallyPoint.position, _rallyPointRange);
            }
        }
    }
}

using UnityEngine;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Tower
{
    public class LightningAttack : TowerAttack
    {
        [Header("Lightning Settings")]
        [SerializeField] private int _segments = 12;
        [SerializeField] private float _arcAmplitude = 0.3f;
        [SerializeField] private float _jitterSpeed = 20f;
        [SerializeField] private float _beamWidth = 0.12f;
        [SerializeField] private float _glowWidth = 0.3f;

        [Header("Colors")]
        [SerializeField] private Color _coreColor = new Color(0.9f, 0.7f, 1f, 1f);
        [SerializeField] private Color _glowColor = new Color(0.5f, 0.1f, 0.9f, 0.6f);

        [Header("Damage Timing")]
        [SerializeField] private float _damageInterval = 0.2f;

        private LineRenderer _coreLine;
        private LineRenderer _glowLine;
        private float _damageTimer;
        private Enemy.Enemy _trackedTarget;
        private bool _isFiring;
        private Vector3[] _linePoints;

        protected override void Update()
        {
            base.Update();

            if (_isFiring)
            {
                float range = _tower != null ? _tower.CurrentStats.attackRange : float.MaxValue;
                bool outOfRange = _trackedTarget != null &&
                    Vector3.Distance(transform.position, _trackedTarget.transform.position) > range;

                if (_trackedTarget == null || _trackedTarget.IsDead || outOfRange)
                {
                    StopLightning();
                    return;
                }

                UpdateLightningVisual();
            }
        }

        public override void Attack(Enemy.Enemy target)
        {
            if (target == null || target.IsDead)
            {
                StopLightning();
                return;
            }

            _trackedTarget = target;

            if (!_isFiring)
            {
                StartLightning();
                _isFiring = true;
                _damageTimer = 0f;
            }

            _damageTimer += Time.deltaTime;
            if (_damageTimer >= _damageInterval)
            {
                _damageTimer = 0f;
                DealDamage(target);
            }
        }

        public override bool CanAttack()
        {
            return _tower != null && _tower.CurrentTarget != null && !_tower.CurrentTarget.IsDead;
        }

        private void DealDamage(Enemy.Enemy target)
        {
            if (target == null || target.IsDead) return;
            float dmg = _tower.CurrentStats.damage;
            target.Health.TakeDamage(Mathf.RoundToInt(dmg), DamageType.Magic);
        }

        private void StartLightning()
        {
            _linePoints = new Vector3[_segments];

            if (_coreLine == null)
            {
                GameObject coreObj = new GameObject("LightningCore");
                coreObj.transform.SetParent(transform);
                coreObj.transform.localPosition = Vector3.zero;
                _coreLine = coreObj.AddComponent<LineRenderer>();
                _coreLine.material = new Material(Shader.Find("Sprites/Default"));
                _coreLine.startColor = _coreColor;
                _coreLine.endColor = _coreColor;
                _coreLine.startWidth = _beamWidth;
                _coreLine.endWidth = _beamWidth;
                _coreLine.positionCount = _segments;
                _coreLine.sortingOrder = 10;
                _coreLine.useWorldSpace = true;
            }

            if (_glowLine == null)
            {
                GameObject glowObj = new GameObject("LightningGlow");
                glowObj.transform.SetParent(transform);
                glowObj.transform.localPosition = Vector3.zero;
                _glowLine = glowObj.AddComponent<LineRenderer>();
                _glowLine.material = new Material(Shader.Find("Sprites/Default"));
                _glowLine.startColor = _glowColor;
                _glowLine.endColor = _glowColor;
                _glowLine.startWidth = _glowWidth;
                _glowLine.endWidth = _glowWidth;
                _glowLine.positionCount = _segments;
                _glowLine.sortingOrder = 9;
                _glowLine.useWorldSpace = true;
            }

            _coreLine.enabled = true;
            _glowLine.enabled = true;
        }

        private void StopLightning()
        {
            _isFiring = false;
            _trackedTarget = null;
            if (_coreLine != null) _coreLine.enabled = false;
            if (_glowLine != null) _glowLine.enabled = false;
        }

        private void UpdateLightningVisual()
        {
            if (_trackedTarget == null || _trackedTarget.IsDead)
            {
                StopLightning();
                return;
            }

            Vector3 start = FirePoint != null ? FirePoint.position : transform.position;
            Vector3 end = _trackedTarget.transform.position;
            Vector3 dir = end - start;

            for (int i = 0; i < _segments; i++)
            {
                float t = (float)i / (_segments - 1);
                Vector3 point = Vector3.Lerp(start, end, t);

                if (i > 0 && i < _segments - 1)
                {
                    Vector3 perpendicular = new Vector3(-dir.y, dir.x, 0).normalized;
                    float noise = Mathf.PerlinNoise(i * 1.7f + Time.time * _jitterSpeed, 0f) - 0.5f;
                    float amplitude = _arcAmplitude * (1f - Mathf.Abs(t - 0.5f) * 2f);
                    point += perpendicular * noise * amplitude * 2f;
                }

                _linePoints[i] = point;
            }

            _coreLine.SetPositions(_linePoints);
            _glowLine.SetPositions(_linePoints);

            _coreLine.startColor = _coreColor;
            _coreLine.endColor = _coreColor;
            _glowLine.startColor = _glowColor;
            _glowLine.endColor = _glowColor;
        }

        private void OnDisable()
        {
            StopLightning();
        }

        private void OnDestroy()
        {
            if (_coreLine != null) Destroy(_coreLine.gameObject);
            if (_glowLine != null) Destroy(_glowLine.gameObject);
        }
    }
}

using System;
using UnityEngine;

namespace TowerDefense.Data
{
    [CreateAssetMenu(fileName = "TowerData", menuName = "TowerDefense/TowerData")]
    public class TowerData : ScriptableObject
    {
        public string towerName;
        public string description;
        public TowerType towerType;
        public GameObject towerPrefab;
        public GameObject projectilePrefab;
        public Sprite icon;
        public TowerStats[] levels;

        [Header("Barracks Settings (only used for Barracks type)")]
        public SoldierData soldierData;
        public int[] soldierCountPerLevel = { 3, 5, 7 };

        [Serializable]
        public struct TowerStats
        {
            public int level;
            public int cost;
            public int upgradeCost;
            public int sellValue;
            public float damage;
            public float attackRange;
            public float attackSpeed;
            public ProjectileType projectileType;
            public int projectileCount;
            public float splashRadius;
            public float slowAmount;
            public float slowDuration;
            public int maxTargets;
            public int maxSplashTargets;
            public int pierceCount;
        }
    }

    public enum TowerType
    {
        Archer,
        Mage,
        Barracks,
        Artillery,
        Sword
    }

    public enum ProjectileType
    {
        Arrow,
        Magic,
        Cannonball,
        None
    }
}

using UnityEngine;
using UnityEngine.UI;
using TowerDefense.Data;
using TowerDefense.Utils;
using TowerDefense.Core;

namespace TowerDefense.Enemy
{
    [RequireComponent(typeof(EnemyMovement), typeof(EnemyHealth))]
    public class Enemy : MonoBehaviour
    {
        [Header("Settings")]
        [SerializeField] private EnemyData _enemyData;

        [Header("Health Bar")]
        [SerializeField] private Slider _healthSlider;
        [SerializeField] private Image _healthFillImage;
        [SerializeField] private Color _lowHealthColor = Color.red;
        [SerializeField] private Color _mediumHealthColor = Color.yellow;
        [SerializeField] private Color _highHealthColor = Color.green;
        [SerializeField] private float _healthBarOffsetY = 1.5f;

        private EnemyMovement _movement;
        private EnemyHealth _health;
        private Canvas _healthCanvas;

        public EnemyData Data => _enemyData;
        public EnemyMovement Movement => _movement;
        public EnemyHealth Health => _health;
        public bool IsDead => _health != null && _health.CurrentHealth <= 0;

        private int _birthWaveId = -1;  // 敌人归属的波次ID

        // 给 EnemySpawner 调用的
        public void SetBirthWaveId(int waveId)
        {
            _birthWaveId = waveId;
        }

        private void Awake()
        {
            _movement = GetComponent<EnemyMovement>();
            _health = GetComponent<EnemyHealth>();

            // 获取血条画布
            if (_healthSlider != null)
            {
                _healthCanvas = _healthSlider.GetComponentInParent<Canvas>();
                _healthSlider.value = 1f;
            }

            if (_enemyData != null)
            {
                Initialize(_enemyData);
            }
        }

        public void Initialize(EnemyData data)
        {
            _enemyData = data;

            if (_health != null)
            {
                _health.Initialize(data.stats.maxHealth, data.stats.goldReward);
                _health.OnHealthChanged += UpdateHealthBar;
                _health.OnDeath += OnDeath;
            }

            if (_movement != null)
            {
                _movement.SetSpeed(data.stats.moveSpeed);
            }

            // 初始化血条
            UpdateHealthBar(data.stats.maxHealth, data.stats.maxHealth);
        }

        public void StartMovement(PathCreator pathCreator)
        {
            if (_movement != null)
            {
                _movement.FollowPath(pathCreator);
            }
        }

        public void OnReachedEnd()
        {
            // 敌人走到终点也统计为波次敌人不再场
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            if (GameManager.Instance != null)
            {
                GameManager.Instance.TakeDamage(_enemyData.stats.lifeDamage);
            }
            EventBus.Publish(new EnemyReachEndEvent { Enemy = gameObject, Damage = _enemyData.stats.lifeDamage });
            Destroy(gameObject);
        }

        public void OnDeath()
        {
            // 波次统计-带上GameObject给HashSet去重
            EnemySpawner.OnEnemyKilled(gameObject, _birthWaveId);

            // 解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }

            // 隐藏血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = false;
            }

            if (GameManager.Instance != null)
            {
                GameManager.Instance.AddGold(_enemyData.stats.goldReward);
                GameManager.Instance.AddKill();
            }
            EventBus.Publish(new EnemyDeathEvent { Enemy = gameObject, Reward = _enemyData.stats.goldReward });
            Destroy(gameObject);
        }

        private void Update()
        {
            // 更新血条位置，始终在敌人头顶
            UpdateHealthBarPosition();
        }

        private void UpdateHealthBar(int currentHealth, int maxHealth)
        {
            if (_healthSlider == null) return;

            float healthPercent = (float)currentHealth / maxHealth;
            _healthSlider.value = healthPercent;

            // 根据血量改变颜色
            UpdateHealthBarColor(healthPercent);

            // 当血量低于最大值时显示血条
            if (_healthCanvas != null)
            {
                _healthCanvas.enabled = healthPercent < 1f;
            }
        }

        private void UpdateHealthBarColor(float healthPercent)
        {
            if (_healthFillImage == null) return;

            if (healthPercent <= 0.3f)
            {
                _healthFillImage.color = _lowHealthColor;
            }
            else if (healthPercent <= 0.6f)
            {
                _healthFillImage.color = _mediumHealthColor;
            }
            else
            {
                _healthFillImage.color = _highHealthColor;
            }
        }

        private void UpdateHealthBarPosition()
        {
            if (_healthSlider == null || _healthCanvas == null) return;

            // 将世界坐标转换为屏幕坐标
            Vector3 worldPosition = transform.position;
            worldPosition.y += _healthBarOffsetY;

            // 如果是世界空间画布，直接设置位置
            if (_healthCanvas.renderMode == RenderMode.WorldSpace)
            {
                _healthSlider.transform.position = worldPosition;
            }
            else
            {
                // 如果是屏幕空间画布，转换坐标
                Vector3 screenPosition = Camera.main.WorldToScreenPoint(worldPosition);
                _healthSlider.transform.position = screenPosition;
            }
        }

        private void OnDestroy()
        {
            // 确保解绑事件
            if (_health != null)
            {
                _health.OnHealthChanged -= UpdateHealthBar;
                _health.OnDeath -= OnDeath;
            }
        }

        public void TakeDamage(int damage)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage);
            }
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            if (_health != null)
            {
                _health.TakeDamage(damage, damageType);
            }
        }

        public void ApplySlow(float slowFactor, float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(slowFactor, duration);
            }
        }

        public void ApplyStun(float duration)
        {
            if (_movement != null)
            {
                _movement.Slow(0f, duration);
            }
        }
    }
}

using UnityEngine;
using TowerDefense.Utils;

namespace TowerDefense.Enemy
{
    public class EnemyMovement : MonoBehaviour
    {
        [Header("Movement Settings")]
        [SerializeField] private float _speed = 2f;
        [SerializeField] private float _rotationSpeed = 5f;

        [Header("Rotation Settings")]
        [Tooltip("旋转模式：None=不旋转, FlipX=只左右翻转, Full=全方向旋转")]
        [SerializeField] private RotationMode _rotationMode = RotationMode.Full;

        public enum RotationMode
        {
            None,       
            FlipX,      
            Full        
        }

        private PathCreator _currentPath;
        private int _currentWaypointIndex;
        private Vector3[] _waypoints;
        private bool _isMoving = false;
        private float _currentSpeed = 0f;

        public bool IsMoving => _isMoving;
        public float CurrentSpeed => _currentSpeed;

        private void Update()
        {
            if (_isMoving && _waypoints != null && _waypoints.Length > 0)
            {
                MoveTowardsWaypoint();
            }
        }

        public void FollowPath(PathCreator pathCreator)
        {
            _currentPath = pathCreator;
            _waypoints = pathCreator.Waypoints.ToArray();
            _currentWaypointIndex = 0;
            _isMoving = true;

            if (_waypoints.Length > 0)
            {
                transform.position = _waypoints[0];
            }
        }

        /// <summary>
        /// Resume movement from current position without resetting to path start.
        /// Used when soldiers release blocked enemies.
        /// </summary>
        public void ResumeMovement()
        {
            if (_waypoints != null && _waypoints.Length > 0)
            {
                _isMoving = true;
            }
        }

        private void MoveTowardsWaypoint()
        {
            if (_currentWaypointIndex >= _waypoints.Length)
            {
                _isMoving = false;
                _currentSpeed = 0f;
                SendMessage("OnReachedEnd", SendMessageOptions.DontRequireReceiver);
                return;
            }

            Vector3 target = _waypoints[_currentWaypointIndex];
            target.z = transform.position.z;

            Vector3 direction = (target - transform.position).normalized;
            _currentSpeed = _speed;
            float step = _speed * Time.deltaTime;
            Vector3 newPosition = Vector3.MoveTowards(transform.position, target, step);
            transform.position = newPosition;

            // 根据旋转模式处理朝向
            if (direction.magnitude > 0.01f)
            {
                switch (_rotationMode)
                {
                    case RotationMode.Full:
                        float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg;
                        Quaternion targetRotation = Quaternion.AngleAxis(angle, Vector3.forward);
                        transform.rotation = Quaternion.Lerp(transform.rotation, targetRotation, _rotationSpeed * Time.deltaTime);
                        break;

                    case RotationMode.FlipX:
                        Vector3 localScale = transform.localScale;
                        if (direction.x > 0.01f)
                        {
                            localScale.x = Mathf.Abs(localScale.x);  
                        }
                        else if (direction.x < -0.01f)
                        {
                            localScale.x = -Mathf.Abs(localScale.x); 
                        }
                        transform.localScale = localScale;
                        break;

                    case RotationMode.None:
                    default:
                        break;
                }
            }

            // 检查是否到达当前路径点
            if (Vector3.Distance(transform.position, target) < 0.15f)
            {
                _currentWaypointIndex++;
            }
        }

        public void SetSpeed(float speed)
        {
            _speed = speed;
        }

        public float GetSpeed()
        {
            return _speed;
        }

        public void StopMovement()
        {
            _isMoving = false;
            _currentSpeed = 0f;
        }

        public float GetProgressPercent()
        {
            if (_waypoints == null || _waypoints.Length < 2) return 0f;

            float totalDistance = 0f;
            for (int i = 0; i < _waypoints.Length - 1; i++)
            {
                totalDistance += Vector3.Distance(_waypoints[i], _waypoints[i + 1]);
            }

            float currentDistance = 0f;
            for (int i = 0; i < _currentWaypointIndex; i++)
            {
                currentDistance += Vector3.Distance(_waypoints[i], _waypoints[i + 1]);
            }

            if (_currentWaypointIndex < _waypoints.Length - 1)
            {
                currentDistance += Vector3.Distance(transform.position, _waypoints[_currentWaypointIndex]);
            }

            return Mathf.Clamp01(currentDistance / totalDistance);
        }

        public void Slow(float slowFactor, float duration)
        {
            StartCoroutine(SlowCoroutine(slowFactor, duration));
        }

        private System.Collections.IEnumerator SlowCoroutine(float slowFactor, float duration)
        {
            float originalSpeed = _speed;
            _speed *= slowFactor;

            yield return new WaitForSeconds(duration);

            _speed = originalSpeed;
        }

        private void OnDrawGizmos()
        {
            if (_waypoints != null)
            {
                for (int i = _currentWaypointIndex; i < _waypoints.Length - 1; i++)
                {
                    Gizmos.color = Color.red;
                    Gizmos.DrawLine(_waypoints[i], _waypoints[i + 1]);
                }
            }
        }
    }
}

using UnityEngine;
using UnityEngine.UI;

namespace TowerDefense.Enemy
{
    public class EnemyHealth : MonoBehaviour
    {
        [Header("Health Settings")]
        [SerializeField] private int _maxHealth = 100;
        [SerializeField] private int _goldReward = 10;

        [Header("UI Settings")]
        [SerializeField] private GameObject _healthBarPrefab;
        [SerializeField] private Vector3 _healthBarOffset = new Vector3(0, 1, 0);

        private int _currentHealth;
        private Slider _healthBarSlider;
        private Transform _healthBarTransform;

        public int CurrentHealth => _currentHealth;
        public int MaxHealth => _maxHealth;
        public float HealthPercentage => (float)_currentHealth / _maxHealth;

        public System.Action<int, int> OnHealthChanged;
        public System.Action OnDeath;

        private void Awake()
        {
            _currentHealth = _maxHealth;

            if (_healthBarPrefab != null)
            {
                CreateHealthBar();
            }
        }

        public void Initialize(int maxHealth, int goldReward)
        {
            _maxHealth = maxHealth;
            _currentHealth = maxHealth;
            _goldReward = goldReward;

            if (_healthBarSlider != null)
            {
                _healthBarSlider.maxValue = _maxHealth;
                _healthBarSlider.value = _currentHealth;
            }
        }

        private void CreateHealthBar()
        {
            Canvas canvas = FindObjectOfType<Canvas>();
            if (canvas == null) return;

            GameObject healthBarObj = Instantiate(_healthBarPrefab);
            healthBarObj.transform.SetParent(canvas.transform, false);

            _healthBarTransform = healthBarObj.transform;
            _healthBarSlider = healthBarObj.GetComponentInChildren<Slider>();

            if (_healthBarSlider != null)
            {
                _healthBarSlider.maxValue = _maxHealth;
                _healthBarSlider.value = _currentHealth;
            }
        }

        public void TakeDamage(int damage)
        {
            TakeDamage(damage, DamageType.Physical);
        }

        public void TakeDamage(int damage, DamageType damageType)
        {
            _currentHealth -= damage;
            _currentHealth = Mathf.Max(0, _currentHealth);

            // 触发血量变化事件
            OnHealthChanged?.Invoke(_currentHealth, _maxHealth);

            UpdateHealthBar();

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        private void UpdateHealthBar()
        {
            if (_healthBarTransform != null && _healthBarSlider != null)
            {
                _healthBarSlider.value = _currentHealth;

                Vector3 worldPos = Camera.main.WorldToScreenPoint(transform.position + _healthBarOffset);
                _healthBarTransform.position = worldPos;
            }
        }

        private void Die()
        {
            Destroy(_healthBarTransform?.gameObject);
            // 触发死亡事件
            OnDeath?.Invoke();
            SendMessage("OnDeath", SendMessageOptions.DontRequireReceiver);
        }

        private void OnDestroy()
        {
            Destroy(_healthBarTransform?.gameObject);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using System.Collections;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Enemy;
using TowerDefense.Core;

namespace TowerDefense.Wave
{
    public class WaveManager : MonoBehaviour
    {
        public static WaveManager Instance { get; private set; }

        [Header("Settings")]
        [SerializeField] private EnemySpawner _enemySpawner;
        [SerializeField] private float _waveDelay = 5f;
        [SerializeField] private int _totalWaves = 5;
        [SerializeField] private int _baseEnemyCount = 5;
        [SerializeField] private int _enemyIncreasePerWave = 2;

        [Header("Wave Data (Optional)")]
        [Tooltip("如果设置了这个数组，将使用这里的配置而不是动态生成")]
        [SerializeField] private WaveData[] _waveDatas;

        [Header("Enemy Data")]
        [Tooltip("所有可用的敌人数据（飞机、骷髅等）")]
        [SerializeField] private EnemyData[] _enemyDatas;

        private EnemyData _defaultEnemyData;

        [Header("UI")]
        [SerializeField] private Text _waveText;
        [SerializeField] private Text _enemyCountText;
        [SerializeField] private Text _waveAnnounceText;
        [SerializeField] private float _announceDuration = 2f;

        private int _currentWaveIndex = 0;
        private float _waveTimer = 0f;
        private bool _isWaveActive = false;
        private bool _isWaveTransition = false;

        public int CurrentWave => _currentWaveIndex;
        public int TotalWaves => _totalWaves;
        public bool IsWaveActive => _isWaveActive;

        private void Awake()
        {
            if (Instance == null)
            {
                Instance = this;
            }
            else
            {
                Destroy(gameObject);
            }
        }

        private void Start()
        {
            LoadEnemyData();
            UpdateWaveUI();

            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }

            EventBus.Subscribe<GameStartEvent>(OnGameStart);
        }

        private void LoadEnemyData()
        {
            // 如果在 Inspector 中设置了敌人数据数组，直接使用
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                Debug.Log($"已加载 {_enemyDatas.Length} 个敌人数据");
                foreach (var enemy in _enemyDatas)
                {
                    Debug.Log($"  - {enemy.enemyName}");
                }
                // 使用第一个作为默认
                _defaultEnemyData = _enemyDatas[0];
                return;
            }

            // 否则尝试从 Resources 加载
            _defaultEnemyData = Resources.Load<EnemyData>("Data/EnemyData");
            if (_defaultEnemyData == null)
            {
                Debug.LogError("Failed to load EnemyData from Resources/Data/EnemyData");
            }
        }

        private void OnDestroy()
        {
            EventBus.Unsubscribe<GameStartEvent>(OnGameStart);
        }

        private void OnGameStart(GameStartEvent e)
        {
            ForceStartWave();
        }

        private void Update()
        {
            if (_isWaveTransition && !_isWaveActive)
            {
                _waveTimer += Time.deltaTime;

                float remainingTime = _waveDelay - _waveTimer;

                if (remainingTime > 0)
                {
                    UpdateWaveCountdown((int)Mathf.CeilToInt(remainingTime));
                }

                if (remainingTime % 1f < 0.05f)
                {
                    Debug.Log($"倒计时更新: timer={_waveTimer:F1}/{_waveDelay}, 剩余={remainingTime:F1}s, transition={_isWaveTransition}, active={_isWaveActive}");
                }

                if (_waveTimer >= _waveDelay)
                {
                    Debug.Log($"✅ 倒计时结束, 准备开始下一波!");
                    _waveTimer = 0f;
                    HideWaveCountdown();
                    StartNextWave();
                }
            }

            UpdateEnemyCountDisplay();
        }

        private void UpdateWaveCountdown(int seconds)
        {
            if (_waveAnnounceText != null)
            {
                int nextWave = _currentWaveIndex + 1;
                _waveAnnounceText.text = $"第 {nextWave} 波 {seconds} 秒后出现！";
                _waveAnnounceText.gameObject.SetActive(true);
            }
        }

        private void HideWaveCountdown()
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private void UpdateEnemyCountDisplay()
        {
            if (_enemyCountText != null)
            {
                // 用 EnemySpawner 追踪的波次剩余敌人（出生总数 - 死亡数）
                _enemyCountText.text = $"剩余敌人:{TowerDefense.Enemy.EnemySpawner.RemainingEnemies}";
            }
        }

        public void StartNextWave()
        {
            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log("All waves completed!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
                return;
            }

            // 先增加波次索引
            _currentWaveIndex++;

            WaveData waveData = GetWaveData();
            if (waveData == null)
            {
                Debug.LogError("Failed to get wave data!");
                return;
            }

            _enemySpawner.StartWave(waveData);

            _isWaveActive = true;
            _isWaveTransition = false;

            if (GameManager.Instance != null)
            {
                GameManager.Instance.SetCurrentWave(_currentWaveIndex);
            }

            EventBus.Publish(new WaveStartEvent { WaveIndex = _currentWaveIndex });

            UpdateWaveUI();
            StartCoroutine(ShowWaveAnnouncement(_currentWaveIndex));
            Debug.Log($"Starting wave {_currentWaveIndex}");
        }

        private IEnumerator ShowWaveAnnouncement(int waveNumber)
        {
            if (_waveAnnounceText != null)
            {
                _waveAnnounceText.text = $"第 {waveNumber} 波开始出怪！";
                _waveAnnounceText.gameObject.SetActive(true);

                Debug.Log($"📢 {_waveAnnounceText.text}");

                yield return new WaitForSeconds(_announceDuration);

                _waveAnnounceText.gameObject.SetActive(false);
            }
        }

        private WaveData GetWaveData()
        {
            // 如果用户设置了 WaveData 数组，使用它
            if (_waveDatas != null && _waveDatas.Length > 0)
            {
                int index = _currentWaveIndex - 1;
                if (index >= 0 && index < _waveDatas.Length)
                {
                    Debug.Log($"使用配置的 WaveData: 波次 {_currentWaveIndex}");
                    return _waveDatas[index];
                }
            }

            // 否则动态生成
            if (_defaultEnemyData == null && (_enemyDatas == null || _enemyDatas.Length == 0))
            {
                Debug.LogError("No EnemyData available! Cannot create wave data.");
                return null;
            }

            Debug.Log($"动态生成 WaveData: 波次 {_currentWaveIndex}");
            return CreateWaveData();
        }

        private WaveData CreateWaveData()
        {
            WaveData waveData = ScriptableObject.CreateInstance<WaveData>();
            waveData.waveNumber = _currentWaveIndex;
            waveData.spawnInterval = Mathf.Max(0.5f, 1.5f - (_currentWaveIndex - 1) * 0.1f);
            waveData.enemies = new List<WaveData.WaveEnemy>();

            int totalEnemies = _baseEnemyCount + (_currentWaveIndex - 1) * _enemyIncreasePerWave;

            // 使用多个敌人数据
            if (_enemyDatas != null && _enemyDatas.Length > 0)
            {
                // 随机选择敌人
                for (int i = 0; i < _enemyDatas.Length; i++)
                {
                    int enemyCount = totalEnemies / _enemyDatas.Length;
                    if (i == 0)
                    {
                        enemyCount += totalEnemies % _enemyDatas.Length;
                    }

                    if (enemyCount > 0)
                    {
                        waveData.enemies.Add(new WaveData.WaveEnemy
                        {
                            enemyData = _enemyDatas[i],
                            count = enemyCount,
                            spawnDelay = 0,
                            spawnPoint = "MainPath"
                        });

                        Debug.Log($"波次 {_currentWaveIndex} 添加 {enemyCount} 个 {_enemyDatas[i].enemyName}");
                    }
                }
            }
            else
            {
                // 只有一个敌人数据时使用旧方法
                waveData.enemies.Add(new WaveData.WaveEnemy
                {
                    enemyData = _defaultEnemyData,
                    count = totalEnemies,
                    spawnDelay = 0,
                    spawnPoint = "MainPath"
                });
            }

            return waveData;
        }

        public void OnWaveComplete()
        {
            _isWaveActive = false;

            Debug.Log($"波次 {_currentWaveIndex}/{_totalWaves} 完成!");
            EventBus.Publish(new WaveEndEvent { WaveIndex = _currentWaveIndex });

            if (_currentWaveIndex >= _totalWaves)
            {
                Debug.Log($"全部波次完成!");
                if (GameManager.Instance != null)
                {
                    GameManager.Instance.OnVictory();
                }
            }
            else
            {
                _isWaveTransition = true;
                _waveTimer = 0f;
            }

            UpdateWaveUI();
        }

        public void StartWaveManually(int waveIndex)
        {
            if (waveIndex >= 0 && waveIndex < _totalWaves)
            {
                _currentWaveIndex = waveIndex;
                StartNextWave();
            }
        }

        public void SkipToNextWave()
        {
            if (!_isWaveActive && _currentWaveIndex < _totalWaves)
            {
                StartNextWave();
            }
        }

        public void ForceStartWave()
        {
            if (!_isWaveActive)
            {
                _isWaveTransition = false;
                _waveTimer = 0f;
                StartNextWave();
            }
        }

        private void UpdateWaveUI()
        {
            if (_waveText != null)
            {
                _waveText.text = $"波次:{_currentWaveIndex}/{_totalWaves}";
            }

            UpdateEnemyCountDisplay();
        }

        public void Reset()
        {
            _currentWaveIndex = 0;
            _waveTimer = 0f;
            _isWaveActive = false;
            _isWaveTransition = false;
            UpdateWaveUI();
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;
using TowerDefense.Enemy;

namespace TowerDefense.Hero
{
    public enum HeroState
    {
        Idle,
        Moving,
        Attacking,
        UsingSkill,
        Dead
    }

    public class Hero : MonoBehaviour
    {
        [Header("Data")]
        [SerializeField] private HeroData _heroData;

        [Header("Components")]
        [SerializeField] private Animator _animator;
        [SerializeField] private SpriteRenderer _spriteRenderer;
        [SerializeField] private Transform _healthBarAnchor;

        [Header("Movement")]
        [SerializeField] private float _moveSpeed = 3f;
        [SerializeField] private float _arrivalThreshold = 0.2f;

        private HeroState _currentState = HeroState.Idle;
        private HeroData.HeroStats _currentStats;
        private float _currentHealth;
        private int _currentLevel = 1;
        private float _currentExp = 0f;
        private float _expToNextLevel = 100f;

        private Enemy.Enemy _currentTarget;
        private Vector3 _targetPosition;
        private bool _isMoving = false;
        private float _attackCooldown = 0f;

        private Dictionary<string, float> _skillCooldowns = new Dictionary<string, float>();

        public HeroData Data => _heroData;
        public HeroState State => _currentState;
        public int CurrentLevel => _currentLevel;
        public float CurrentHealth => _currentHealth;
        public float HealthPercent => _currentHealth / _currentStats.maxHealth;
        public float CurrentExp => _currentExp;
        public float ExpPercent => _currentExp / _expToNextLevel;
        public bool IsDead => _currentState == HeroState.Dead;

        public System.Action<Hero> OnLevelUp;
        public System.Action<Hero> OnDeath;
        public System.Action<float> OnHealthChanged;
        public System.Action<float> OnExpChanged;
        public System.Action<string> OnSkillUsed;
        public System.Action<string> OnSkillReady;

        private void Awake()
        {
            if (_animator == null) _animator = GetComponentInChildren<Animator>();
            if (_spriteRenderer == null) _spriteRenderer = GetComponentInChildren<SpriteRenderer>();
        }

        public void Initialize(HeroData data)
        {
            _heroData = data;
            _currentStats = data.baseStats;
            _currentHealth = _currentStats.maxHealth;
            _currentLevel = 1;
            _currentExp = 0f;
            _currentState = HeroState.Idle;

            foreach (var skill in _heroData.skills)
            {
                _skillCooldowns[skill.skillName] = 0f;
            }
        }

        private void Update()
        {
            if (_currentState == HeroState.Dead) return;

            UpdateCooldowns();
            UpdateMovement();
            UpdateAttack();
            UpdateHealthRegen();
        }

        private void UpdateCooldowns()
        {
            List<string> skills = new List<string>(_skillCooldowns.Keys);
            foreach (var skillName in skills)
            {
                if (_skillCooldowns[skillName] > 0)
                {
                    _skillCooldowns[skillName] -= Time.deltaTime;
                    if (_skillCooldowns[skillName] <= 0)
                    {
                        _skillCooldowns[skillName] = 0;
                        OnSkillReady?.Invoke(skillName);
                    }
                }
            }
        }

        private void UpdateMovement()
        {
            if (!_isMoving) return;

            Vector3 direction = (_targetPosition - transform.position).normalized;
            transform.position += direction * _moveSpeed * Time.deltaTime;

            if (_spriteRenderer != null)
            {
                _spriteRenderer.flipX = direction.x < 0;
            }

            float distance = Vector3.Distance(transform.position, _targetPosition);
            if (distance <= _arrivalThreshold)
            {
                _isMoving = false;
                _currentState = HeroState.Idle;

                if (_animator != null)
                {
                    _animator.SetBool("IsMoving", false);
                }
            }
        }

        private void UpdateAttack()
        {
            if (_currentState != HeroState.Idle) return;

            if (_currentTarget == null || _currentTarget.IsDead)
            {
                FindTarget();
            }

            if (_currentTarget != null && _attackCooldown <= 0)
            {
                Attack();
            }

            if (_attackCooldown > 0)
            {
                _attackCooldown -= Time.deltaTime;
            }
        }

        private void UpdateHealthRegen()
        {
            if (_currentStats.healthRegen > 0 && _currentHealth < _currentStats.maxHealth)
            {
                _currentHealth += _currentStats.healthRegen * Time.deltaTime;
                if (_currentHealth > _currentStats.maxHealth)
                {
                    _currentHealth = _currentStats.maxHealth;
                }
                OnHealthChanged?.Invoke(_currentHealth);
            }
        }

        public void MoveTo(Vector3 position)
        {
            _targetPosition = position;
            _isMoving = true;
            _currentState = HeroState.Moving;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", true);
            }
        }

        public void StopMoving()
        {
            _isMoving = false;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsMoving", false);
            }
        }

        private void FindTarget()
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            _currentTarget = spawner.GetClosestEnemy(transform.position, _currentStats.attackRange);
        }

        private void Attack()
        {
            if (_currentTarget == null) return;

            _currentState = HeroState.Attacking;
            _attackCooldown = 1f / _currentStats.attackSpeed;

            if (_animator != null)
            {
                _animator.SetTrigger("Attack");
            }

           // 在第211行和第257行添加转换
            _currentTarget.TakeDamage(Mathf.RoundToInt(_currentStats.attackDamage), DamageType.Physical);

            _currentState = HeroState.Idle;
        }

        public bool UseSkill(int skillIndex)
        {
            if (skillIndex < 0 || skillIndex >= _heroData.skills.Length) return false;

            HeroData.HeroSkill skill = _heroData.skills[skillIndex];

            if (_skillCooldowns[skill.skillName] > 0) return false;

            _skillCooldowns[skill.skillName] = skill.cooldown;
            _currentState = HeroState.UsingSkill;

            if (_animator != null)
            {
                _animator.SetTrigger("Skill");
            }

            ExecuteSkill(skill);

            OnSkillUsed?.Invoke(skill.skillName);
            EventBus.Publish(new SkillUsedEvent { SkillName = skill.skillName });

            _currentState = HeroState.Idle;
            return true;
        }

        private void ExecuteSkill(HeroData.HeroSkill skill)
        {
            if (skill.effectPrefab != null)
            {
                Instantiate(skill.effectPrefab, transform.position, Quaternion.identity);
            }

            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return;

            List<Enemy.Enemy> enemiesInRange = spawner.GetEnemiesInRange(transform.position, skill.effectRadius);

            foreach (var enemy in enemiesInRange)
            {
                if (enemy != null && !enemy.IsDead)
                {
                    // 在第211行和第257行添加转换
enemy.TakeDamage(Mathf.RoundToInt(skill.effectValue), DamageType.Magic);
                }
            }
        }

        public void TakeDamage(float damage)
        {
            if (_currentState == HeroState.Dead) return;

            float actualDamage = damage * (1f - _currentStats.armor / 100f);
            _currentHealth -= actualDamage;

            OnHealthChanged?.Invoke(_currentHealth);

            if (_animator != null)
            {
                _animator.SetTrigger("Hit");
            }

            if (_currentHealth <= 0)
            {
                Die();
            }
        }

        public void Heal(float amount)
        {
            _currentHealth += amount;
            if (_currentHealth > _currentStats.maxHealth)
            {
                _currentHealth = _currentStats.maxHealth;
            }
            OnHealthChanged?.Invoke(_currentHealth);
        }

        public void AddExp(float exp)
        {
            _currentExp += exp;
            OnExpChanged?.Invoke(_currentExp);

            while (_currentExp >= _expToNextLevel)
            {
                LevelUp();
            }
        }

        private void LevelUp()
        {
            _currentExp -= _expToNextLevel;
            _currentLevel++;
            _expToNextLevel *= 1.5f;

            _currentStats.maxHealth *= 1.1f;
            _currentStats.attackDamage *= 1.1f;
            _currentHealth = _currentStats.maxHealth;

            OnLevelUp?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetTrigger("LevelUp");
            }
        }

        private void Die()
        {
            _currentState = HeroState.Dead;
            OnDeath?.Invoke(this);

            if (_animator != null)
            {
                _animator.SetBool("IsDead", true);
            }
        }

        public void Revive()
        {
            _currentHealth = _currentStats.maxHealth;
            _currentState = HeroState.Idle;

            if (_animator != null)
            {
                _animator.SetBool("IsDead", false);
            }
        }

        public float GetSkillCooldown(string skillName)
        {
            return _skillCooldowns.TryGetValue(skillName, out float cd) ? cd : 0f;
        }

        public float GetSkillCooldownPercent(string skillName)
        {
            foreach (var skill in _heroData.skills)
            {
                if (skill.skillName == skillName)
                {
                    return GetSkillCooldown(skillName) / skill.cooldown;
                }
            }
            return 0f;
        }
    }
}

using UnityEngine;
using UnityEngine.EventSystems;
using TowerDefense.Data;

namespace TowerDefense.Hero
{
    public class HeroController : MonoBehaviour
    {
        [Header("Hero")]
        [SerializeField] private Hero _hero;
        [SerializeField] private HeroData _heroData;

        [Header("Movement Settings")]
        [SerializeField] private bool _useClickMovement = true;
        [SerializeField] private LayerMask _groundLayer;

        [Header("Skill Keys")]
        [SerializeField] private KeyCode _skill1Key = KeyCode.Q;
        [SerializeField] private KeyCode _skill2Key = KeyCode.W;
        [SerializeField] private KeyCode _skill3Key = KeyCode.E;

        private Camera _mainCamera;

        private void Awake()
        {
            _mainCamera = Camera.main;

            if (_hero == null)
            {
                _hero = GetComponent<Hero>();
            }
        }

        private void Start()
        {
            if (_hero != null && _heroData != null)
            {
                _hero.Initialize(_heroData);
            }
        }

        private void Update()
        {
            if (_hero == null || _hero.IsDead) return;

            HandleMovement();
            HandleSkills();
        }

        private void HandleMovement()
        {
            if (!_useClickMovement) return;

            if (Input.GetMouseButtonDown(1) && !EventSystem.current.IsPointerOverGameObject())
            {
                Ray ray = _mainCamera.ScreenPointToRay(Input.mousePosition);
                RaycastHit2D hit = Physics2D.Raycast(ray.origin, ray.direction, Mathf.Infinity, _groundLayer);

                if (hit.collider != null)
                {
                    _hero.MoveTo(hit.point);
                }
                else
                {
                    Vector3 worldPosition = _mainCamera.ScreenToWorldPoint(Input.mousePosition);
                    worldPosition.z = 0;
                    _hero.MoveTo(worldPosition);
                }
            }
        }

        private void HandleSkills()
        {
            if (_heroData == null || _heroData.skills == null) return;

            if (Input.GetKeyDown(_skill1Key) && _heroData.skills.Length > 0)
            {
                _hero.UseSkill(0);
            }
            else if (Input.GetKeyDown(_skill2Key) && _heroData.skills.Length > 1)
            {
                _hero.UseSkill(1);
            }
            else if (Input.GetKeyDown(_skill3Key) && _heroData.skills.Length > 2)
            {
                _hero.UseSkill(2);
            }
        }

        public void UseSkillByIndex(int index)
        {
            if (_hero != null)
            {
                _hero.UseSkill(index);
            }
        }

        public void SetHeroData(HeroData data)
        {
            _heroData = data;
            if (_hero != null)
            {
                _hero.Initialize(_heroData);
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Enemy;

namespace TowerDefense.Skill
{
    public enum SkillTargetType
    {
        Self,
        Enemy,
        Area,
        Direction
    }

    public abstract class SkillBase : ScriptableObject
    {
        [Header("Skill Info")]
        public string skillName;
        public string description;
        public Sprite icon;
        public int maxLevel = 5;

        [Header("Cooldown & Cost")]
        public float cooldown = 10f;
        public int manaCost = 0;
        public int goldCost = 0;

        [Header("Targeting")]
        public SkillTargetType targetType = SkillTargetType.Area;
        public float range = 5f;
        public float radius = 2f;

        [Header("Effects")]
        public GameObject effectPrefab;
        public AudioClip soundEffect;

        protected int _currentLevel = 1;

        public int CurrentLevel => _currentLevel;

        public virtual bool CanUse(GameObject user)
        {
            if (goldCost > 0 && !GameManager.Instance.HasEnoughGold(goldCost))
            {
                return false;
            }
            return true;
        }

        public virtual void Use(GameObject user, Vector3 targetPosition)
        {
            if (!CanUse(user)) return;

            if (goldCost > 0)
            {
                GameManager.Instance.SpendGold(goldCost);
            }

            Execute(user, targetPosition);
            PlayEffects(targetPosition);

            EventBus.Publish(new SkillUsedEvent { SkillName = skillName });
        }

        protected abstract void Execute(GameObject user, Vector3 targetPosition);

        protected virtual void PlayEffects(Vector3 position)
        {
            if (effectPrefab != null)
            {
                Instantiate(effectPrefab, position, Quaternion.identity);
            }

            if (soundEffect != null)
            {
                AudioSource.PlayClipAtPoint(soundEffect, position);
            }
        }

        public virtual void Upgrade()
        {
            if (_currentLevel < maxLevel)
            {
                _currentLevel++;
            }
        }

        protected List<Enemy.Enemy> GetEnemiesInRadius(Vector3 center, float radius)
        {
            EnemySpawner spawner = FindObjectOfType<EnemySpawner>();
            if (spawner == null) return new List<Enemy.Enemy>();

            return spawner.GetEnemiesInRange(center, radius);
        }
    }
}

