        {
           // Debug.Log($"TowerSlot {gameObject.name} initialized");

            // 初始化高亮和建造指示器状态
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(!_isOccupied);
            }
        }

        /// <summary>
        /// 鼠标进入槽位
        /// </summary>
        private void OnMouseEnter()
        {
            if (!_isOccupied)
            {
                _isHovered = true;
                // Debug.Log($"Mouse entered slot: {gameObject.name}");

                // 显示高亮效果
                if (_highlight != null)
                {
                    _highlight.SetActive(true);
                }
            }
        }

        /// <summary>
        /// 鼠标离开槽位
        /// </summary>
        private void OnMouseExit()
        {
            _isHovered = false;
            // 非选中状态下隐藏高亮
            if (_highlight != null && !_isSelected)
            {
                _highlight.SetActive(false);
            }
        }

        void Start()
        {
            CircleCollider2D collider = GetComponent<CircleCollider2D>();
            if (collider != null)
            {
                collider.radius = 1f;
            }
        }

        /// <summary>
        /// 鼠标点击槽位
        /// </summary>
        private void OnMouseDown()
        {
            Debug.Log($"Slot clicked: {gameObject.name}, IsOccupied: {_isOccupied}");

            // 取消之前的选中状态（不隐藏面板，面板常驻）
            DeselectAllSlots();
            HideTowerInfoPanel();

            if (!_isOccupied)
            {
                SelectSlot();
                ShowTowerSelectPanel();
            }
            else
            {
                SelectSlot();
                ShowTowerInfoPanel();
            }
        }

        /// <summary>
        /// 选中槽位
        /// </summary>
        public void SelectSlot()
        {
            _isSelected = true;
            OnSlotSelected?.Invoke();
                // Debug.Log($"Slot selected: {gameObject.name}");

            // 如果有塔，显示攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.ShowRange();
            }
        }

        /// <summary>
        /// 取消选中槽位
        /// </summary>
        public void DeselectSlot()
        {
            _isSelected = false;
            // 隐藏高亮效果
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            // 如果有塔，隐藏攻击范围
            if (_isOccupied && _currentTower != null)
            {
                _currentTower.HideRange();
            }
                // Debug.Log($"Slot deselected: {gameObject.name}");
        }

        /// <summary>
        /// 显示塔选择面板
        /// </summary>
        private void ShowTowerSelectPanel()
        {
            // 先尝试通过 画布 下已知路径查找（包括非激活对象）
            TowerSelectPanel panel = null;
            var panelObj = GameObject.Find("画布/塔选择面板");
            if (panelObj != null)
            {
                panel = panelObj.GetComponent<TowerSelectPanel>();
            }

            // 备用：用英文名查找（兼容重命名前）
            if (panel == null)
            {
                panelObj = GameObject.Find("Canvas/TowerSelectPanel");
                if (panelObj != null)
                    panel = panelObj.GetComponent<TowerSelectPanel>();
            }

            // 备用：在激活对象中查找
            if (panel == null)
            {
                panel = FindObjectOfType<TowerSelectPanel>();
            }

            if (panel != null)
            {
                panel.Show(this);
            }
        }

        /// <summary>
        /// 显示塔信息面板
        /// </summary>
        private void ShowTowerInfoPanel()
        {
            TowerInfoPanel panel = null;
            var panelObj = GameObject.Find("画布/塔信息面板");
            if (panelObj != null)
            {
                panel = panelObj.GetComponent<TowerInfoPanel>();
            }
            if (panel == null)
            {
                panelObj = GameObject.Find("Canvas/TowerInfoPanel");
                if (panelObj != null)
                    panel = panelObj.GetComponent<TowerInfoPanel>();
            }
            if (panel == null)
            {
                panel = FindObjectOfType<TowerInfoPanel>();
            }
            if (panel != null && _currentTower != null)
            {
                panel.Show(_currentTower);
            }
        }

        /// <summary>
        /// 取消所有槽位的选中状态
        /// </summary>
        private void DeselectAllSlots()
        {
            foreach (var slot in FindObjectsOfType<TowerSlot>())
            {
                if (slot._isSelected)
                {
                    slot.DeselectSlot();
                }
            }
        }

        /// <summary>
        /// 隐藏塔信息面板
        /// </summary>
        private void HideTowerInfoPanel()
        {
            var infoObj = GameObject.Find("画布/塔信息面板");
            if (infoObj == null) infoObj = GameObject.Find("Canvas/TowerInfoPanel");
            if (infoObj != null)
            {
                var infoPanel = infoObj.GetComponent<TowerInfoPanel>();
                if (infoPanel != null) infoPanel.Hide();
            }
            else
            {
                var ip = FindObjectOfType<TowerInfoPanel>();
                if (ip != null) ip.Hide();
            }
        }

        /// <summary>
        /// 隐藏所有UI面板
        /// </summary>
        private void HideAllPanels()
        {
            var selectObj = GameObject.Find("画布/塔选择面板");
            if (selectObj == null) selectObj = GameObject.Find("Canvas/TowerSelectPanel");
            if (selectObj != null)
            {
                var selectPanel = selectObj.GetComponent<TowerSelectPanel>();
                if (selectPanel != null) selectPanel.Hide();
            }
            else
            {
                var sp = FindObjectOfType<TowerSelectPanel>();
                if (sp != null) sp.Hide();
            }

            var infoObj = GameObject.Find("画布/塔信息面板");
            if (infoObj == null) infoObj = GameObject.Find("Canvas/TowerInfoPanel");
            if (infoObj != null)
            {
                var infoPanel = infoObj.GetComponent<TowerInfoPanel>();
                if (infoPanel != null) infoPanel.Hide();
            }
            else
            {
                var ip = FindObjectOfType<TowerInfoPanel>();
                if (ip != null) ip.Hide();
            }

            if (BuildButtonManager.Instance != null)
            {
                BuildButtonManager.Instance.HideBuildButton();
            }
        }

        /// <summary>
        /// 被管理器调用的建造按钮点击
        /// </summary>
        public void OnBuildButtonClickedByManager()
        {
                // Debug.Log("OnBuildButtonClickedByManager called!");

            // 尝试放置塔
            TowerData towerToBuild = GetTowerDataToBuild();

            if (towerToBuild != null)
            {
                bool success = PlaceTower(towerToBuild);

                if (success)
                {
                    // Debug.Log("✅ Tower built successfully!");
                }
                else
                {
                    // Debug.Log("❌ Failed to build tower!");
                }
            }
            else
            {
                // Debug.LogError("❌ No tower data to build!");
            }
        }

        /// <summary>
        /// 获取要建造的塔数据
        /// </summary>
        private TowerData GetTowerDataToBuild()
        {
            // 优先使用配置的塔列表
            if (buildableTowers != null && buildableTowers.Length > 0)
            {
                    // Debug.Log($"Using configured tower: {buildableTowers[0].towerName}");
                return buildableTowers[0];
            }

            // 尝试从Resources/Data/Towers/加载
            Debug.Log("Trying to load from Resources/Data/Towers/");
            TowerData[] towerDatas1 = Resources.LoadAll<TowerData>("Data/Towers");
            if (towerDatas1.Length > 0)
            {
                     Debug.Log($"Found {towerDatas1.Length} tower data assets in Data/Towers/");
                return towerDatas1[0];
            }

            // 尝试从Resources/Data/加载
            Debug.Log("Trying to load from Resources/Data/");
            TowerData[] towerDatas2 = Resources.LoadAll<TowerData>("Data");
            if (towerDatas2.Length > 0)
            {
                Debug.Log($"Found {towerDatas2.Length} tower data assets in Data/");
                return towerDatas2[0];
            }

                Debug.LogError("❌ No tower data found!");
            return null;
        }

        /// <summary>
        /// 在槽位放置塔
        /// </summary>
        /// <param name="towerData">塔数据</param>
        /// <returns>是否放置成功</returns>
        public bool PlaceTower(TowerData towerData)
        {
            if (_isOccupied) return false;

            int cost = towerData.levels[0].cost;
            if (!GameManager.Instance.SpendGold(cost)) return false;

            Vector3 spawnPos = transform.position;
            spawnPos.z = _towerZPosition;

            GameObject towerObj = Instantiate(towerData.towerPrefab, spawnPos, Quaternion.identity);
            if (towerObj == null) return false;

            if (_towerScale != Vector3.one)
            {
                towerObj.transform.localScale = _towerScale;
            }

            _currentTower = towerObj.GetComponent<Tower>();
            if (_currentTower != null)
            {
                _currentTower.Initialize(towerData, this);
            }

            _isOccupied = true;

            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(false);
            }
            if (_highlight != null)
            {
                _highlight.SetActive(false);
            }

            OnTowerPlaced?.Invoke();
            EventBus.Publish(new TowerPlacedEvent { Tower = towerObj, Cost = cost });

            return true;
        }

        /// <summary>
        /// 移除塔（不返还金币）
        /// </summary>
        public void RemoveTower()
        {
            _currentTower = null;
            _isOccupied = false;

            // 显示建造指示器
            if (_buildIndicator != null)
            {
                _buildIndicator.SetActive(true);
            }

            OnTowerRemoved?.Invoke();
        }

        /// <summary>
        /// 售卖塔（返还部分金币）
        /// </summary>
        public void SellTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Sell();
        }

        /// <summary>
        /// 升级塔
        /// </summary>
        public void UpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return;

            _currentTower.Upgrade();
        }

        /// <summary>
        /// 获取塔的售卖价值
        /// </summary>
        /// <returns>售卖金币数</returns>
        public int GetTowerSellValue()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetSellValue();
        }

        /// <summary>
        /// 获取塔的升级费用
        /// </summary>
        /// <returns>升级金币数</returns>
        public int GetTowerUpgradeCost()
        {
            if (!_isOccupied || _currentTower == null) return 0;
            return _currentTower.GetUpgradeCost();
        }

        /// <summary>
        /// 检查塔是否可以升级
        /// </summary>
        /// <returns>是否可升级</returns>
        public bool CanUpgradeTower()
        {
            if (!_isOccupied || _currentTower == null) return false;
            return !_currentTower.IsMaxLevel;
        }

        /// <summary>
        /// 绘制Gizmos（编辑器模式下）
        /// </summary>
        private void OnDrawGizmos()
        {
            // 绿色表示可建造，红色表示已占用
            Gizmos.color = _isOccupied ? Color.red : Color.green;
            Gizmos.DrawWireSphere(transform.position, 0.3f);
        }
    }
}

using UnityEngine;
using System.Collections.Generic;
using TowerDefense.Data;
using TowerDefense.Utils;
using TowerDefense.Wave;

namespace TowerDefense.Enemy
{
    public class EnemySpawner : MonoBehaviour
    {
        [Header("Settings")]
        [SerializeField] private PathCreator _pathCreator;
        [SerializeField] private Transform _spawnPoint;

        private void Awake()
        {
            if (_pathCreator == null)
            {
                _pathCreator = FindObjectOfType<PathCreator>();
                if (_pathCreator != null)
                    Debug.Log("EnemySpawner: 自动找到 PathCreator - " + _pathCreator.gameObject.name);
                else
                    Debug.LogError("EnemySpawner: 找不到 PathCreator！");
            }
        }

        /// <summary>获取当前场景中所有有效的 PathCreator（实时查找，不缓存）</summary>
        private List<PathCreator> GetValidPaths()
        {
            var paths = new List<PathCreator>();
            foreach (var pc in FindObjectsOfType<PathCreator>())
            {
                if (pc != null && pc.WaypointCount > 0)
                    paths.Add(pc);
            }
            return paths;
        }

        /// <summary>随机选一条有效路径</summary>
        private PathCreator PickRandomPath()
        {
            var paths = GetValidPaths();
            if (paths.Count == 0)
            {
                // fallback 到序列化引用
                if (_pathCreator != null && _pathCreator.WaypointCount > 0)
                    return _pathCreator;
                return null;
            }
            if (paths.Count == 1) return paths[0];
            return paths[Random.Range(0, paths.Count)];
        }

        private Queue<EnemyData> _spawnQueue = new Queue<EnemyData>();
        private float _spawnTimer = 0f;
        private float _spawnInterval = 1f;
        private bool _isSpawning = false;
        private bool _allSpawned = false; // 标记是否所有敌人都已出生

        public bool IsSpawning => _isSpawning;
        public static int CurrentWaveId { get; private set; }
        public static int TotalEnemiesInWave { get; private set; }

        // 双保险：本波 HashSet 防止重复统计
        private static HashSet<GameObject> _killedEnemiesThisWave = new HashSet<GameObject>();

        public static int RemainingEnemies 
        { 
            get 
            { 
                int remaining = TotalEnemiesInWave - _killedEnemiesThisWave.Count;
                return remaining >= 0 ? remaining : 0;  // 保证非负
            } 
        }

        private void Update()
        {
            if (_isSpawning && _spawnQueue.Count > 0)
            {
                _spawnTimer += Time.deltaTime;

                if (_spawnTimer >= _spawnInterval)
                {
                    _spawnTimer = 0f;
                    SpawnEnemy();
                }
            }

            // 所有敌人都已出生，且全部死亡/到达终点，才通知波次完成
            if (_allSpawned && RemainingEnemies <= 0)
            {
                _isSpawning = false;
                _allSpawned = false;
                WaveManager.Instance?.OnWaveComplete();
            }
        }

        public static void EnemyBorn(GameObject enemy)
        {
            // 敌人出生时注册波次ID
            enemy.GetComponent<Enemy>()?.SetBirthWaveId(CurrentWaveId);
        }

        public static void OnEnemyKilled(GameObject enemy, int enemyWaveId)
        {
            // ✅ 双保险: HashSet去重 + 波次ID相等才统计
            if (!_killedEnemiesThisWave.Contains(enemy) && enemyWaveId == CurrentWaveId)
            {
                _killedEnemiesThisWave.Add(enemy);
                Debug.Log($"✅ 波次{CurrentWaveId}敌人死亡: {_killedEnemiesThisWave.Count}/{TotalEnemiesInWave}, 剩余: {RemainingEnemies}");
            }
        }

        public void StartWave(WaveData waveData)
        {
            _spawnQueue.Clear();

            // 波次递进，给新的ID
            CurrentWaveId++;
            TotalEnemiesInWave = 0;

            // ✅ 新波次: 清空死亡集合，防止死循环统计
            _killedEnemiesThisWave.Clear();

            foreach (var enemyGroup in waveData.enemies)
            {
                for (int i = 0; i < enemyGroup.count; i++)
                {
                    _spawnQueue.Enqueue(enemyGroup.enemyData);
                    TotalEnemiesInWave++;
                }
            }

            Debug.Log($"🌊 波次{CurrentWaveId}开始: 准备出生 {TotalEnemiesInWave} 个敌人");

            _spawnInterval = waveData.spawnInterval;
            _isSpawning = true;
            _allSpawned = false;
            _spawnTimer = 0f;

            Debug.Log($"Wave started! Enemies to spawn: {_spawnQueue.Count}");
        }

        private void SpawnEnemy()
        {
            if (_spawnQueue.Count == 0)
            {
                _allSpawned = true;
                return;
            }

            EnemyData enemyData = _spawnQueue.Dequeue();

            // 队列空了，标记所有敌人都已出生
            if (_spawnQueue.Count == 0)
            {
                _allSpawned = true;
            }

            if (enemyData == null || enemyData.enemyPrefab == null)
            {
                SpawnEnemy();
                return;
            }

            // 实时获取有效路径，不再依赖缓存
            var path = PickRandomPath();
            if (path == null)
            {
                Debug.LogError("EnemySpawner: 没有有效的 PathCreator，敌人生成失败！");
                return;
            }

            Vector3 spawnPos = path.WaypointCount > 0 ? path.GetWaypoint(0) : transform.position;

            GameObject enemyObj = Instantiate(enemyData.enemyPrefab, spawnPos, Quaternion.identity);
            Enemy enemy = enemyObj.GetComponent<Enemy>();

            if (enemy != null)
            {
                enemy.SetBirthWaveId(CurrentWaveId);
                enemy.Initialize(enemyData);
                enemy.StartMovement(path);
            }

            Debug.Log($"Spawned enemy: {enemyData.enemyName}, 波次ID={CurrentWaveId}");
        }

        public void StopSpawning()
        {
            _isSpawning = false;
            _spawnQueue.Clear();
        }

        public Enemy GetClosestEnemy(Vector3 position, float maxDistance)
        {
            Enemy[] enemies = FindObjectsOfType<Enemy>();
            Enemy closestEnemy = null;
            float closestDistance = float.MaxValue;

            foreach (var enemy in enemies)
            {
                float distance = Vector3.Distance(position, enemy.transform.position);
                if (distance <= maxDistance && distance < closestDistance)
                {
                    closestDistance = distance;
                    closestEnemy = enemy;
                }
            }

            return closestEnemy;
        }

        public List<Enemy> GetEnemiesInRange(Vector3 position, float range)
        {
            List<Enemy> enemiesInRange = new List<Enemy>();
            Enemy[] enemies = FindObjectsOfType<Enemy>();

            foreach (var enemy in enemies)
            {
                float distance = Vector3.Distance(position, enemy.transform.position);
                if (distance <= range)
                {
                    enemiesInRange.Add(enemy);
                }
            }

            return enemiesInRange;
        }

        private void OnDrawGizmos()
        {
            Gizmos.color = Color.cyan;
            Vector3 spawnPos = _spawnPoint != null ? _spawnPoint.position : transform.position;
            Gizmos.DrawSphere(spawnPos, 0.3f);
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;
using TowerDefense.Core;
using TowerDefense.Data;

namespace TowerDefense.UI
{
    public class MainMenuUI : MonoBehaviour
    {
        [Header("Panels")]
        [SerializeField] private GameObject _mainPanel;
        [SerializeField] private GameObject _levelSelectPanel;
        [SerializeField] private GameObject _settingsPanel;

        [Header("Level Selection")]
        [SerializeField] private Transform _levelButtonContainer;
        [SerializeField] private GameObject _levelButtonPrefab;

        [Header("Settings")]
        [SerializeField] private Slider _musicSlider;
        [SerializeField] private Slider _sfxSlider;
        [SerializeField] private Toggle _fullscreenToggle;

        [Header("Currency Displays")]
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _diamondText;
        [SerializeField] private Text _staminaText;
        [SerializeField] private Text _playerLevelText;
        [SerializeField] private Slider _playerExpSlider;

        [Header("Exchange")]
        [SerializeField] private Button _exchangeButton;
        [SerializeField] private ExchangePanel _exchangePanel;

        [Header("Level Data")]
        [SerializeField] private LevelData[] _levels;

        private void Start()
        {
            ShowMainPanel();
            LoadSettings();
            UpdatePlayerLevelDisplay();

            if (_exchangeButton != null)
                _exchangeButton.onClick.AddListener(OnExchangeClicked);
        }

        private void OnEnable()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                wallet.OnGoldChanged += UpdateGold;
                wallet.OnDiamondChanged += UpdateDiamond;
                wallet.OnStaminaChanged += UpdateStamina;
                UpdateGold(wallet.Gold);
                UpdateDiamond(wallet.Diamond);
                UpdateStamina(wallet.Stamina);
            }

            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem != null)
            {
                levelSystem.OnLevelChanged += UpdateLevelText;
                levelSystem.OnExpChanged += UpdateExpSlider;
                UpdatePlayerLevelDisplay();
            }
        }

        private void OnDisable()
        {
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                wallet.OnGoldChanged -= UpdateGold;
                wallet.OnDiamondChanged -= UpdateDiamond;
                wallet.OnStaminaChanged -= UpdateStamina;
            }

            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem != null)
            {
                levelSystem.OnLevelChanged -= UpdateLevelText;
                levelSystem.OnExpChanged -= UpdateExpSlider;
            }
        }

        private void UpdateGold(int amount) { if (_goldText != null) _goldText.text = amount.ToString(); }
        private void UpdateDiamond(int amount) { if (_diamondText != null) _diamondText.text = amount.ToString(); }
        private void UpdateStamina(int amount) { if (_staminaText != null) _staminaText.text = amount.ToString(); }

        public void ShowMainPanel()
        {
            if (_mainPanel != null) _mainPanel.SetActive(true);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(false);
            if (_settingsPanel != null) _settingsPanel.SetActive(false);
        }

        public void ShowLevelSelect()
        {
            if (_mainPanel != null) _mainPanel.SetActive(false);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(true);
            if (_settingsPanel != null) _settingsPanel.SetActive(false);

            GenerateLevelButtons();
        }

        public void ShowSettings()
        {
            if (_mainPanel != null) _mainPanel.SetActive(false);
            if (_levelSelectPanel != null) _levelSelectPanel.SetActive(false);
            if (_settingsPanel != null) _settingsPanel.SetActive(true);
        }

        public void StartLevel(int levelIndex)
        {
            if (levelIndex >= 0 && levelIndex < _levels.Length)
            {
                SceneManager.LoadScene(_levels[levelIndex].sceneName);
            }
        }

        public void QuitGame()
        {
#if UNITY_EDITOR
            UnityEditor.EditorApplication.isPlaying = false;
#else
            Application.Quit();
#endif
        }

        private void OnExchangeClicked()
        {
            if (_exchangePanel != null)
                _exchangePanel.Show();
        }

        private void GenerateLevelButtons()
        {
            if (_levelButtonContainer == null || _levelButtonPrefab == null) return;

            foreach (Transform child in _levelButtonContainer)
            {
                Destroy(child.gameObject);
            }

            for (int i = 0; i < _levels.Length; i++)
            {
                GameObject buttonObj = Instantiate(_levelButtonPrefab, _levelButtonContainer);
                LevelButton levelButton = buttonObj.GetComponent<LevelButton>();

                if (levelButton != null)
                {
                    levelButton.Setup(_levels[i], i, this);
                }
            }
        }

        #region Settings

        public void OnMusicVolumeChanged(float value)
        {
            PlayerPrefs.SetFloat("MusicVolume", value);
            PlayerPrefs.Save();
        }

        public void OnSFXVolumeChanged(float value)
        {
            PlayerPrefs.SetFloat("SFXVolume", value);
            PlayerPrefs.Save();
        }

        public void OnFullscreenToggled(bool isFullscreen)
        {
            Screen.fullScreen = isFullscreen;
            PlayerPrefs.SetInt("Fullscreen", isFullscreen ? 1 : 0);
            PlayerPrefs.Save();
        }

        private void LoadSettings()
        {
            if (_musicSlider != null)
            {
                _musicSlider.value = PlayerPrefs.GetFloat("MusicVolume", 1f);
            }
            if (_sfxSlider != null)
            {
                _sfxSlider.value = PlayerPrefs.GetFloat("SFXVolume", 1f);
            }
            if (_fullscreenToggle != null)
            {
                _fullscreenToggle.isOn = PlayerPrefs.GetInt("Fullscreen", 1) == 1;
            }
        }

        #endregion

        #region Player Level Display

        private void UpdatePlayerLevelDisplay()
        {
            var levelSystem = PlayerLevelSystem.Instance;
            if (levelSystem == null) return;

            UpdateLevelText(levelSystem.Level);
            UpdateExpSlider(levelSystem.CurrentExp, levelSystem.ExpToNextLevel);
        }

        private void UpdateLevelText(int level)
        {
            if (_playerLevelText != null)
                _playerLevelText.text = $"Lv.{level}";
        }

        private void UpdateExpSlider(int currentExp, int expToNext)
        {
            if (_playerExpSlider != null)
            {
                _playerExpSlider.maxValue = expToNext;
                _playerExpSlider.value = currentExp;
            }
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEngine.SceneManagement;
using TowerDefense.Core;

namespace TowerDefense.UI
{
    public class VictoryPanel : MonoBehaviour
    {
        [Header("Title")]
        [SerializeField] private Text _titleText;

        [Header("Stars")]
        [SerializeField] private Image[] _starImages = new Image[3];
        [SerializeField] private Sprite _starFilledSprite;
        [SerializeField] private Sprite _starEmptySprite;

        [Header("Stats")]
        [SerializeField] private Text _killCountText;
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _waveText;

        [Header("Buttons")]
        [SerializeField] private Button _restartButton;
        [SerializeField] private Button _nextLevelButton;
        [SerializeField] private Button _mainMenuButton;

        private void Awake()
        {
            if (_restartButton != null)
                _restartButton.onClick.AddListener(OnRestartClicked);
            if (_nextLevelButton != null)
                _nextLevelButton.onClick.AddListener(OnNextLevelClicked);
            if (_mainMenuButton != null)
                _mainMenuButton.onClick.AddListener(OnMainMenuClicked);
        }

        private void OnDestroy()
        {
            if (_restartButton != null)
                _restartButton.onClick.RemoveListener(OnRestartClicked);
            if (_nextLevelButton != null)
                _nextLevelButton.onClick.RemoveListener(OnNextLevelClicked);
            if (_mainMenuButton != null)
                _mainMenuButton.onClick.RemoveListener(OnMainMenuClicked);
        }

        public void ShowVictory()
        {
            gameObject.SetActive(true);
            UpdateStats();
            UpdateStars();
        }

        public void HideVictory()
        {
            gameObject.SetActive(false);
        }

        private void UpdateStats()
        {
            var gm = GameManager.Instance;
            if (gm == null) return;

            if (_killCountText != null)
                _killCountText.text = gm.EnemiesKilled.ToString();
            if (_goldText != null)
                _goldText.text = gm.CurrentGold.ToString();
            if (_waveText != null)
                _waveText.text = $"{gm.CurrentWave}/{gm.TotalWaves}";
        }

        private void UpdateStars()
        {
            var gm = GameManager.Instance;
            if (gm == null) return;

            int starCount = CalculateStars(gm);
            for (int i = 0; i < _starImages.Length; i++)
            {
                if (_starImages[i] == null) continue;
                if (_starFilledSprite != null && _starEmptySprite != null)
                {
                    _starImages[i].sprite = i < starCount ? _starFilledSprite : _starEmptySprite;
                }
                else
                {
                    _starImages[i].color = i < starCount
                        ? new Color(1f, 0.85f, 0f, 1f)
                        : new Color(0.3f, 0.3f, 0.3f, 0.5f);
                }
            }
        }

        private int CalculateStars(GameManager gm)
        {
            float lifeRatio = (float)gm.CurrentLife / 20f;
            if (lifeRatio >= 0.7f) return 3;
            if (lifeRatio >= 0.4f) return 2;
            return 1;
        }

        private void OnRestartClicked()
        {
            HideVictory();
            GameManager.Instance.RestartGame();
        }

        private void OnNextLevelClicked()
        {
            HideVictory();
            int nextIndex = GameManager.Instance.CurrentLevelIndex + 1;
            var levels = GameManager.Instance.Levels;
            if (levels != null && nextIndex < levels.Length)
            {
                GameManager.Instance.LoadLevel(nextIndex);
            }
            else
            {
                // 没有下一关，回到主菜单
                GameManager.Instance.ReturnToHome();
            }
        }

        private void OnMainMenuClicked()
        {
            HideVictory();
            if (ModuleModeDetector.IsModuleMode)
            {
                // 从家园进入时，返回家园
                SceneManager.LoadScene("HomeScene");
            }
            else
            {
                SceneManager.LoadScene("MainMenu");
            }
        }
    }
}

